INSERT INTO performance.overview_vision ("mv_id", "plan_id", "overview", "vision", "web_address")
VALUES
    (1, 1, 'The Department of General Services (DGS) delivers expertise, innovation, and accountability to help partners in the City of Baltimore get their respective jobs done. DGS maintains facilities that provide safe and healthy workplaces. They procure, repair and service vehicles and motorized equipment. The department designs and constructs new buildings and renovates old ones. DGS helps Baltimore reduce its carbon footprint and manage energy costs.', 'The Department of General Services’ vision is to be a leader in delivering expertise, efficiency, and service excellence. Its mission is to deliver results for City partners through services and solutions that are timely, cost-effective, and sustainable.', NULL),
    (2, 2, 'The Mayor''s Office of Neighborhood Safety and Engagement (MONSE) is responsible for implementing the City''s public health approach to violence through Baltimore''s Comprehensive Violence Prevention Plan, working with agencies and community partners to stem the tide of violence while simultaneously unearthing its root causes. MONSE implements and supports effective violence prevention and intervention, reentry, and rehabilitative strategies, including the Community Violence Intervention (CVI) ecosystem, the Group Violence Reduction Strategy (GVRS), victim services support and advocacy, neighborhood stabilization and outreach, and reentry services.', 'MONSE''s approach, strategies, and programs are designed to prevent and intervene in violence, help people make better choices through balancing opportunity and accountability, and support those returning from prisons and jails. Our programs include stopping community violence, giving support to victims of crime and trauma, and making our neighborhoods stronger.', NULL)
ON CONFLICT ("mv_id") DO UPDATE SET
    "plan_id" = EXCLUDED."plan_id", "overview" = EXCLUDED."overview", "vision" = EXCLUDED."vision", "web_address" = EXCLUDED."web_address";
SELECT setval(
    pg_get_serial_sequence('performance.overview_vision', 'mv_id'),
    COALESCE((SELECT MAX("mv_id") FROM performance.overview_vision), 1),
    (SELECT COUNT(*) > 0 FROM performance.overview_vision)
);

