INSERT INTO performance.agency_goal ("agency_goal_id", "plan_id", "title", "sort_order")
VALUES
    (1, 1, 'Continue effective long-term asset management by rightsizing our vehicle fleet and building portfolio, reducing avoidable costs, reducing capital demands and effectively allocating scarce resources.', 1),
    (2, 1, 'Build a resilient, high-performing workforce by strengthening recruitment pipelines for trades and administrative roles, accelerating onboarding and skill development, and creating clear pathways for advancement and retention.', 2),
    (3, 1, 'Improve service delivery and responsible use of City resources through innovative process improvement, effective use of data, and operational accountability.', 3),
    (4, 2, 'Sustain Effectiveness of Violence Intervention Models: Sustain a 15% reduction in Homicides and Shootings Year Over Year in Baltimore City by December 31, 2028.', 1),
    (5, 2, 'Enhance Community Safety Perception and Engagement: Through proactive and responsive neighborhood stabilization efforts and community collaborations, increase the percentage of residents who live near qualifying traumatic incidents with increased confidence in local government by December 31, 2028.', 2),
    (6, 2, 'Maintain High Quality Victim and Survivor Support: Ensure every referral to MONSE Victim Services is processed with a completed intake in under 48 hours by December 31, 2028.', 3),
    (7, 2, 'Expand Re-Entry Planning: Increase the number of returning citizens returning to Baltimore City with a co-developed Safe Return Plan.', 4)
ON CONFLICT ("agency_goal_id") DO UPDATE SET
    "plan_id" = EXCLUDED."plan_id", "title" = EXCLUDED."title", "sort_order" = EXCLUDED."sort_order";
SELECT setval(
    pg_get_serial_sequence('performance.agency_goal', 'agency_goal_id'),
    COALESCE((SELECT MAX("agency_goal_id") FROM performance.agency_goal), 1),
    (SELECT COUNT(*) > 0 FROM performance.agency_goal)
);

INSERT INTO performance.agency_goal_pillar_link ("link_id", "agency_goal_id", "pillar_goal_id", "link_type", "alignment_narrative")
VALUES
    (1, 1, 19, 'Primary', 'Goal 1 directly advances Pillar Goal 6.1 through fleet rightsizing, facilities maintenance, energy management, and capital project delivery.'),
    (2, 2, 15, 'Primary', 'Goal 2 directly advances Pillar Goal 5.2 through recruitment pipeline development, apprenticeship programs, and employee engagement improvement.'),
    (3, 3, 14, 'Primary', 'Goal 3 directly advances Pillar Goal 5.1 through invoice payment performance, energy cost management, and data-informed asset management.'),
    (4, 4, 2, 'Primary', 'Goal 1 advances Pillar Goal 1.2 (Disrupt Violent Networks) through GVRS expansion, Safe Streets staffing, and evidence-based violence reduction. NOTE: plan document cites this as ''1.1'' but maps to code 1.2 in the Mayor''s Action Plan database.'),
    (5, 5, 3, 'Primary', 'Goal 2 advances Pillar Goal 1.3 (Build a Culture of Accountability) through community trust-building, proactive neighborhood engagement, and the Neighborhood Public Safety Plan process.'),
    (6, 6, 8, 'Primary', 'Goal 3 advances Pillar Goal 3.2 (Improve Resident Health) through victim services, trauma-informed support, and seamless referral pathways for crime victims.'),
    (7, 7, 13, 'Primary', 'Goal 4 advances Pillar Goal 4.3 (Build Workforce Development Systems) through re-entry employment pipelines, Individualized Development Plans, and partnerships with reentry-friendly employers.')
ON CONFLICT ("link_id") DO UPDATE SET
    "agency_goal_id" = EXCLUDED."agency_goal_id", "pillar_goal_id" = EXCLUDED."pillar_goal_id", "link_type" = EXCLUDED."link_type", "alignment_narrative" = EXCLUDED."alignment_narrative";
SELECT setval(
    pg_get_serial_sequence('performance.agency_goal_pillar_link', 'link_id'),
    COALESCE((SELECT MAX("link_id") FROM performance.agency_goal_pillar_link), 1),
    (SELECT COUNT(*) > 0 FROM performance.agency_goal_pillar_link)
);

INSERT INTO performance.initiative ("initiative_id", "title", "description", "status")
VALUES
    (1, 'Expand preventative maintenance program', 'Expand the preventative maintenance program to include issuance, execution, and tracking of PMs across all building systems.', 'Planned'),
    (2, 'EV charging station strategy', 'Develop an electric vehicle (EV) charging station strategy incorporating deliverables and recommendations such as the deployment of chargers and piloting an EV motor pool.', 'Planned'),
    (3, 'Carbon emissions reduction', 'Identify and implement activities to meaningfully reduce the city''s carbon emissions footprint and support the mayor''s climate goals.', 'Planned'),
    (4, 'Capital plan master schedule', 'Use a capital plan master schedule aligning projects with the available capital funding cycle to ensure timely use of allocated funds, improved project execution, and enhanced transparency and accountability in capital planning.', 'Planned'),
    (5, 'Streamline trades recruitment', 'Streamline the recruitment process with an emphasis on high value, hard to fill tradesman roles and expand targeted recruitment, trade and vocational school partnerships and youth apprentice programs to meet target levels of tradespeople needed to meet DGS service level targets.', 'Planned'),
    (6, 'Improve employee engagement', 'Improve employee engagement, perceptions of safety, and sense of meaningful work.', 'Planned'),
    (7, 'Energy cost hedging strategy', 'Improve management of energy costs by purchasing energy through a hedging strategy to improve budget accuracy, reliability, and exposure.', 'Planned'),
    (8, 'Telematics system implementation', 'Implementation of new telematics system to allow for development of a data-informed asset replacement schedule.', 'Planned'),
    (9, 'Fiscal payment process improvement', 'Review and successfully implement fiscal payment processes to exceed all stakeholder expectations and strengthen vendor relations.', 'Planned'),
    (10, 'Scale GVRS to additional districts', 'Scale the Group Violence Reduction Strategy to at least two more districts, moving closer to citywide scale.', 'Planned'),
    (11, 'Achieve Safe Streets staffing levels', 'Achieve 85% staffing levels across all Safe Streets sites.', 'Planned'),
    (12, 'Train Safe Streets staff on model and trauma-informed interventions', 'Train 65% of Safe Streets staff on the Safe Streets model and trauma-informed interventions by Fiscal Year 27 end.', 'Planned'),
    (13, 'Oversee youth safety engagement activations', 'Successfully oversee 2026 and 2027 youth safety engagement activations.', 'Planned'),
    (14, 'Multi-Agency Inspection Task Force coordination', 'Strengthen strategic coordination with City agencies through the Multi-Agency Inspection Task Force and with community-based partners during neighborhood stabilizations.', 'Planned'),
    (15, 'Neighborhood Public Safety Plan with BPD', 'Activate new Neighborhood Public Safety Plan process in partnership with the Baltimore Police Department (BPD) for new communities.', 'Planned'),
    (16, 'Formalize victim services protocols', 'Formalize processes and protocols with other victim services agencies, both in government and in community.', 'Planned'),
    (17, 'CVI referral partner coordination meetings', 'Regularly host coordination meetings for strategic case review among Community Violence Intervention (CVI) referral partners and interagency Victim Services providers.', 'Planned'),
    (18, 'Increase HVIP referrals to MONSE Victim Services', 'Increase referrals from all Hospital Violence Intervention Program (HVIP) partners to MONSE Victim Services, continuing close coordination with BPD Victim Services to avoid duplication of efforts.', 'Planned'),
    (19, 'Employment pipelines for returning citizens', 'Identify and establish pipelines for employment opportunities within city government and beyond for Baltimore''s returning citizens, in partnership with city agencies and private companies.', 'Planned'),
    (20, 'Build out Office of Returning Citizens', 'Build out the Office of Returning Citizens.', 'Planned'),
    (21, 'Stable housing partnerships for returning citizens', 'Support stable housing planning for returning citizens through strategic partnerships with housing providers and the Governor''s Office.', 'Planned'),
    (22, 'Reentry-friendly employer partnerships', 'Increase the number of established partnerships with reentry-friendly employers that have formally committed to and opened specific roles for returning citizens.', 'Planned')
ON CONFLICT ("initiative_id") DO UPDATE SET
    "title" = EXCLUDED."title", "description" = EXCLUDED."description", "status" = EXCLUDED."status";
SELECT setval(
    pg_get_serial_sequence('performance.initiative', 'initiative_id'),
    COALESCE((SELECT MAX("initiative_id") FROM performance.initiative), 1),
    (SELECT COUNT(*) > 0 FROM performance.initiative)
);

