    "agency_goal_id" = EXCLUDED."agency_goal_id", "initiative_id" = EXCLUDED."initiative_id", "link_type" = EXCLUDED."link_type";
SELECT setval(
    pg_get_serial_sequence('performance.agency_goal_initiative_link', 'link_id'),
    COALESCE((SELECT MAX("link_id") FROM performance.agency_goal_initiative_link), 1),
    (SELECT COUNT(*) > 0 FROM performance.agency_goal_initiative_link)
);

INSERT INTO performance.service_risk ("risk_id", "plan_id", "risk_type", "description")
VALUES
    (1, 1, 'cross-agency inputs', 'Most goals and related metrics reflect DGS''s role as a core service provider to public-facing agencies. Cross-agency inputs are seen in the interplay between usage of city vehicles and buildings and how those activities impact demands of DGS operations. DGS fleet and facilities maintenance directly supports agencies delivering the mayor''s goals around neighborhood cleanliness and stabilization.'),
    (2, 1, 'technology', 'DGS performance reporting relies on FasterWeb (Fleet), Archibus (Facilities), EnergyCAP (Energy), and Microsoft O365/SharePoint (Capital Projects). Analysts are assigned as primary/secondary SMEs to both develop reporting and troubleshoot with BCIT or vendors. Stored queries allow reproduction of data. One dependency: timing of energy usage data delivery.'),
    (3, 1, 'procurement', 'Fleet: supply chain conditions affecting vehicle parts availability and new vehicle procurement lead times. Energy: market conditions affecting Renewable Energy Credits (RECs) pricing. Capital Projects: contractor availability and construction material cost volatility. Workforce: regional labor market competition from private sector employers offering higher starting wages.'),
    (4, 1, 'legislation', 'Maryland Building Energy Performance Standards (BEPS) require all non-exempt city-owned buildings over threshold square footage to be benchmarked and meet minimum energy performance targets — failure carries penalties. As of FY27, Baltimore City''s electric supply contract grandfathering under prior RPS legislation is expiring, increasing renewable electricity target from 20% cap to 44%.'),
    (5, 2, 'cross-agency inputs', 'Cross-agency coordination: GVRS effectiveness depends on continuous coordination across MONSE, BPD, State''s Attorney, Office of the Attorney General, federal partners, and service providers. As the strategy expands to additional districts, coordination intensity must keep pace. Recidivism outcome data for re-entry, youth diversion, and GVRS participants requires regular data sharing and validation with DPSCS and DJS, reinforced through interagency agreements.'),
    (6, 2, 'technology', 'IT/Case management: Performance plan introduces several time-sensitive KPIs requiring case management infrastructure capable of standardized timestamping, cross-program reporting, structured document storage, and reliable data export. MONSE is transitioning from Apricot to a Microsoft 365 CMS for greater cross-lane visibility and better tracking. Community surveying infrastructure must also be maintained and scaled to produce statistically reliable sample sizes for public perception metrics.'),
    (7, 2, 'staffing', 'External partner capacity: Several outcomes in Goal 4 (re-entry) and Goal 1 (wraparound services) rely on participants accessing stable housing, behavioral health, and substance use treatment through partners beyond MONSE''s direct control. Capacity in Baltimore''s behavioral health and housing systems is finite. Process metrics may register healthy program performance while outcome metrics reflect system-level capacity gaps outside MONSE''s authority.')
ON CONFLICT ("risk_id") DO UPDATE SET
    "plan_id" = EXCLUDED."plan_id", "risk_type" = EXCLUDED."risk_type", "description" = EXCLUDED."description";
SELECT setval(
    pg_get_serial_sequence('performance.service_risk', 'risk_id'),
    COALESCE((SELECT MAX("risk_id") FROM performance.service_risk), 1),
    (SELECT COUNT(*) > 0 FROM performance.service_risk)
);

