VALUES
    (1, 'AGC2300', 4, '# of Calls Requiring Assistance', 'Efficiency', 'Inquiries that come into the Call Center can be answered by a live person or the IVR-Interactive Voice Response System.', 'BRC Report:  Integrated Voice Response System Management by Vendor', 'Carla Nealy/Donna Turner', 'Chief/Customer Service Manager', 'This system''s efficiency can be viewed daily, monthly, etc.', 'BRC Report:  Integrated Voice Response System Management by Vendor', 'Decrease', NULL, NULL, 'Count', NULL, 'Whether it''s a goal to expand the IVR system for use in answering calls/inquiries', false, NULL, 'CCM Web
MicroCall', 'Data is collected from automated system.', 'The data is used to determine how effective the IVR system is in answering calls without a live person.', NULL, NULL, 'Confirm purpose of metric, either to measure efficiency of IVR system or to track call volume. Give more info on the specific process of calculating that number via a report on CCMWeb', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (2, 'AGC2300', 4, '% of Service Requests Closed on Time', 'Efficiency', 'The time required to respond to and complete customer requests or inquiries, i.e., questions, refunds, redemptions.', 'BRC Statistical Report', 'Carla Nealy or Dorothy Reed', 'Chief or Deputy Chief', 'Daily', 'BRC Statistical Report', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'CitiStat', 'Electronically', 'To track efficiency.', NULL, 'N/A', 'Re-do the information on data source, location, formula, and method of collection to detail the process of how this number can be calculated', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (3, 'AGC2300', 4, 'Average Call Center Wait Time (in minutes)', 'Outcome', 'Number of minutes a caller must wait before a call center operator answers his/her call.', 'BRC Report:  Integrated Voice Response System Management by Vendor', 'Carla Nealy or Donna Turner', 'Chief, Customer Service Manager', 'Daily, Weekly, Monthly', 'BRC Report:  Integrated Voice Response System Management by Vendor', 'Decrease', NULL, NULL, 'Count', NULL, 'Clarity on how this data can be used to measure the number of employees required to answer phones.', false, NULL, 'CCM Web
MicroCall', 'Automated system', 'This data is used to track efficiency for each call center operators. This also measures the number of employees required to answer phones.', NULL, 'N/A', 'Improve the details given for data location and formula to give clear instructions to calculate the metric', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (4, 'AGC2300', 4, 'Real Property Tax Collection Rate', 'Outcome', 'Percent of payments made prior to the tax sale - payments made by customers; and then the final percent is based upon the inclusion of the sale of tax sale certificates (tax sale).', 'BCIT Report from the Mainframe - Collect 7 Report', 'Carla Nealy or Carol Albaugh', 'Chief or Supervisor', 'Daily', 'BCIT Report', 'Increase', NULL, NULL, 'Percent', NULL, 'Will data location/method of collection change during the implementation of the TaxSMART system?', false, NULL, 'Mainframe', 'Cash, debit/credit card, wire, checks/money orders', 'Collecton of property taxes versus how much was billed.', NULL, 'N/A', 'Re-do the answers for method of collection and formula', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (5, 'AGC2300', 4, 'Interest rate on GO Bonds issued', 'Outcome', 'Interest rate on GO Bonds issued', 'Bond Offering Document - Sources & Uses Report', 'Kalief Cole, CPA', 'Deputy Chief of Treasury Management', 'As bonds are issued', 'Bond Offering Document - Sources & Uses Report', 'Decrease', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Bureau of Treasury Management', 'Bond documents', 'Demonstrates City''s use of market condition and credit rating for the benefit of optimizing borrowing costs', NULL, NULL, 'Give more info on specific report location.  how to access, etc, and a detailed formula. I''d like more detail on the metric description as well and to clarify whether the data availability is live or not.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (6, 'AGC2300', 4, '# of bids per formal solicitation', 'Output', 'Tracking the average number of bids submitted per formal solicitation', 'Comptroller''s Office website - Formal Soliciation/Bid Results', 'Kyle Parry', 'Operations Manager I', 'Live', 'Total number of formal responses received divided by total number of solicitations posted.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Comptroller''s Office Website/Procurement Records', 'Staff manually reviews bid submission summary sheets created by the Comptroller''s Office as formal bids are recieved and opened.', 'This data tracks supplier participation in the City''s posted formal solicitations', NULL, 'N/A', 'I would recommend changing the measure type from output to outcome as measure depends on suppliers submitting bids', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (7, 'AGC2300', 4, '# of purchase orders issued', 'Output', 'Tracks the total number of Purchase Orders created and issued in Workday', 'Workday report', 'Kyle Parry', 'Operations Manager I', 'Live', 'Workday report', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Workday', 'Workday delieverd reports "Find Purchase Orders" further filtered by date and satatus', 'Track Bureau of Procurement outputs to suppliers in service of Agency users.', NULL, 'N/A', 'More clarity on report name and measure formula', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (8, 'AGC2300', 4, '# of requisitions received', 'Output', 'Tracking the total number of requisitions created and processed based on the document date and status fields.', 'Workday report', 'Kyle Parry', 'Operations Manager I', 'Live', 'Workday report', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Workday', 'Workday delivered report "find requisitions"', 'This data tracks the workload created by Agency users in Workday that is then processes by the Bureau of Procurement and results in the creation of solicitations, puchase orders, and/or supplier contracts.', NULL, 'N/A', 'Clarity on report name and measure formula', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (9, 'AGC2300', 4, '% of formal solicitations meeting benchmark of 150 day turnaround', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Percent', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
