    (11, 'AGC2300', 4, '# of pieces of property surplused', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
