    (13, 'AGC2300', 4, '# of billable jobs', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (14, 'AGC2300', 4, 'Average # of days for Print Shop job turnaround', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (15, 'AGC2300', 4, '# of off-cycle checks', 'Output', 'The number of off-cycle payments issued measures how many payroll payments were processed outside of the regular payroll cycle to handle time-sensitive or corrective pay events.', 'Headcount Report, Direct Deposit register, check register, and Audit Missing Payment Elections reports', 'Danielle Tillman', 'Acting Chief, BAPS', 'Quarterly', 'Off-Cycle Payments Issued=Total number of payroll payments processed outside the regular payroll cycle during the period', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Workday', 'Off-cycle payments are pulled from Workday payroll transaction reports', 'This metric is used to understand how much exception payroll work the City is generating.', NULL, 'n/a', 'Addition of needed parameters to run reports', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (16, 'AGC2300', 4, '# of payroll checks / advices issued', 'Effectiveness', 'The number of payroll checks / advices issued is the total count of employee pay statements generated by the City’s payroll system for a given pay period or reporting window including direct deposits and physical checks.,', 'Workday reports: Headcount Report, Direct Deposit register, check register, and Audit Missing Payment Elections', 'Danielle Tillman', 'Acting Chief, BAPS', 'Quarterly', 'Payroll Checks / Advices Issued=Total number of pay statements generated by Workday for the period', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Workday', 'The count is pulled directly from payroll processing reports, which list every pay advice and live check generated for each payroll run.', 'This metric is used to monitor the scale and stability of each payroll run.', NULL, 'n/a', 'Clarification on why this is an effectiveness metric rather than output', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (17, 'AGC2300', 4, '% of employees using direct deposit', 'Efficiency', 'The percentage of employees using direct deposit measures how much of the City’s payroll is being delivered through the most secure, efficient, and controlled payment method (vs paper checks).', 'Direct Deposit register', 'Danielle Tillman', 'Acting Chief, BAPS', 'Monthly', 'Number of employees enrolled in direct deposit divided by total number of employees paid in the period (times 100)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Direct deposit register', 'Direct deposit enrollment is pulled from Workday payroll and employee payment-election records, which show how each active employee is set up to receive pay.', 'When more employees use direct deposit, the City has fewer lost or late checks, less manual work, and fewer payroll problems, which makes payroll cheaper, faster, and more reliable for everyone.', NULL, 'n/a', 'Clarify report location and parameters', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (18, 'AGC2300', 4, 'Average # of days for month-end close', 'Efficiency', 'We are measuring the number of business days it takes from the last day of the accounting month until the general ledger for that month is formally closed and locked for reporting.

"Month-end date" definition: The final calendar day of the accounting period
(e.g., January 31).

"Close start" definition: Begins on the first day of the next month
(e.g., February 1).

"Close complete (the stop clock)" definition: the date when all required journal entries are posted, all subledgers are reconciled, all bank and cash accounts are reconciled, and the period is closed/locked in Workday so no further changes can be made without reopening.', 'Manually tracked via Excel (no current WD report that pulls this data cleanly)', 'Danae Moore', 'Accounting Manager, BAPS', 'Monthly', 'Days to Close = Close Complete Date – Month-End Date (minus holidays)', 'Decrease', NULL, NULL, 'Count', NULL, 'Are there efforts to create a report?', false, NULL, 'Internal BAPS spreadsheet', 'Workday accounting ledgers', 'Days to month-end close shows how quickly the City can produce accurate, complete financial information. A shorter, consistent close means agency fiscal leadership is making decisions using real numbers, not estimates, and problems are caught early instead of surfacing at year-end.', NULL, 'n/a', 'Creation of a more stable report (likely hosted on Workday) to store data', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (19, 'AGC2300', 4, '# of claims received annually per 100 employees', 'Efficiency', 'This measure represents the rate of Workers’ Compensation claims reported annually, normalized per 100 City employees. It is calculated by dividing the total number of claims received during the reporting period by the total number of City employees, then multiplying by 100. This metric provides insight into the frequency of workplace injuries relative to workforce size and helps track trends in employee safety over time.', 'Claims Administration (Sedgwick) report', 'Chris Allen', 'Special Assistant', 'Monthly', 'Claims per 100 Employees=(Total Number of Employees/Number of Claims in Period​)×100', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'The data is maintained in Sedgwick’s claims management system by the third-party administrators. Copies of the reports are also stored on the Bureau’s SharePoint, providing internal access for analysis and historical tracking.', 'Claims are recorded in Sedgwick’s system as they are reported. The total number of claims is extracted from standard reports and divided by employee counts to calculate the rate per 100 employees.', 'This metric tracks the frequency of workplace injuries relative to workforce size, helping the Bureau evaluate safety programs, identify trends, and target initiatives to reduce employee injuries and associated claims.', NULL, NULL, 'Would recommend chaning to an outcome type metric', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (20, 'AGC2300', 4, '# of employees on paid-leave status per 100 employees', 'Outcome', 'This metric represents the number of City employees on paid leave due to Workers’ Compensation claims, normalized per 100 employees. This measure provides insight into the severity and impact of workplace injuries on the workforce.', 'Workday report', 'Chris Allen', 'Special Assistant', 'Monthly.', 'Employees on Paid Leave per 100 Employees = (Number of Unique Employees with Paid Leave ÷ Total Number of Employees) × 100', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Data on employees on paid-leave status is stored in Workday, with a scheduled report exported monthly. This report is saved in a shared file hosted on the Acting Director’s OneDrive for internal reference and historical tracking.', 'Data is collected from Workday using a scheduled monthly report of all applicable absence requests. Each line represents a day of absence for a specific employee. To calculate the metric, duplicate entries are removed using the Workday ID as a unique identifier, and the total number of employees with at least one paid-leave absence due to a Workers’ Compensation claim is counted for the reporting period.', 'This metric is used to monitor the number of employees on paid leave due to Workers’ Compensation claims. It provides insight into the severity of workplace injuries and helps the Bureau assess trends in claims that result in lost work time.', NULL, NULL, 'Detail the name of the Workday report used and any needed parameters', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (21, 'AGC2300', 4, '# or random drug / alcohol tests completed', 'Output', 'This measure tracks the total number of random drug and alcohol tests conducted within the reporting period. It ensures the City remains in compliance with the Administrative Manual (AM) and all applicable regulatory requirements, supporting adherence to mandated workplace safety standards.', 'The number of random drug and alcohol tests is tracked through weekly email notifications from the Occupational Health Facility. These notifications detail all tests performed and indicate whether each scheduled random test was attended or unattended, providing the official record for internal tracking and reporting.', 'Chris Allen', 'Special Assistant', 'Weekly.', 'Number of Random Tests Completed = Total Number of Scheduled Random Tests − Number of Missed Tests', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Records of random drug and alcohol tests are maintained by the Occupational Health Facility, and Bureau staff access and reporting are based on these official records. Copies of the reports are also stored on the Bureau’s SharePoint as a backup for internal reference and historical tracking.', 'Random drug and alcohol tests are scheduled according to the City’s testing program. The Occupational Health Facility tracks which tests are completed and which are missed, sending weekly email notifications to the Bureau. The total number of tests completed is calculated by subtracting the number of missed tests from the total number of scheduled tests.', 'This metric ensures the City remains in compliance with the AM Manual and all regulatory requirements for drug and alcohol testing. It allows the Bureau to monitor adherence to the testing schedule, identify missed tests, and take corrective action to maintain a safe and compliant workplace.', NULL, NULL, 'Develop a single report that consolidates all drug testing reports for simple calculation', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (22, 'AGC2300', 4, 'Average claim cost per employee', 'Efficiency', 'This measure represents the average Workers’ Compensation claim cost attributable to each City employee during the reporting period. It is calculated by dividing the total incurred Workers’ Compensation claim costs—defined as the sum of all paid losses and outstanding reserves for claims during the period—by the total number of City employees during the same reporting period.', 'Claims Administration (Sedgwick) report', 'Chris Allen', 'Special Assistant', 'Monthly', 'Average Claim Cost per Employee=Total Incurred Claims Costs (Paid + Reserves)/Total Number of Employees	​', 'Decrease', NULL, NULL, 'Currency', NULL, 'N/A', false, NULL, 'The data for this metric is maintained on Sedgwick’s system by the third-party administrators, ensuring that the official claims information is securely stored and managed. For internal reference and historical tracking, copies of the reports are also sto', 'Workers’ Compensation claim data is collected and maintained by the third-party administrator, Sedgwick, through their claims management system. The total incurred costs and employee counts are extracted from their system via standard reports, which are t', 'This metric helps monitor the financial impact of workplace injuries, assess the effectiveness of safety programs, and guide decisions on risk management and resource allocation to reduce claims costs and improve employee safety.', NULL, NULL, 'Clarify how a city employee could access this data', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (23, 'AGC2300', 4, '# of fiscal notes and bill responses prepared', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (24, 'AGC2300', 4, '# of Management Research reports published annually', 'Outcome', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (25, 'AGC2300', 4, 'Revenue forecast accuracy', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Percent', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (26, 'AGC2300', 4, 'Turnaround time for BOE Submit approvals', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (27, 'AGC2300', 4, '# of appraisals reviewed / completed', 'Output', 'Tracks the total number of property appraisals that are reviewed or completed by the Fiscal Integrity Office during a reporting period.', 'CHAP Tracking Spreadsheet and the Tax Credit System', 'Johanna Collado', 'Director of the Fiscal Integrity Office', 'Live', 'Total number of appraisal reviews during the reporting period.', 'Not Applicable', NULL, NULL, 'Count', NULL, 'Is there a distinction between a reviewed and completed appraisal that needs to be considered?', false, NULL, 'OneDrive and Tax Credit System', 'Excel report and report from the Tax Credit System.', 'This measure provides insight into the office workload and productivity in managing property appraisal reviews for CHAP applications.', NULL, NULL, 'Clarify report name and location', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (28, 'AGC2300', 4, '# of tax credit applications received', 'Output', 'This measure tracks the total number of applications received by the Fiscal Integrity Office via the Tax Credit System during the reporting period.', 'Tax Credit System', 'Johanna Collado', 'Director of the Fiscal Integrity Office', 'Live', 'Cumulative', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Tax Credit System', 'Reports from the Tax Credit System', 'The number of applications received is an output measure that tracks workload and service demand.', NULL, NULL, 'Clarify report name and location', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (29, 'AGC2300', 4, '# of tax credits rejected or revoked', 'Output', 'Tracks the total number of tax credit applications that are rejected or previously granted credits that are revoked during a reporting period due to the review of initial and continuing eligibility requirements. This measure reflects workload and processing activity.', 'Tax Credit System', 'Johanna Collado', 'Director of the Fiscal Integrity Office', 'Live', 'Total number of tax credit applications rejected or tax credits revoked during the reporting period', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Tax Credit System', 'Reports from the Tax Credit System', 'This measure provides insight into office workload related to reviewing eligibility requirements, rejecting, or revoking applications.', NULL, NULL, 'Clarify report name and location', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (30, 'AGC2300', 4, '$ of increase property tax revenue attributable to successful appeals', 'Outcome', 'Estimation of the amount of additional (new) revenue generated by the successful appeals of property tax assessments.', 'Appeal Tracking Spreadsheet for the given Fiscal Year, as well as the latest assessment data from the monthly GIS data file.', 'Johanna Collado', 'Director of the Fiscal Integrity Office', 'Monthly', '(New Full Cash Value Reassessment – Original Full Cash Value Reassessment) x City Tax Rate x 2  [the x2 factor accounts for the phase-in of the difference over the three-year assessment cycle, with 1/3 applied in the first year, 2/3 applied in the second year, and the full difference applied in the third year.', 'Not Applicable', NULL, NULL, 'Currency', NULL, 'N/A', true, NULL, 'Department''s shared R drive.', 'Analysis of the latest assessment information that the State has loaded into the City’s Real Property System, as displayed in the monthly GIS file.', 'The estimated increase in property tax revenue indicates the accuracy of the initial reassessment values; lower additional revenue suggests the original assessments were correct. While this revenue reflects the Assessment Appeals Unit''s performance, the unit''s success is more accurately measured by the ratio of successful appeals to total appeals filed. Importantly, the unit cannot file appeals or generate revenue when original assessments are accurate.', NULL, NULL, 'Clarify what the actual name of the appeal tracking spreadsheet is', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (31, 'AGC2300', 4, '# of tax credit applications granted', 'Output', 'Tracks the total number of tax credit applications that are approved and granted by the Fiscal Integrity Office during the reporting period. Reflects workload and processing activity.', 'Tax Credit System', 'Johanna Collado', 'Director of the Fiscal Integrity Office', 'Live', 'Total number of tax credits granted during the reporting period.', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Tax Credit System', 'Reports from the Tax Credit System', 'This measure tracks the volume of tax credits granted by the Fiscal Integrity Office, providing insight into workload and operational demand.', NULL, NULL, 'Clarify report name and location', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (32, 'AGC2300', 4, '% of active grants with at least 1 drawdown during the fiscal year', 'Effectiveness', 'The % of active grants with at least one drawdown during the fiscal year measures how many of the City’s awarded grants are actually being used to bring money in, rather than sitting idle in Workday. 

Key definitions: 
Active grant: A grant with a valid Workday grant worktag that is open and eligible to incur expenses during the fiscal year (i.e., not closed, expired, or fully spent).

Drawdown: A request submitted to a grantor to reimburse the City for eligible grant expenses, resulting in cash being received or posted.', '"Find Customer Invoices for Company" Workday report (filtered for grants, date of invoice, invoice due date, invoice status approved and paid)', 'Ashley Meyer', 'Grants Director', 'Quarterly', 'Number of active grants with at least one drawdown during a fiscal year divided by total number of grants during a fiscal year, times 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, '"Find Customer Invoices for Company" Workday report (filtered for grants, date of invoice, invoice due date, invoice status approved and paid)', 'Drawdown activity is pulled from the City’s grant billing/drawdown records in Workday, which show which active grant worktags had at least one reimbursement request submitted during the fiscal year.

GMO compares the list of active grants in Workday.', 'Leadership uses this metric to see whether the City’s grants are functioning as real revenue streams. A grant that never has a drawdown is effectively lost or delayed money, even if it was awarded. This metric shows whether Baltimore is actually turning grant awards into cash to fund services, reimburse costs, and stay compliant with grantor deadlines.', NULL, 'n/a', 'No improvement needed', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (33, 'AGC2300', 4, '% of city agencies (with grants) that participate in monthly trainings', 'Outcome', 'The % of City agencies (with grants) that participate in monthly trainings measures how broadly Finance’s grant management guidance is actually reaching the agencies that receive and manage grant funding.', 'Teams attendance tracking', 'Ashley Meyer', 'Grants Director', 'Monthly', 'Number of City agencies with ≥1 attendee at the monthly training / Total number of City agencies with at least one active grant worktag in Workday x 100', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Internal tracking', 'Training participation is tracked by comparing monthly training attendance logs on Teams to the list of City agencies with active grant worktags in Workday for that month', 'This metric is used to show whether Finance’s grant guidance is actually reaching the agencies that manage grant money. High participation means agencies are more likely to submit correct invoices, draw funds on time, and avoid audit findings.', NULL, 'n/a', 'Clarity on internal tracking', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (34, 'AGC2300', 4, 'Number of audit findings with corresponding corrective action plan', 'Outcome', 'The number of audit findings with a corresponding corrective action plan (CAP) measures how many audit issues have been formally addressed with a documented plan for fixing them, whether the plan is completed, underway, or not yet started.', 'GMO CAPS Sharepoint Site: https://bmore.sharepoint.com/sites/opi/grants-management/SitePages/Home.aspx?xsdata=MDV8MDJ8YXNobGV5Lm1leWVyQGJhbHRpbW9yZWNpdHkuZ292fDA4NmVkMmU1MDBjOTQ4YTYzNjM5MDhkZGQ2OGNiMjU4fDMxMmNiMTI2YzZhZTRmYzI4MDBkMzE4ZTY3OWNlNmM3fDB8MHw2M', 'Ashley Meyer', 'Grants Director', 'Quarterly', 'The number of audit findings that have been formally assigned a corrective action plan and entered into DOF’s CAP tracking process.', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'GMO SharePoint Site "Grants Management Audit Tracker"', 'Agencies report their progress each quarter, and Finance consolidates and tracks the results.', 'This metric is used to show whether the City has moved every audit finding into a  remediation process. Leadership uses it to:

-Confirm that no audit finding is unassigned or ignored

-Ensure every issue has a named owner, a plan, and a tracking record

-Demonstrate to auditors, the State, and grantors that findings are being actively managed, not sitting unresolved

-Provide a baseline for monitoring progress through the CAP statuses (Complete, In Progress, Not Started)', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (35, 'AGC2300', 4, 'Number of grant worktags processed', 'Effectiveness', 'The number of grant worktags processed is a count of how many new or updated grant identifiers are successfully set up in Workday so agencies can spend, bill, and draw against their awards.

Key definitions-
Grant worktag: The unique Workday code for a specific grant award that links all spending, billing, and drawdowns to that grant.
Grant award: A legally executed funding agreement from a grantor (federal, state, or other).', '"Extract Grants with Hierarchies with Agency & Service" Workday report (filtered for date created and not inactive)', 'Ashley Meyer', 'Grants Director', 'Monthly', 'Grant Worktags Processed=Total count of grant worktags created or updated in Workday during the period', 'Increase', NULL, NULL, 'Count', NULL, 'Clarity on whether agencies or GMO is inputting grant worktags. If agencies, then keep type as effectiveness but if GMO then I''d recommend Output type', true, NULL, 'Workday', 'Workday report "Extract Grants with Hierarchies with Agency & Service" (filtered for date created and not inactive)', 'This measures how fast the City converts awards into usable funding. If worktags aren’t processed, agencies cannot spend or draw funds, even if the grant is signed.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (36, 'AGC2300', 4, 'Monetary recoveries in a FY', 'Outcome', 'Actual revenue recovered', 'Sharepoint, MUNIS, Workday', 'Daniel Goldberg', 'Director, Corporate Compliance', 'Live', 'Actual revenue received', 'Increase', NULL, NULL, 'Currency', NULL, 'N/A', false, NULL, 'Sharepoint', 'Revenue received via ACH payments, wire transfers, checks, or via settlement agreements and/or litigation', 'Revenue was used as input for future budgetary decisions and calculations', NULL, 'Finance departments, such as BBMR and BRC, use this information for budgetary and collection purposes.', 'Clarify data calculation process', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (37, 'AGC2300', 4, 'Number of case reviews completed in a FY', 'Output', 'Number of case reviews completed or brought into compliance', 'Actual cases, analysis of taxes submitted in MUNIS and workday', 'Daniel Goldberg', 'Director, Corporate Compliance', 'Live', 'Actual cases', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Sharepoint', 'Review of actual cases completed', 'Cases are used to ensure compliance with existing business code and regulations, including some entities that are currently in compliance', NULL, 'Other finance departents, such BBRM and BRC, use this information', 'Clarify data storage location/access', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (38, 'AGC2300', 4, 'Number of cases opened in a FY', 'Outcome', 'Cases opened for review in the first half of FY 26', 'Internal tracker', 'Daniel Goldberg', 'Director, Corporate Compliance', 'Live', 'Actual cases opened', 'Increase', NULL, NULL, 'Count', NULL, 'Clarify metric description. Description specifices first half of FY26, so I''m not sure what time frame this metric is intended to apply to', false, NULL, 'Sharepoint', 'Internal tracking', 'Review of open cases for further analysis', NULL, 'Cases and tracking used for finance departments, including BBMR and BRC', 'Clarify data storage location/access', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (39, 'AGC2300', 4, '% rate of return on short-term (6-month) investments vs. 6-month Treasury', 'Outcome', 'This performance measures the investment performance of the City''s portfolio. The portfolio is measured against the performance of its designated benchmark which is the 6-month U.S. Treasury Bill (T-Bill). A benchmark is used as a standard against which the performance of a security, mutual fund or investment manager can be measured. The 6-month T-Bill was selected as the appropriate comparative security "the benchmark" due to its short-term nature, low risk profile, high liquidity and high credit quality.', 'Treasury Mmgt. Monthly Investment Report', 'Kalief Cole, CPA', 'Deputy Chief of Treasury', 'The data is available on a monthly basis.', 'Treasury Mmgt. Monthly Investment Report compiled and calculated in Clearwater.', 'Increase', NULL, NULL, 'N/A', NULL, 'N/A', false, NULL, 'The data is collected and stored in a cloud based software, Clearwater Analytics.', 'Clearwater is updated when there are purchases and redemptions in the investment portfolio.', 'Treasury effectively invests all available cash on a daily basis ensuring no material amoung of cash sits in the City''s bank account un-invested.', NULL, 'N/A', 'Clear calculation instructions, including any needed parameters and/or filters', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (40, 'AGC2500', 4, '% of fires that progress to a multiple alarm of fire', 'Outcome', 'The percent of fires that progress to a multiple alarm of fire', 'Database', 'John F. Eid, BS, NRP', 'Assistant Chief Operations', 'Live', '# of fires that progress to a multiple alarm fire / total # of fires', 'Decrease', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CAD/ BCFD IT', 'Fire Records System/ BCFD IT', 'This measure is used to evaluate how successfully initial responding units contain fires before they escalate and require significant additional resources. It helps leadership assess the adequacy of first-alarm assignments, water supply reliability, command effectiveness, and tactical decision-making. Patterns in this data can trigger changes to response protocols, staffing levels, or pre-incident planning for higher-risk occupancies. It is meaningful because multiple-alarm fires increase risk to firefighters, strain citywide coverage, drive overtime costs, and often result in greater property loss and community displacement.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (41, 'AGC2500', 4, '% of responses with 1st engine on scene within 5 minutes, 20 seconds', 'Effectiveness', 'The overall percentage of responses with the first engine on the scene within 5 minutes, 20 seconds', 'database', 'John Eid', 'Assistant Chief', 'Weekly', '(# of responses with 1st engine on scene within 5 minutes, 20 seconds / total # of responses)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CAD', 'BCFD IT / Filter CAD Data', 'This measure is used to evaluate how effectively the department deploys resources to reach emergencies quickly and consistently. It informs decisions about station placement, unit staffing, first-due boundaries, dispatch practices, and daily coverage adjustments. Monitoring this metric helps identify response-time gaps caused by staffing shortages, unit availability, traffic, or dispatch delays and supports corrective actions such as redeployment, overtime staffing, or operational policy changes. It is meaningful because rapid first arrival is critical to controlling fire growth, improving survivability, reducing firefighter risk, and limiting property damage; even small delays can significantly worsen incident outcomes.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (42, 'AGC2500', 4, 'Number of fatal fires per 100,000 residents', 'Outcome', 'The number of fatal fires per 100,000 Baltimore City residents', 'Database', 'John Eid', 'Assistant Chief of Operations', 'Live', 'Database', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Fire Marshall''s Office', 'Fire Marshall Consult / BCFD IT', 'This measure is used to assess overall community fire safety outcomes and the effectiveness of both suppression and prevention strategies. By normalizing fatalities by population, the department can identify high-risk neighborhoods, populations, and contributing factors such as lack of smoke alarms, housing conditions, or delayed detection. The data informs targeted prevention efforts, training priorities, and interagency interventions with housing, health, and social services. It is meaningful because it directly reflects the department’s core mission of saving lives and provides a clear, outcome-based indicator of whether operational and prevention efforts are reducing preventable fire deaths.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (43, 'AGC2500', 4, 'Number of home safety inspections', 'Output', 'Number of home safety inspections', 'Database', 'John Eid', 'Assistant Chief Operations', 'Live', 'Actual # within the time period', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'BCFD Fire Records', 'Fire Records System/ BCFD IT', 'This measure is used to track the department’s proactive prevention and community risk reduction efforts aimed at reducing fires before they occur. It informs how prevention resources are allocated and whether high-risk neighborhoods and populations are being reached through education, smoke and carbon monoxide alarm installation, and hazard identification. The data supports coordination with code enforcement and social service partners and helps evaluate the effectiveness of outreach programs. It is meaningful because home safety inspections address root causes of residential fires, lower the likelihood of serious incidents, and contribute to long-term reductions in injuries, fatalities, and emergency calls.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (44, 'AGC2500', 4, 'Community members trained for community emergency response team program', 'Outcome', 'Number of Community Members who completed the Community Emergency Response Team certification training.', 'Training Rosters', 'Kim Stinchcomb', 'Deputy Director of Planning and Administration', 'Monthly', 'Total number of individuals that complete the training.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'OEM Staff Sharepoint - Excel sheet', 'Manual entry in excel sheet from Training roster after each class.', 'Data on community members trained through the CERT program demonstrate the City’s commitment to whole-community preparedness by building local response capacity, strengthening neighborhood resilience, and expanding the pool of trained volunteers who can support emergency response and recovery efforts.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (45, 'AGC2500', 4, 'Drills and table top exercises held with stakeholders', 'Output', 'Number of Workshops, Drills, and Exercises (TTX, Functional, Full Scale) completed by OEM in partnership with City Agencies.', 'Internal Tracking System', 'Kim Stinchcomb', 'OEM Deputy Director of Planning and Administration', 'Monthly', 'Internal Tracking System', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'OEM Staff SharePoint - Excel Sheet', 'Recorded via tracking spreadsheet after completion of a workshop, drill, or exercise.', 'This data demonstrates preparedness capability, service quality, and continuous improvement. These activities build skills in emergency response coordination, incident command and decision-making, communication and information sharing, continuity of operations and recovery planning. Data allow us to demonstrate that the City is fullfilling its goal to train City staff and partners and test emergency plans and procedures.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (46, 'AGC2500', 4, 'Number of on-scene responses for city resource coordination', 'Output', 'Number of on-scene responses where OEM was deployed.', 'CAD', 'Kim Stinchcomb', 'Deputy Director of Planning and Administration', 'Daily', 'Total reponses where OEM responded by event.', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'CAD', 'CAD', 'The number of on-scene responses for city resource coordination measures the service’s direct operational involvement in emergency incidents and planned events. This metric reflects the demand for interagency coordination, informs staffing and readiness decisions, and demonstrates the value of centralized resource management in supporting effective incident response.', NULL, 'OEM Duty Officer Incident Report', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (47, 'AGC2500', 4, 'Percentage of Homeland Security grant dollars spent or invoiced 60 days before grant close out', 'Output', 'Percent of Federal FEMA/Homeland Security grant funds that are invoiced before grant closure', 'Grant Management System', 'Kim Stinchcomb', 'Deputy Director of Planning and Administration', 'Live', 'Total grant funds spent/Total grant funds awarded', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Grants Management System', 'Grant Management System', 'The percentage of Homeland Security grant funds spent or invoiced at least 60 days prior to grant closeout measures the service’s ability to execute grant-funded projects efficiently, manage financial risk, and ensure compliance with federal requirements. This metric supports proactive grant management and helps ensure preparedness investments deliver their intended impact.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (48, 'AGC2500', 4, '# of EMS Incidents', 'Output', 'Actual number of times that an EMS unit is dispatched to a response', 'CAD', 'James Matz', 'Assistant Chief of Emergency Services', 'Monthly', 'CAD', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'CAD', 'CAD Data', 'This metric refers to the number of times that an EMS unit is dispatched. The EMS Division measures responses rather than incidents given that one incident could have multiple units responding. This measure includes all instances when a medic unit is cancelled en-route, a telling indicator of inefficient dispatching.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (49, 'AGC2500', 4, '# of patients outreached by population health', 'Output', '# of Patients outreached by Population Health', 'Elite', 'James Matz', 'Assistant Chief of Emergency Services', 'Weekly', 'Actual number within the time period', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'ELITE/ Population Health Records', 'CARES Report extraction from Statewide CARES database', 'This measure is used to assess the quality and effectiveness of prehospital cardiac arrest care, including early CPR, defibrillation, advanced life support, and coordinated post-resuscitation efforts. It helps guide training priorities, equipment deployment, and protocol refinement for high-acuity cardiac events. This metric is meaningful because cardiac survival rate is a widely recognized indicator of EMS clinical performance and directly reflects the system’s ability to save lives during one of the most critical medical emergencies.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (50, 'AGC2500', 4, '% of EMS response within 9 minutes', 'Output', '% of EMS Response within 9 Minutes', 'CAD', 'James Matz', 'Assistant Chief of Emergency Services', 'Weekly', 'Total number of responses within the 9 minutes/Total number of responses', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CAD', 'BCFD IT / Filter CAD Data', 'This measure tracks the reach and effectiveness of EMS-led population health and community paramedicine initiatives aimed at reducing repeat 911 calls and improving chronic disease management. It informs decisions about targeting high-utilizer patients, coordinating with healthcare and social service partners, and allocating outreach staff. This metric is meaningful because proactive patient engagement can improve health outcomes, reduce unnecessary emergency responses, and lower overall system strain.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (51, 'AGC2500', 4, '% QA Reports reviewed', 'Output', '% QA Reports reviewed', 'ELITE/FirstWatch', 'James Matz', 'Assistant Chief of Emergency Services', 'Monthly', 'Actual ePCRs reviewed by BCFD', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Elite/First Watch', 'Combination of ELITE and First Watch Records', 'This measures the number of electronic patient care reports (ePCRs) reviewed for accuracy, completeness, and protocol compliance.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (52, 'AGC2500', 4, 'Cardiac survival rate', 'Output', 'Cardiac Survival Rate', 'CARES', 'James Matz', 'Assistant Chief of Emergency Services', 'Monthly', '# of cardiac arrest survivors/Total number of cardiac arrests', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CARES Database', 'CARES Report extraction from Statewide CARES database', 'This measure is used to assess the quality and effectiveness of prehospital cardiac arrest care, including early CPR, defibrillation, advanced life support, and coordinated post-resuscitation efforts. It helps guide training priorities, equipment deployment, and protocol refinement for high-acuity cardiac events. This metric is meaningful because cardiac survival rate is a widely recognized indicator of EMS clinical performance and directly reflects the system’s ability to save lives during one of the most critical medical emergencies.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (53, 'AGC2500', 4, '# of citizens trained in hands-only CPR', 'Output', '# of citizens trained in Hands-Only CPR', 'internal BCFD database', 'James Matz', 'Assistant Chief of Emergency Services', 'Monthly', '# of citizens trained by the BCFD in Hands-Only CPR', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'BCFD Outreach', 'BCFD Internal Tracker', 'This measure informs how effectively the department is expanding lifesaving capacity beyond its own responders by equipping the public to act during cardiac emergencies. It helps guide outreach planning, training deployment, and partnerships with schools, workplaces, and community organizations, particularly in areas with high cardiac arrest incidence or longer response times. This metric is meaningful because early bystander CPR significantly increases survival rates for cardiac arrest victims, making community training a critical extension of EMS operations and a powerful driver of improved patient outcomes.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (54, 'AGC2500', 4, '# of City and BOPA-sponsored events accommodated', 'Outcome', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Increase', NULL, NULL, 'Count', NULL, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, 'straight-forward', NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (55, 'AGC2500', 4, '# of leave behind Narcan kits left with citizens', 'Output', '# of leave behind Narcan kits left with citizens', 'internal BCFD database', 'James Matz', 'Assistant Chief of Emergency Services', 'Monthly', 'Actual # of Naloxone Kits left behind with patients, family, and bystanders', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'BCFD Population Health', 'ELITE/BCFD Inernal tracker', 'This measure informs how effectively the department is extending overdose prevention efforts beyond the immediate emergency response by equipping citizens, families, and bystanders with lifesaving naloxone. It helps guide outreach strategies, identify communities with high overdose risk, and assess coordination with public health and harm-reduction partners. This metric is meaningful because leave-behind Narcan kits increase the likelihood of rapid intervention during future overdoses, reduce repeat fatal incidents, and position the fire and EMS service as a proactive public health partner focused on prevention as well as emergency response.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (56, 'AGC2500', 4, '# of non-City sponsored events accommodated', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Increase', NULL, NULL, 'Count', NULL, NULL, false, NULL, NULL, NULL, NULL, NULL, NULL, 'straight-forward', NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (57, 'AGC2500', 4, '# of requests received for Fire and Life Safety educational programs', 'Output', '# of requests received for Fire and Life Safety educational programs', 'internal BCFD database', 'Kensington White', 'Executive Assistant Chief', 'Monthly', '# of requests received from the public', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'BCFD IT', 'Fire Records/BCFD IT', 'This measure informs the department about community demand for fire and life safety education and helps guide staffing, scheduling, and resource allocation for prevention and outreach activities. It allows leadership to identify trends in public interest, emerging risk areas, and opportunities to proactively engage schools, businesses, and community organizations. This metric is meaningful because strong demand for educational programs reflects community trust and engagement, and these programs play a critical role in reducing preventable fires, injuries, and fatalities by increasing public awareness and safe behaviors.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (58, 'AGC2500', 4, '# of fire inspections completed annually', 'Output', 'This measure tracks the total number of fire code inspections conducted by the department each year. Inspections include routine, follow-up, and complaint-driven visits to ensure compliance with fire safety regulations in all occupancies.', 'Fire Records database', 'Robert Hamlin', 'Deputy Chief – Fire Marshal', 'Data is available live and can be aggregated monthly and annually.', 'Total number of fire inspections completed within the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Records Management Database (internal records system)', 'Inspections are logged electronically by inspectors in the field using mobile devices, or in office using a desktop computer; with data uploaded in real time to the central database.', 'This data is used to monitor workload, allocate inspection resources, and ensure that all required occupancies are inspected on schedule. It is meaningful because regular inspections are critical to identifying and correcting fire hazards, thereby reducing the risk of fire incidents and improving public safety. Trends in inspection volume can also inform staffing and training needs.', NULL, 'Not applicable; data is captured live.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (59, 'AGC2500', 4, '# of new Use and Occupancy Permits completed annually', 'Output', 'This measure tracks the total number of new Use & Occupancy Permits issued by the department each year, reflecting new or changed building uses that require fire code compliance verification.', 'Permit records are maintained in the Records Management Database. The annual total is calculated by summing all new permits issued within the fiscal year.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is updated live and can be reported monthly and annually.', 'Total number of new Use & Occupancy Permits issued within the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Records Management Database', 'Permits are logged electronically upon issuance.', 'This measure is used to monitor workload and ensure that all new or modified occupancies are inspected for fire code compliance before use. It is meaningful because it ensures public safety in new or renovated buildings and supports economic development.', NULL, 'Not applicable; data is captured live.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (60, 'AGC2500', 4, '# of Plan Reviews', 'Output', 'This measure tracks the total number of fire code plan reviews conducted annually, including new construction, renovations, and special projects.', 'Plan review records are maintained in the Plan Review Management System. The annual total is calculated by summing all plan reviews completed within the fiscal year.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is updated live and can be reported monthly and annually.', 'Total number of plan reviews completed within the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Plan Review Management System', 'Plan reviews are logged electronically upon completion.', '•	This measure is used to monitor workload, allocate resources, and ensure timely review of construction and renovation projects for fire code compliance. It is meaningful because thorough plan reviews prevent code violations and hazards before construction begins, supporting public safety and efficient project delivery.', NULL, 'Not applicable; data is captured live.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (61, 'AGC2500', 4, '# of training hours completed annually', 'Output', 'This measure captures the total number of training hours completed by Fire Code Enforcement personnel annually, including mandatory certifications, continuing education, and specialized fire code training.', 'Training attendance and completion records are maintained in the department’s Records Management Database.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is updated live and can be reported monthly and annually.', 'Total number of training hours completed by all personnel within the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Records Management Database', 'Training hours are logged by members supervisor and verified by next level supervisors upon course completion.', 'This measure informs leadership about the department’s investment in workforce development and ensures compliance with regulatory and best-practice training standards. It is meaningful because well-trained inspectors are more effective at identifying hazards and enforcing codes, directly impacting community safety.', NULL, 'Not applicable; data is captured live.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (62, 'AGC2500', 4, '% of complaints/fire code violations completed within 10 days annually', 'Outcome', 'This measure tracks the percentage of fire code complaints or violations that are investigated and resolved within 10 days of receipt.', 'Complaint and violation records are maintained in the Records Management Database and City’s 311 database. The percentage is calculated by dividing the number of cases closed within 10 days by the total number of cases received annually.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is updated live and can be reported monthly and annually.', '(Number of complaints/violations closed within 10 days ÷ Total number of complaints/violations received) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Records Management Database and 311 database.', 'Complaints and violations are logged upon receipt, and closure dates are recorded upon resolution.', 'This measure is used to assess the department’s responsiveness to community concerns and code violations. Timely resolution reduces risk, improves public trust, and ensures hazardous conditions are addressed promptly. It is meaningful as it reflects operational efficiency and customer service quality.', NULL, 'Not applicable; data is captured live.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (63, 'AGC2500', 4, '% of initial plan reviews assigned and completed within 30 days annually', 'Outcome', 'This measure tracks the percentage of initial fire code plan reviews that are assigned and completed within 30 days of submission.', 'Plan Review Management System. The percentage is calculated by dividing the number of reviews completed within 30 days by the total number of reviews submitted annually.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is updated live and can be reported monthly and annually.', '(Number of plan reviews completed within 30 days ÷ Total number of plan reviews submitted) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Plan Review Management System', 'Plan submissions and completion dates are logged electronically.', 'This measure informs management about the efficiency of the plan review process, which is critical for timely construction and occupancy approvals. Delays can impact economic development and public safety. The metric is meaningful as it reflects the department’s ability to support community growth while maintaining safety standards.', NULL, 'Not applicable; data is captured live.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (64, 'AGC2500', 4, '# of fire investigations ruled incendiary', 'Outcome', 'This measure counts the total number of fire investigations that, upon completion, are ruled as incendiary (deliberately set) annually.', 'Records Management Database: Each case’s cause determination is recorded in the system and cross-referenced with Baltimore Police Arson data.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data available live; can be reported monthly and annually.', 'Actual count of investigations classified as incendiary during the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Records Management Database', 'Investigators classify the cause upon case closure; data is extracted via query.', 'This metric provides insight into the prevalence and detection of arson within the community. It informs resource allocation for prevention, public education, and law enforcement collaboration. The data is meaningful for identifying trends and targeting interventions.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (65, 'AGC2500', 4, '# of fires investigated', 'Output', 'This measure counts the total number of fire incidents investigated by the department annually.', 'Records Management Database: Each fire investigation is logged at assignment.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is available live and can be reported monthly and annually.', 'Actual count of fires investigated during the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Location: Records Management Database', 'Investigations are entered by staff as incidents are assigned.', 'This measure reflects workload and is used for resource planning, staffing, and identifying trends in fire occurrence. It is meaningful for budgeting, trend analysis, and operational planning.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (66, 'AGC2500', 4, '% of closed fire investigations annually', 'Output', 'This measure calculates the percentage of fire investigation cases that are closed within the fiscal year, including all incidents where an investigation is formally concluded (regardless of cause determined).', 'Records Management Database: All fire investigation case files are tracked from initiation through closure in the department’s case management system. The annual percentage is calculated for all cases opened during the fiscal year.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is available live and can be aggregated monthly and annually.', '(Number of fire investigations closed during the fiscal year ÷ Total number of fire investigations initiated in the same period) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Records Management Database', 'Investigators update case status electronically. Closure is verified and logged by supervisors.', 'This measure assesses the department’s ability to resolve fire investigations in a timely manner. High closure rates reflect operational efficiency, enable more accurate fire cause statistics, and provide timely information to stakeholders (e.g., victims, law enforcement, insurers). It is meaningful as it demonstrates the effectiveness and accountability of the investigative process.', NULL, 'Not applicable; data is fully captured in the system.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (67, 'AGC2500', 4, '% of fire investigation reports completed/closed within 30 days', 'Output', 'This measure tracks the percentage of fire investigation reports that are completed and closed within 30 days of incident assignment, indicating timeliness of documentation.', 'Records Management Database: Each report’s assignment and closure dates are logged, enabling calculation of turnaround time.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data is available live and can be reported monthly and annually.', '(Number of investigation reports closed within 30 days ÷ Total number of fire investigations completed) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Records Management Database', 'Dates are automatically timestamped in the case management system when reports are opened and closed.', 'This measure is used to monitor timeliness in reporting, which supports prompt information flow to other agencies, victims, and insurers. Delays may hinder follow-up investigations, prosecution, or risk mitigation. Timely completion is meaningful as it reflects professionalism and responsiveness.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (68, 'AGC2500', 4, '% of fire investigations where causation is determined annually', 'Output', 'This measure calculates the percentage of fire investigations in which an official cause is determined (accidental, incendiary, natural, or undetermined), out of all investigations completed annually.', 'Records Management Database: Each case file documents the final determination of cause. The annual percentage is derived from all closed cases.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data available live; can be reported monthly and annually.', '(Number of investigations with a cause determined ÷ Total number of closed investigations) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Records Management Database', 'Investigators record the cause of fire as part of case closure; data is extracted by supervisory review.', 'This measure reflects investigative thoroughness and the quality of evidence collection. A higher percentage indicates the department is effectively identifying fire causes, supporting prevention efforts, policy development, and criminal prosecution as needed. It is meaningful because undetermined causes limit the ability to address underlying risks and trends.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (69, 'AGC2500', 4, '% of investigators that take 3 or more training classes annually', 'Effectiveness', 'This measure captures the percentage of fire investigators who attend at least three training classes during the fiscal year, reflecting investment in professional development.', 'Records Management Database: Records of all training sessions attended by investigators are maintained and verified.', 'Robert Hamlin', 'Deputy Chief - Fire Marshal', 'Data available live; can be reported monthly and annually.', '(Number of investigators attending 3 or more classes ÷ Total number of investigators) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Records Management Database', 'Supervisors verify and log attendance; system tracks class completion per investigator.', 'This measure ensures a highly trained workforce, helps maintain certifications, and keeps staff up to date on best practices and new investigative techniques. It is meaningful because ongoing training is linked to higher investigative quality and staff retention.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (70, 'AGC2500', 4, '% of in-service ground ladders that meet and/or exceed the National Fire Protection Association (NFPA) Standard 1932, standard use, maintenance, and service of in-service Fire Department ground ladders', 'Output', '% of in-service ground ladders that meet and/or exceed the National Fire Protection Association (NFPA) Standard 1932, Standard use, Maintenance, and Service of In-Service Fire Department Ground Ladders.', 'Ladder Inventory in Operative IQ', 'Dante P. Stewart', 'Assistant ChiefSupport Services / Community Risk Reduction', 'Live', '# of ground ladder in service that meet/exceed the minimum of the standard', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Operative IQ program.', 'Ground ladder testing is conducted annually in the fall. A Fire Supply member ensures that all ladders tested by the vendor are verified and entered into Operative IQ at the time of testing. This process creates an maint record for each ground ladder.', 'This measure informs the department’s progress in deploying integrated intelligence and information systems that support data-driven decision-making across operations, logistics, training, and administration. It is used to assess system functionality, user adoption, and the ability to collect, analyze, and act on operational data in real time. This metric is meaningful because effective IQ systems enhance situational awareness, improve coordination and accountability, and enable leadership to proactively manage risk, performance, and resource allocation.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (71, 'AGC2500', 4, '% of in-service turnout gear that meets and/or exceeds the National Fire Protection Association (NFPA) Standard 1851, standard on selection, care, and maintenance of protective ensembles for structural fire fighting and proximity fire fighting', 'Output', '% of in-service turnout gear that meets and/or Exceeds the National Fire Protection Association (NFPA) Standard 1851, Standard on Selection, Care, and Maintenance of Protective Ensembles for Structural Fire Fighting and Proximity Fire Fighting.', 'TurnOut Gear Database', 'Dante P. Stewart', 'Assistant ChiefSupport Services / Community Risk Reduction', 'Live', '# of turnout gear pieces that meet/exceed the advanced cleaning and advanced inspection minimums of the standard', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Operative IQ program', 'Turnout gear is collected weekly based on assigned shift and battalion schedules. Gear is picked up by a designated driver and transported to Fire Supply, where Fire Supply personnel verify each set of gear and the associated member. All turnout gear is t', 'This measure informs how well the department is maintaining and replacing firefighter protective ensembles to ensure they remain safe, effective, and compliant with national standards. It is used to guide gear inspection cycles, cleaning and decontamination practices, repair decisions, and replacement funding priorities. This metric is meaningful because compliant turnout gear directly protects firefighters from thermal injury, toxic exposure, and equipment failure, reduces long-term health risks, and supports operational readiness and regulatory compliance.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (72, 'AGC2500', 4, 'Number of operative IQ systems implemented', 'Output', 'Number of Operative IQ systems implemented', 'Operative IQ', 'Dante P. Stewart', 'Assistant ChiefSupport Services / Community Risk Reduction', 'Live', 'Five Logistics sections operating the Operative IQ system', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Operative IQ', 'Data is collected by tracking the implementation and active operational use of modules within the Operative IQ system across Logistics sections. Implementation is verified through system configuration, user access, and active data entry.', 'This measure informs the department’s progress in deploying integrated intelligence and information systems that support data-driven decision-making across operations, logistics, training, and administration. It is used to assess system functionality, user adoption, and the ability to collect, analyze, and act on operational data in real time. This metric is meaningful because effective IQ systems enhance situational awareness, improve coordination and accountability, and enable leadership to proactively manage risk, performance, and resource allocation.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (73, 'AGC2500', 4, '# of EMS response units dispatched and monitored annually', 'Output', '# of EMS response units dispatched and monitored annually', 'Fire Records  IT Data Based', 'Tenea Reddick', 'Director of Fire 911 and Communication and Dispatch', 'Monthly', 'Actual #', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'CAD', 'BCFD IT/Filter CAD DATA', 'This measure informs the department about overall EMS system demand, workload distribution, and resource utilization across the city. It is used to evaluate unit availability, staffing models, deployment patterns, and the frequency of simultaneous incidents that may strain response capacity. This metric is meaningful because understanding how often EMS units are dispatched helps leadership plan for adequate staffing and coverage, manage fatigue and overtime, and ensure the EMS system can reliably meet community needs without compromising response times or quality of care.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (74, 'AGC2500', 4, '# of Fire response units dispatched and monitored annually', 'Output', '# of Fire response units dispatched and monitored annually', 'Fire Records  IT Data Based', 'Tenea Reddick', 'Director of Fire 911 and Communication and Dispatch', 'Monthly', 'Actual #', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'CAD', 'BCFD IT/Filter CAD DATA', 'This measure is used to assess overall call volume, workload, and system demand across Fire and EMS operations. It informs staffing models, shift scheduling, unit availability, and long-term resource planning. This metric is meaningful because understanding response volume helps ensure the department can meet community demand without overextending personnel or compromising service levels.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (75, 'AGC2500', 4, '% of 911 calls compliant with customer QA scores', 'Output', '% of 911 calls compliant with customer QA scores', '911 QA database', 'Tenea Reddick', 'Director of Fire 911 and Communication and Dispatch', 'Weekly', '(# of 911 calls compliant with customer service QA scores / # of total 911 calls)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Aqua Software', 'Priority Dispatch QA/QI Reports', 'This measure tracks how consistently call-handling interactions meet established customer service and quality standards. It informs performance management, training enhancements, and customer-focused improvements in communication and professionalism. This metric is meaningful because positive, compliant call interactions improve caller cooperation, reduce confusion during emergencies, and reinforce public confidence in emergency services.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (76, 'AGC2500', 4, '% of calls for service processed and dispatched within one minute', 'Output', 'Retrieving data. Wait a few seconds and try to cut or copy again.', 'BCFD IT database', 'Tenea Reddick', 'Director of Fire 911 and Communication and Dispatch', 'Monthly', '(% of calls for service processed and dispatched within one minute / # of all calls for service)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CAD', 'BCFD IT/Filter CAD DATA', 'This measure informs how efficiently the communications center processes emergency information and initiates response, highlighting performance in call handling, call triage, and dispatcher workflow. It is used to identify staffing, training, or technology gaps that delay dispatch and to guide improvements in call-taking protocols and CAD usage. This metric is meaningful because faster dispatch reduces overall response times, enabling Fire and EMS units to arrive sooner and improving outcomes for time-critical emergencies.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (77, 'AGC2500', 4, '% of emergency calls answered in 10 seconds or less', 'Output', '% of emergency calls answered in 10 seconds or less', '911 database', 'Tenea Reddick', 'Director of Fire 911 and Communication and Dispatch', 'Live', '(# of emergency calls answered in 10 seconds or less / total # of emergency calls answered)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Ecats Software', 'ECats Reports/ Vesta System', 'This measure informs whether the communications center has sufficient staffing, scheduling, and technology to promptly answer incoming emergency calls. It helps identify peak demand periods, staffing gaps, and system bottlenecks. This metric is meaningful because rapid call answer times reduce caller distress, prevent call abandonment, and ensure emergencies are recognized and acted upon without delay.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (78, 'AGC2500', 4, 'Average QA score for all calls dispatched and monitored', 'Outcome', 'Average QA score for all calls dispatched and monitored', 'BCFD IT database', 'Tenea Reddick', 'Director of Fire 911 and Communication and Dispatch', 'Monthly', 'Average score', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Fire communications Share drive', 'QA Spreadsheet', 'This measure evaluates the quality and accuracy of call-taking and dispatch decisions, including adherence to protocols, information gathering, and professionalism. It informs training needs, performance coaching, and policy refinement to ensure consistent, high-quality service delivery. This metric is meaningful because accurate and compliant call handling directly affects responder safety, appropriate resource deployment, and public trust in the 911 system.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (79, 'AGC2500', 4, '# of line of duty injuries per 100 uniformed members', 'Output', 'Number of line of duty injuries per 100 sworn members based on 1583 sworn members', 'Safety Office database', 'Laura A. Shiloh, BS, NRP', 'Deputy Chief 6, Director of Education and Training', 'Live', 'Safety Office database', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'BCFD Safety Office database', 'Safety Office forwards data upon request', 'This measure informs the department’s risk management and driver safety programs by tracking preventable and non-preventable incidents involving fire apparatus and support vehicles. It helps identify needs for additional driver training, policy changes, route planning, or apparatus technology improvements. This metric is meaningful because vehicle collisions pose significant risk to firefighters and the public, result in costly repairs and downtime, and can directly impact the department’s ability to respond effectively to emergencies.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (80, 'AGC2500', 4, '# of recruits who enter the Fire Academy', 'Output', 'The number of new hires to be trained to become sworn members (EMT-Firefighter, EMT or Paramedic)', 'Fire Academy class tracking spreadsheet', 'Laura A. Shiloh, BS, NRP', 'Deputy Chief - Director of Training and Education', 'Live data as it is received from FDHR', 'Fire Academy class tracking spreadsheet', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Fire Department network - Fire Academy folder', 'Class lists received from FDHR', 'The number of new hires beginning their training gives the projected number of sworn members to reduce operational vacancies', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (81, 'AGC2500', 4, '# of training hours delivered to field members', 'Output', 'The total number of training hours delivered to current sworn members of the department', 'Fire Academy spreadsheet/Fire Records', 'Laura A. Shiloh', 'Deputy Chief - Director of Training and Education', 'Data is entered daily - available live', 'Fire Academy spreadsheet/FireRecords', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Fire Academy spreadsheet/FireRecords/BCFD Info page', 'Fire Academy Spreadsheet/FireRecords', 'Ongoing training and increased frequency reduces probability of injuries and illnesses, both physical and mental.  Also,  Insurance Services Office (ISO) ratings are affected by monthly minimum trainings, which affects community insurance costs.  BCFD currently holds the highest rating.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (82, 'AGC2500', 4, '# of vehicle collisions', 'Output', '# of vehicle collisions per year', 'Safety Office database', 'Laura A. Shiloh, BS, NRP', 'Deputy Chief 6, Director of Education and Training', 'Live', 'Actual number', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'BCFD Safety Office database', 'FD Safety Office forwards data upon request', 'This measure informs the department’s risk management and driver safety programs by tracking preventable and non-preventable incidents involving fire apparatus and support vehicles. It helps identify needs for additional driver training, policy changes, route planning, or apparatus technology improvements. This metric is meaningful because vehicle collisions pose significant risk to firefighters and the public, result in costly repairs and downtime, and can directly impact the department’s ability to respond effectively to emergencies.', NULL, 'n/a', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (83, 'AGC2500', 4, '% of recruits who graduate', 'Output', 'The number of new hires for EMT/Firefighter, EMT, or Paramedic who successfully complete all training requirements for sworn field positions.', 'Fire Academy class tracking spreadsheet', 'Laura A. Shiloh', 'Deputy Chief - Director of Training and Education', 'Live data upon completion of training and graduating from the Fire Academy', 'Fire Academy class tracking spreadsheet', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Fire Academy spreadsheet', 'Entries on spreadsheet within FA folder', 'The number of recruits who successfully complete all training requirements and transition to operational roles varies. As a result, initial hiring figures are not a reliable indicator of future staffing levels. Instead, the graduation rate provides a more accurate basis for projecting workforce capacity and forecasting the ability to fill vacancies.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (84, 'AGC2600', 4, '% of fleet preventive maintenance work requests completed in a fiscal year', 'Effectiveness', 'This KPI tracks the percentage of preventive maintenance by vehicle within the fleet management division.', 'FasterWeb', 'James Trimarco', 'Analyst', 'Yearly', '(COUNT(PMs Marked "Completed")/ COUNT(PMs Marked as "Due")) * 100', 'Increase', 74, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'FasterWeb', 'We use FasterWeb GUI, SQL-based stored procedures and documented DAX expressions for calculation.  The space here doesn''t allow for pasting.', 'Yes', 'This is to track the preventive maintenance overall and by vehicle within the fleet management division.', NULL, 'For FY27, DGS improved the methodology for this measure allowing for monthly and quarterly reporting. Replaced by % of Routine Services PMs Completed On Time and % of Public Safety PMs Completed On Time (15 Days).', 'Replaced', 5, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (85, 'AGC2600', 4, '% of total costs spent on maintenance and repair outside of regular wear and tear', 'Efficiency', 'This tracks the percentage of total costs spent on maintenance and repair that are outside of regular wear and tear.', 'FasterWeb', 'James Trimarco', 'Analyst', 'Monthly', '(SUM(Repair Charges Marked as "Abuse") / SUM(All Repairs)) * 100', 'Decrease', 4, 2025, 'Percent', NULL, 'N/A', true, 'Yes', 'Faster Web', 'We use SQL-based stored procedures and documented DAX expressions for calculation.  The space here doesn''t allow for pasting.', 'Yes', 'This is to track the percentage of total costs spent on maintenance and repair that are outside of regular wear and tear.', NULL, 'Identify the specific reports and locations for data in FasterWeb', 'Unchanged', 5, 14, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (86, 'AGC2600', 4, 'Public Safety Fleet Availability', 'Effectiveness', 'This KPI measures the percentage of Public Safety vehicles that were available for use during the fiscal period.', 'FasterWeb', 'James Trimarco', 'Analyst', 'Daily', '(COUNT(Public Safety Vehicles Available) / COUNT(All Public Safety Vehicles)) * 100', 'Increase', 86.1, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'FasterWeb', 'We use SQL-based stored procedures and documented DAX expressions for calculation.  The space here doesn''t allow for pasting.', 'Yes', 'This KPI measures the percentage of Public Safety vehicles that were available for use during the fiscal period.', NULL, 'Identify the specific reports and locations for data in FasterWeb', 'Unchanged', 1, 3, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (87, 'AGC2600', 4, 'Routine Services Availability', 'Effectiveness', 'This KPI measures the proportion of fleet vehicles designated for routine service that are operationally available.', 'FasterWeb', 'James Trimarco', 'Analyst', 'Daily', '(COUNT(Routine Services Vehicles Available)/ COUNT(All Routine Services Vehicles)) * 100', 'Increase', 82.2, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'FasterWeb', 'We use SQL-based stored procedures and documented DAX expressions for calculation.  The space here doesn''t allow for pasting.', 'Yes', 'This KPI measures the proportion of fleet vehicles designated for routine service that are operationally available.', NULL, 'Identify the specific reports and locations for data in FasterWeb', 'Unchanged', 5, 9, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (88, 'AGC2600', 4, 'Total gallons of fuel consumed (in millions)', 'Output', 'This KPI measures the total annual gallons of fuel consumed by Fleet operations, reported in millions.', 'FasterWeb', 'James Trimarco', 'Analyst', 'Daily', 'SUM(Fuel Gallons) excluding quasi-agencies and police rentals.', 'Decrease', 3.4, NULL, 'Count', 'millions of gallons', 'The data validation exercise completed doesn’t include what the data is used for. There is no indication of how the measure informs operations or why it''s meaningul.', true, 'Yes', 'FasterWeb', 'Fuel gallons consumed are viewed on FasterWeb', 'Partially', 'This KPI measures the total annual gallons of fuel consumed by Fleet operations, reported in millions.', NULL, 'Identify the specific reports and locations for data in FasterWeb', 'Removed', 5, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (89, 'AGC2600', 4, 'Energy use of City buildings (kBtu/SF)', 'Effectiveness', 'This KPI is to track the energy used by City Buildings. The metric determines the median consumption intensity.', 'Energy Management Database (EnergyCAP) and Facilities Data', 'Amy DaSilva', 'Administrative Analyst II', 'Yearly', '=(Median EUI/Degree Days) X FY21 Degree Days

EUI - Energy Use Intensity
Degree Days - Obtained by finding the mean temperature for a day/week/month and comparing it to a base value of 65. We use a static Degree Days figure from FY21 for normalization.', 'Decrease', 60, NULL, 'Count', 'kBtu/SF', 'N/A', true, 'No', 'Energy Management Database (EnergyCAP) and Facilities Data', 'Data is collected and analyzed in EnergyCAP', 'Partially', 'Measures energy use efficiency (by looking at intensity) of buildings DGS is responsible for.', NULL, 'Identify the specific reports and locations for data in EnergyCap.', 'Unchanged', 3, 10, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (90, 'AGC2600', 4, 'Grant and rebate revenue awarded', 'Outcome', 'This KPI measure represents the total dollar value of grant awards and secured rebates obtained during the fiscal period.', 'Microsoft O365', 'Amy DaSilva', 'Administrative Analyst II', 'Monthly', '=SUM(Grants received)+SUM(Rebates received)', 'Increase', 838373, NULL, 'Currency', NULL, 'N/A', true, 'No', 'Spreadsheet internal records', 'Rebates & grants are applied for, come in, and are tracked manually in an internal spreadsheet.', 'Partially', 'Measures how effectively we''re defraying energy costs with the use of grant and rebate funding.', NULL, 'For FY27, DGS improved the methodology so that reporting quarters are consistent.', 'Modified', 5, 14, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (91, 'AGC2600', 4, 'Number of City buildings benchmarked in ENERGYSTAR® Portfolio Manager', 'Output', 'This KPI tracks the total number of buildings captured in ENERGY STAR® Portfolio Manager.', 'ENERGYSTAR® Portfolio Manager', 'Amy DaSilva', 'Administrative Analyst II', 'Live', '=COUNT(Buildings benchmakred in ENERGYSTAR Portfolio Manager)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'ENERGYSTAR® Portfolio Manager', 'Viewable in ENERGYSTAR Portfolio Manager', 'Measuring how many buildings we''ve benchmarked in Energystar Portfolio, which was a previous data validation effort of DGS.', NULL, 'We would like to transition this measure to "% of BEPS Buildings Benchmarked in ENERGYSTAR Portfolio Manager," as described in Measure Improvement.', 'Identify the specific reports and locations for data in ENERGYSTAR.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (92, 'AGC2600', 4, 'Percentage of City government electricity usage from renewable sources', 'Outcome', 'This KPI tracks the percentage of city government electricity usage from renewable sources.', 'Energy Cap', 'Amy DaSilva', 'Administrative Analyst II', 'Yearly', '(Electricity use of BRCPC portfolio (kWh) x % covered by RECs + Electricity generated by renewable production) / Total electricity use', 'Increase', 18, NULL, 'Percent', NULL, 'The Baltimore Regional Cooperative Purchasing Committee (BRCPC) plays an important role in the energy procurement strategy.', true, 'No', 'Annual Baltimore Regional Cooperative Purchasing Committee (BRCPC) report on usage, Bi-monthly Enel X report on Renewable Energy Credit(REC) purchases, renewable project databases', 'Development of this measure includes the annual BRCPC report on usage and regular reports on purchases.', 'Yes', 'This measures either how well we''re implementing renewable energy, or whether or not we''re in compliance with relevant requirements.', NULL, 'Identify the specific reports and locations for data in EnergyCap.', 'Unchanged', 3, 10, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (93, 'AGC2600', 4, '% of corrective work request completed on time', 'Effectiveness', 'This KPI tracks what percentage of corrective maintenance is completed on time.', 'Archibus', 'Happy Iguare', 'Operations Research Analyst', 'Daily', '(Count of Corrective Maintenance Workorders Completed within SLA / Count of All Corrective Maintenance Workorders) * 100', 'Increase', 37, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'Archibus', 'Maintenance requests are viewable in Archibus, data is exported to a SQL database and analyzed from there.', 'Yes', 'Measures how quickly we''re completing CMs, and how well we''re adhering to our estimated completion time.', NULL, 'For FY27 DGS improved this KPI, changing the methodology, to ensure that performance reporting accurately reflects when work is actually completed.', 'Modified', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (94, 'AGC2600', 4, '% of elevator cars available per quarter', 'Effectiveness', 'This KPI tracks the percentage of elevators that are available during a given period.', 'Archibus', 'Happy Iguare', 'Operations Research Analyst', 'Quarterly', '(Count of Elevators marked "Available" / Count of All Elevators) * 100', 'Increase', 90, NULL, 'Percent', NULL, 'N/A', true, 'No', 'Archibus', 'Elevator status is viewable in Archibus, data is exported to a SQL database and analyzed from there.', 'Yes', 'This KPI helps in measuring how effective we are at keeping elevator cars available across the city.', 'Elevator Measure Improvement Pilot', 'A crossfunctional DGS team has made progress on the development and implementation of a new measure pilot.', 'Unchanged', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (95, 'AGC2600', 4, '% of grass mowing service completed on time', 'Effectiveness', 'This KPI tracks what percentage of lawn mowing work is done on time.', 'Archibus', 'Happy Iguare', 'Operations Research Analyst', 'Daily', '(Count of Lawn PMs Completed On Time / Count of All Lawn PMs) * 100', 'Increase', 98, NULL, 'Percent', NULL, 'Lawns are scheduled on a 2-week rotation April-November each year. The SLA from the request date is 14 days before a mowing is considered overdue.', true, 'No', 'CleanStat', 'Maintenance requests are viewable in Archibus, data is exported to a SQL database and analyzed from there.', 'Partially', 'This KPI tracks what percentage of lawn mowing work is done on time.', NULL, 'This measure is replaced in FY27 with the % Routine Maintenance Completed On Time.', 'Removed', 3, 9, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (96, 'AGC2600', 4, '% of preventive maintenance completed on time', 'Effectiveness', 'This KPI tracks the preventive maintenance work orders that are completed on time. Preventative maintenance completion is a leading indicator of asset reliability and operational discipline.', 'Archibus', 'Happy Iguare', 'Operations Research Analyst', 'Daily', '(Count of Preventative Maintenance Work Requests Completed w/in SLA / Count of All Preventative Maintenance Work Orders) * 100', 'Increase', 95, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'Archibus', 'Maintenance requests are viewable in Archibus, data is exported to a SQL database and analyzed from there.', 'Yes', 'Directly reduces unplanned downtime, extends equipment life, and catches costly repairs sooner.', NULL, 'For FY27 DGS improved this KPI to align with the JLL-recommended SLA framework and to support monitoring of the planned preventative maintenance program expansion.', 'Modified', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (97, 'AGC2600', 4, '% of construction projects that are completed on time', 'Effectiveness', 'This KPI measures the percentage of capital construction projects completed on or before their scheduled completion dates.', 'Microsoft O365', 'Happy Iguare', 'Engineer', 'Monthly', '(Count of Construction Projects Completed On Time / Count of Construction Projects) * 100', 'Increase', 100, 2025, 'Percent', NULL, 'N/A', true, 'Yes', 'Project Stat Spreadsheet', 'Relevant data is managed in an internal spreadsheet with inputs coordinated with project managers and project meetings.', 'Yes', 'Reflects the division''s ability to manage schedules effectively and deliver projects as planned.', NULL, 'N/A', 'Unchanged', 6, 19, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (98, 'AGC2600', 4, '% of construction projects that are within 10% of the accepted bid value', 'Effectiveness', 'This KPI measures the percentage of construction projects completed within 10% of their accepted bid value.', 'Microsoft O365', 'Happy Iguare', 'Engineer II', 'Monthly', '(Count of Construction Projects Within 10% / Count of Construction Projects) * 100', 'Increase', 50, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'Project Stat Spreadsheet', 'This measure is tracked manually.', 'Partially', 'Reflects cost management effectiveness and how closely final costs align with original estimates.', NULL, 'N/A', 'Unchanged', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (99, 'AGC2600', 4, '% of construction projects that meet or exceed the Original Minority Business Enterprise goals', 'Outcome', 'This KPI measures the percentage of construction projects that met or exceeded the Minority Business Enterprise (MBE) participation goals established.', 'Microsoft O365', 'Happy Iguare', 'Engineer II', 'Monthly', '(Count of Construction Projects Meeting MBE Goal / Count of Construction Projects) * 100', 'Increase', 100, NULL, 'Percent', NULL, 'Each project must be searched individually on the website: baltimorecity.diversitycompliance.com', true, 'No', 'Project Stat Spreadsheet', 'This measure is tracked manually.', 'Yes', 'Reflects effectiveness in achieving equity participation objectives and compliance with contract requirements.', NULL, 'N/A', 'Unchanged', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (100, 'AGC2600', 4, '% of construction projects that meet or exceed the Original Women Business Enterprise goals', 'Outcome', 'This KPI measures the percentage of construction projects that met or exceeded the Women Business Enterprise (WBE) participation goals established.', 'Microsoft O365', 'Happy Iguare', 'Engineer II', 'Monthly', '(Count of Construction Projects Meeting WBE Goal / Count of Construction Projects) * 100', 'Increase', 100, NULL, 'Percent', NULL, 'Each project must be searched individually on the website: baltimorecity.diversitycompliance.com', true, 'No', 'Project Stat Spreadsheet', 'This measure is tracked manually.', 'Partially', 'Reflects effectiveness in achieving equity participation objectives and compliance with contract requirements.', NULL, 'SOURCE DATA FLAG: agency-submitted formula reads ''* 101'' instead of ''* 100'' — likely a typo in the original submission. Confirm with DGS before using in the portal.', 'Unchanged', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (101, 'AGC2600', 4, '% of customer satisfaction', 'Outcome', 'This metric tracks customer satisfaction based on surveys administered by the Capital Division during the design and construction phases of Capital projects, evaluating quality of service, engagement, frequency of updates, responsiveness, and issue resolution.', 'Microsoft O365', 'Happy Iguare', 'Engineer', 'Quarterly', '(SUM(Survey Values)/COUNT(Survey Questions))*100', 'Increase', 100, NULL, 'Percent', NULL, 'N/A', true, 'No', 'Microsoft Forms', 'Microsoft Forms data is exported to Excel.', 'Yes', 'Tracks customer satisfaction across multiple service dimensions during design and construction.', NULL, 'N/A', 'Unchanged', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (102, 'AGC2600', 4, '% of design projects that are completed on time', 'Effectiveness', 'This KPI measures the percentage of DGS managed capital design projects completed on or before their scheduled completion dates.', 'Microsoft O365', 'Happy Iguare', 'Engineer', 'Monthly', '(COUNT(Design Projects Completed On Time in the Period) / COUNT(All Design Projects for the Period)) * 100', 'Increase', 90, NULL, 'Percent', NULL, 'N/A', true, 'Yes', 'Project Stat Spreadsheet', 'Relevant data is managed in an internal spreadsheet with inputs coordinated with project managers and project meetings.', 'Yes', 'Provides insight into the division''s ability to manage design timelines effectively and ensure projects progress toward construction.', NULL, 'N/A', 'Unchanged', 6, 19, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (103, 'AGC2700', 4, '# of client visits for STI services', 'Output', 'Number of client visits for STI services. These include Office visits, Appointments, walkins and medication management,', 'OCHIN EPIC EMR', 'Paris Johnson and Alexis glasgow', 'Epidemiologist and clinic operations director', 'Weekly', 'EMR', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, NULL, 'OCHIN EPIC', 'Regstration and clinical intake forms', NULL, 'Not applicable', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (104, 'AGC2700', 4, '# of dental visits', 'Output', 'Number of dental visits (includes new, repeating patients) for preventative services, emergency and appointments.', 'OCHIN EPIC and excel tracking', 'Patricia Bell-Mcduffie', 'Director Oral health services', 'Monthly', 'Number of dental visits during the specified time period.', 'Increase', NULL, NULL, 'Count', NULL, 'How is the excel sheet updated?', true, NULL, NULL, 'OCHIN EPIC', 'Dental intake form and registration', NULL, 'Not applicable', 'Use of an automated report stemming from EPIC rather than an excel sheet', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (105, 'AGC2700', 4, '% of actively infected TB patients who are receiving anti-tubercular medications', 'Outcome', 'Percent of active TB cases starting on TB medication.', 'OCHIN EPIC, NEDSS', 'Siobain Fisher', 'TB Program manager', 'Daily', 'Number of active TB cases started on TB medication/Number of active TB cases reported and identified.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'OCHIN EPIC, NEDSS, Shared drive', 'Referrals to the Health department from Hospitals/Clinics. Or initiate from NEDSS based on Micro results', NULL, 'Not applicable', 'Consolidation of data sources into one source of truth', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (106, 'AGC2700', 4, '% of contact investigations initiated for eligible active TB cases', 'Outcome', 'Percent of contacts of active TB cases initiated for investigations. It is necessary to identify and test all contacts of active TB cases to curb the spread of disease', 'Case Investigation Records (BCHD)', 'Siobain Fischer', 'TB Program manager', 'Monthly', 'Case Investigation Records (BCHD)', 'Increase', NULL, NULL, 'Percent', NULL, 'Does initiation of an investigation depend on an external factor (i.e. TB patients reporting contact)?', true, NULL, NULL, 'OCHIN EPIC', 'Number of contact investigations inputed in OCHIN and are linked to active TB cases', NULL, 'Not applicable', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (107, 'AGC2700', 4, '% of out of care persons with HIV linked to ongoing healthcare', 'Outcome', 'Number of out of care individuals encountered in the clinic and of those percent successfully linked to ongoing care.', 'OCHIN EPIC and HIV care enrollment tracking at SWHC', 'Tyree J. Bolden', 'Social Services Manager', 'Monthly', 'Number of out of care patients linked to ongoing care/number of out of care patients encountered during the time period.', 'Increase', NULL, NULL, 'Percent', NULL, 'Are instances of patients receiving treatment at care centers outside of the city''s clinic system captured?', true, NULL, NULL, 'OCHIN EPIC', 'Intake form/Registration into Linkage to care program', NULL, 'Not applicable', 'Continue development of automated report as mentioned', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (108, 'AGC2700', 4, '# of homes assessed for health and safety risks', 'Output', 'Number of homes that received an environmental or case management home visit', 'STELLAR and HHLPSS', 'Brionna Adams', 'Director, Childhood Lead Poisoning Prevention Program', 'Monthly', 'Straight count deduplicated', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'STELLAR and HHLPSS', 'Data collected as part of program sites visits following reports of EBLS', NULL, 'N/A', 'More granular detail on data source', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
