    (110, 'AGC2700', 4, '% of children with reduced asthma-related ED visits at the 3rd home visit', 'Outcome', 'Improvement in home triggers of asthma to achieve a reduction in ED visits', 'REDCap', 'Willietta Gombeh', 'Director, Community Asthma Program', 'Monthly', '# children with reduced asthma-related ED visits/ # children participating in the program', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'RedCap', 'Data is reviewed in the RedCap system as part of case management activities.', NULL, 'N/A', 'More granular detail on data source', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (111, 'AGC2700', 4, '# of individuals trained in Naloxone administration by the Baltimore City Health Department', 'Output', 'The number of individuals within Baltimore City that participate in overdose response training directly through BCHD', 'Training Rosters, individual participant forms', 'Rania Mohamed', 'OEND Administrator', 'Weekly, Monthly, Quarterly, and Annually', 'Count', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Hard Copies filed away within DPBH. Also maintained within an agency electronic tracking document.', 'Hard Copy', NULL, 'N/A', 'More granular detail on data source', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (112, 'AGC2700', 4, '# of naloxone kits distributed by the Baltimore City Health Department', 'Output', 'The number of overdose kits distributed through OEND outreach activities.', 'Training rosters, participant forms, reversal reporting forms.', 'Rania Mohamed', 'OEND Administrator', 'Monthly, Quarterly, and Annually', 'Count', 'Increase', NULL, NULL, 'Count', NULL, 'Has there been any discussion of digitizing the collection process?', false, NULL, NULL, 'Files within the Division of Public Behavioral Health', 'Hard Copy forms', NULL, 'N/A', 'Clear instructions on how to access files', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (113, 'AGC2700', 4, '# of needles exchanged', 'Output', 'This measures the number of syringes distributed by the BCHD Opioid-Associated Disease Prevention and Outreach Program', 'EMR', 'Jeffrey Long', 'Director of Community Risk Reduction Services', 'Monthly, Quarterly, Annually', 'EMR', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Ochin Epic', 'Count', NULL, 'N/A', 'More granular detail on data source', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (114, 'AGC2700', 4, '# of new Baltimore City Health Department buprenorphine patients', 'Output', 'Number of new BCHD patients prescribed buprenorphine between July 1 and September 30, 2025', 'OCHIN/Epic electronic medical record system (EMR)', 'Kay Webster', 'Director of Administration, Division of Public Behavioral Health', 'Monthly', 'N/A', 'Increase', NULL, NULL, 'Count', NULL, 'Clarity on the stated date range in the description', false, NULL, NULL, 'OCHIN/Epic EMR - Queries and data are largely kept on SQL server reporting services. If needed, limited de-identified data can be pulled into Sharepoint.', 'Data pull from OCHIN/Epic EMR', NULL, 'N/A - data can be collected monthly', 'Clear data pull instructions', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (115, 'AGC2700', 4, '# students who engage in substance use services in participating schools where substance use services are offered', 'Output', 'Total number of Baltimore City Public School students engaged with substance use services in participating schools between 7/01/2025 - 9/30/2025', '1. Quarterly YTD totals provided by sub-vendors 
2. Unduplicated student count comes from the following categories of interaction: 
a. Teacher/Classroom consultations 
b. Prevention Group Services 
c. Individual services 
3. Students engaging in any of the above services are counted once per fiscal year as an unduplicated student', 'Kay Webster', 'Director of Administration, Division of Public Behavioral Health', 'Quarterly', 'N/A - measure is a count', 'Increase', NULL, NULL, 'Count', NULL, 'Clarity on the stated date range in the description', false, NULL, NULL, 'BHSB Contract Managing System (CMS)', 'Providers report on a quarterly basis, with reports due 15 days following the end of the previous quarter', NULL, 'N/A', 'Clear report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (116, 'AGC2700', 4, '% 988 calls answered by Baltimore City''s call center versus calls sent to a backup call center', 'Efficiency', 'Number of 988 Helpline calls answered directly by the regional call center, rather than being sent to the backup call center', 'Vibrant Emotional Health (national manager of 988)', 'Kay Webster', 'Director of Administration, Division of Public Behavioral Health', 'Monthly', 'number of calls answered by the regional call center / total number of calls routed to the center', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, NULL, 'Maryland Department of Health has access to Vibrant Emotional Health’s records', 'Vibrant Emotional Health collects data on calls that are routed to our local 988 call center that are answered by the local call center. Behavioral Health System Baltimore does not collect this data directly. Rather, MDH compiles and distributes it in a monthly email report. [Please note: specific Desired Outcome is to maintain a 90% answer rate, which is the national and state target.]', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (117, 'AGC2700', 4, '# of reproductive health service clients served by City clinics', 'Output', 'Number of unique reproductive health service clients being served at all BCHD-Title X funded clinics in Baltimore City.', 'AHLERS database', 'Jana Goins & Ashley Cunningham', 'BCHD-Epidemiologist & BCHD-ARH Director', 'Monthly', 'This data can be pulled from AHLERS using the reporting function, based on period of interest.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'AHLERS database and EPIC EMR', 'This is collected at time of service and submitted into the local EMR (EPIC). EPIC transmits data into AHLERS on a monthly basis.', NULL, 'Not needed', 'Clear report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (118, 'AGC2700', 4, '# of unduplicated families that receive case management services by professional home visitors', 'Output', 'Number of unduplicated families that are receiving home visiting services from the Nurse Family Partnership program in Baltimore City', 'FLO Database', 'Jana Goins & Shonette Boone', 'BCHD- Epidemiologist & BCHD-Home Visiting Nurse Manager', 'Monthly', 'Data is pulled manually from FLO database by the home visiting program admin team.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'FLO Database (national database)', 'This information is documented by Nurse Family Partnership Home Visitors in FLO for service coordination and provision.', NULL, 'Not needed', 'Clear report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (119, 'AGC2700', 4, '% of children receiving home visiting services that have a completed social/emotional development screening at recommended intervals', 'Efficiency', 'Percent of home visiting clients who are being screened for social emotional development at recommended intervals of 6,12,18 and 24 months of age', 'FLO Database', 'Jana Goins and Shonette Boone', 'BCHD-Epidemiologist & NFP Homevisiting Nurse Manager', 'Monthly', 'Manual Data Pull from FLO database by the NFP home visiting program', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'FLO Database (national database)', 'Home visitors collect this information at time of client screening', NULL, 'Not needed', 'Clear report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (120, 'AGC2700', 4, '# of visits to school health suites', 'Output', 'The data encompasses all school services provided in the school health suites during the period, including acute visits, well child visits, mental health visits, medication administration, skilled nursing visits, and hearing and vision screening.', 'Monthly Report', 'Francine Childs', 'Assistant Commissioner, Bureau of School Health.', 'Monthly', 'Total number of visits for services to include acute illness, injury +visits for mental health + well child  visits + medication administration adminstration+skilled nursing visits', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'The data is stored in a shared electronic file.', 'Data is collected daily at the health suite and entered into an electronic file', NULL, 'N/A', 'Clarify database and report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (121, 'AGC2700', 4, '% of obese students seen in School-Based Health Centers who have received individual nutrition education', 'Effectiveness', 'This indicator reflects the proportion of obese or overweight students based on Body Mass Index who are seen in School-Based Health Centers (denominator) who received individualized nutrition education (numerator) during the reporting period. It highlights the SBHC’s role in addressing obesity through preventive counseling and health education, which are key components of chronic disease prevention and health promotion in school-aged populations.', 'SBHC Encounter Report', 'Francine Childs', 'Assistant Commissioner, Bureau of School Health', 'Monthly', 'All students who are diagnosed at any time during the school year with obesity or overweight or obesity divided by the number of those who are provided with individualized nutrition education.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Encounters Database located in the school health shared drive. Data source will change to OCHIN EPIC in February 2026', 'BMI and the nutrition and education services provided are collected via the SBHC data collection form encounter and SBHC staff enter data into an eectronic file. Once OCHIN Epic is fully operational data will be entered directly there.', NULL, 'N/A', 'Clarify report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (122, 'AGC2700', 4, '% of students who return to class after health suite visit', 'Outcome', 'The return to class rate reflects the percentage of students who were managed by health suite staff for acute illness, injury, or acute symptoms related to chronic conditions (denominator), and were safely able to return to class the same day (numerator).', 'Monthly Report', 'Francine Childs', 'Assistant Commissioner, Bureau of School Health', 'Monthly', 'Number of  student visits divided by the number of students who returned to class', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Database located in the school health shared drive  (Shared electronic file)', 'Data is collected daily at the health suite and entered into an electronic file.', NULL, 'N/A', 'Clarify database and report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (123, 'AGC2700', 4, '# of Adult Evaluation and Review Service (AERS) assessments performed', 'Output', 'AERS assessments provide assistance to older adults and individuals with disabilities. The AERS conducts comprehensive evaluations to identify available community resources to help individuals remain in the least restrictive environment, with as much independence as possible.', 'LTSS (Long Term Services and Support System)', 'Kelleigh Eastman', 'Assistant Commissioner, Home and Community Based Services', 'Weekly', 'LTSS (Long Term Services and Support System)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Maryland Department of Health Office of Long Term Supports and Services client management system', 'Direct service delivery personnel data entry', NULL, NULL, 'Clarify report name and calculation formula', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (124, 'AGC2700', 4, '# of Community Personal Assistance Services (CPAS) nurse monitoring visits conducted', 'Output', 'Nurse Monitor (NM) visits provide assistance to older adults and individuals with disabilities. NMs conduct level of care evaluations to determine if the plan of care is appropriate for the older adult or disabled client receiving Personal Assistance Services to help individuals remain in the least restrictive environment, with as much independence as possible.', 'LTSS (Long Term Services and Support System)', 'Kelleigh Eastman', 'Assistant Commissioner, Home and Community Based Services', 'Weekly', 'LTSS (Long Term Services and Support System)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Maryland Department of Health Office of Long Term Supports and Services client management system', 'Direct service delivery personnel data entry', NULL, NULL, 'Clarify report within LTSS and any parameters/filters needed', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (125, 'AGC2700', 4, '# of support planning hours', 'Output', 'The Community Options Waiver, also as known as the Home and Community-Based Options Waiver (HCBOW), is a home and community-based services waiver. The program assists constituents with accessing home and community services and supports and avoiding institutionalization. Supports Planners deliver comprehensive person centered and self-directed case management to older adults and individuals with disabilities.', 'Maryland Department of Health Office of Long Term Supports and Services client management system.', 'Kelleigh Eastman', 'Assistant Commissioner for Home and Community Based Services', 'Weekly', 'LTSS (Long Term Services and Support System)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Maryland Department of Health Office of Long Term Supports and Services client management system', 'Direct service delivery personnel data entry', NULL, NULL, 'Clarify report within LTSS and any parameters/filters needed', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (126, 'AGC2700', 4, '# of investigated outbreaks', 'Output', 'The Health Department monitors outbreaks of infectious diseases, which are reportable to the local health department and the Maryland Dept of Health.', 'Outbreak Investigation records', 'Lanisha Childs', 'Assistant Commissioner', 'Data can be querried weekly, monthly and annually.', 'Outbreak Investigation records', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Baltimore City Health Department program sharepoint', 'The Health Dept identifies outbreaks from various mechanism: reports from a healthcare provider or entity (hospital, nursing home, school, childcare program), detection using surveillance data, or from other public health agencies. The number of outbreaks are accounted in internal databases.', NULL, NULL, 'Clarify report name/location within sharepoint', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (127, 'AGC2700', 4, '% of outbreaks with a confirmed etiology', 'Outcome', 'The measure collects data that shows whether outbreaks that are reported to the health department have an identified etiology (cause of illnesses). With knowing the cause of the outbreak, we are able to provide control and prevention guidance to the community and to health care providers.', 'Outbreak investigtion records', 'Lanisha Childs', 'Assistant Commissioner', 'Monthly and annually', 'Outbreak investigtion records', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Baltimore City Health Department internal database', 'Outbreak investigators collect information from health care providers, hospital and clinical and public health laboratories of lab test results from cases associated with the outbreak.', NULL, NULL, 'Clarify database, report, and calculation formula', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (128, 'AGC2700', 4, '# of agency, organizational and program staff trained on Trauma Informed Care', 'Output', 'Number of agency and organizational staff who participated and completed training.', 'REDCap', 'Aisha Burgess', 'Director', 'Monthly', 'Count on the number of staff participating in trainings', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'REDCap', 'Post survey', NULL, NULL, 'Clarify report and parameters', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (129, 'AGC2700', 4, '# of individuals reached through suicide prevention awareness', 'Output', 'number of individuals participating in suicide prevention awareness training', 'Post surveys', 'Aisha Burgess', 'Director, Office of Youth Trauma Services', 'Live', 'Straight count of number of individuals participating', 'Increase', NULL, NULL, 'Count', NULL, 'Is this data collected by BCHD or an external organization?', false, NULL, NULL, 'Program files', 'Post surveys', NULL, NULL, 'State specific database', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (130, 'AGC2700', 4, '# of victims served', 'Output', 'Straight count of number of clients served', 'Intake assessment forms', 'Aisha Burgess', 'Director, Office of Youth Trauma Services', 'Ongoing when program was operating. Program ended in September 2025.', 'Straight count of number of clients served', 'Increase', NULL, NULL, 'Count', NULL, 'Is this program being replaced/moved?', false, NULL, NULL, 'Program files', 'Intake assessment forms', NULL, NULL, 'Replace metric now that program has ended', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (131, 'AGC2700', 4, '% of trainees reporting satisfaction with training', 'Outcome', 'Satisfaction', 'evaluation survey', 'Aisha Burgess', 'Director, Office of Youth Trauma Services', 'Monthly', 'Survey questions measure satisfaction using a 5 point likert scale. # of trainees reporting 3 or greater/total trained x 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, NULL, 'Qualtrics survey used by Training Partner at UMD', 'Post survey', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (132, 'AGC2700', 4, '% reporting increased knowledge and how to apply key concepts from the training to practice', 'Outcome', 'Knowledge gained and application of key concepts in practice', 'evaluation survey', 'Aisha Burgess', 'Director', 'Monthly', 'Annual analyses of 2 cross-sectional samples of each organization (baseline and post completion of training). # of trainees reporting 1 or greater / total trained x 100 (5 point-likert scale)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, NULL, 'Qualtrics', 'Post survey', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (133, 'AGC2700', 4, '# of dog and cats entering shelter', 'Effectiveness', 'The amount of dogs and cats entering the shelter.', 'Pet Point', 'Sharon Colburn or Jennifer Brause', 'Director', 'Monthly', 'Total number of cats and dogs entering shelter', 'Decrease', NULL, NULL, 'Count', NULL, 'Metric seems like an output measure initially, interested in justification for effectiviness metric', false, NULL, NULL, 'Pet Point', 'Pulling stats from PetPoint', NULL, 'N/A', 'Clarify report name within petpoint', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (134, 'AGC2700', 4, '% High priority complaints closed on time', 'Output', 'The closure rate of top priority service calls', 'Salesforce', 'Sharon Colburn', 'Director', 'Monthly', 'Number of calls closed on time divided by total calls', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Salesforce', '311 Stats - run report', NULL, 'N/A', 'Would recommend changing metric to an effectiveness type', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (135, 'AGC2700', 4, 'Live release rate', 'Outcome', 'The number of animals that were either adopted, sent to rescue or returned to owner (positive outcome).', 'Pet Point', 'Sharon Colburn or Jennifer Brause', 'Director', 'Monthly', 'Live outcomes divided by all outcomes minus unhealthy/untreatable', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Pet Point', 'Pulling stats from Petpoint', NULL, 'N/A', 'Clarify report name within petpoint', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (136, 'AGC2700', 4, '# of inspections of food service facilities', 'Output', 'Total number of inspections conducted of food facilities including all complaints, routine and outbreak inspections.', 'Jadian & inspector daily location sheets', 'Jessica Speaker', 'Asst. Commissioner Environmental Health', 'monthly', 'Add all food facility inspections completed', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, NULL, 'Jadian and Food Supervisors collection of daily location sheets', 'Jadian- Food stats tab
Daily location sheets - tally of daily inspections per inspector', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (137, 'AGC2700', 4, '% of complaints closed on time', 'Outcome', 'The percentage of all Food and Ecology complaints closed on time', 'Salesforce (311)', 'Jessica Speaker', 'Asst. Commissioner Environmental Health', 'Daily', 'Number of calls closed on time divided by total calls', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Salesforce', '311 Stats - run statistical report', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (138, 'AGC2700', 4, 'Average # of days to receive a final plan review after request', 'Efficiency', 'Average number of days to recieve a plan review inspection once the facility applies and requests the inspection.', 'New Plan Review Calendar & Inspector''s daily location sheet', 'Jessica Speaker', 'Asst. Commissioner Environmental Health', 'Monthly', 'Date of scheduled inspection minus date of application = # of business days to recieve an inspection; Average is done by total days for inspection divided by total number of working days for the month.', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'New Plan Review Calendar & inspectors daily location sheet', 'Compare date of application to date of Plan review scheduled inspection', NULL, 'N/A', 'Consolidate data sources into single report', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (139, 'AGC2700', 4, '# of tobacco outlets checked for compliance with Baltimore City Health Code - Unlawful Distribution', 'Output', 'This measures the number of Baltimore City tobacco retailers that received compliance check. The compliance check occurs when a Tobacco program enforcement officer observes whether a retailer will sell to an individual under the age of 21.', 'Excel spreadsheet', 'Brianne Gilkes', 'Chronic Disease Prevention Director', 'Weekly', 'Spreadsheet', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'OneDrive, Excel spreadsheet', 'Each visit to a tobacco retailer to ensure compliance is counted in this measure.', NULL, NULL, 'Clarify report location/creation of automated report outside of excel', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (140, 'AGC2700', 4, '# of unique virtual supermarket clients per fiscal year', 'Output', 'This measures the number of clients who are using the Virtual Supermarket Program to order groceries online for the first time this fiscal year. If they ordered in a prior month in the same fiscal year, they are not counted as a unique client the next time they order.', 'Data Log, Excel spreadsheet', 'Brianne Gilkes', 'Chronic Disease Prevention Director', 'Monthly', 'Excel spreadsheet', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Microsoft Excel spreadsheet (OneDrive)', 'Order information is collected via order sheets each time the program is utilized by a client to order groceries online with the assistance of Virtual Supermarket team. That information is then added to an Excel spreadsheet.', NULL, 'This data is captured monthly.', 'Clarify report location/creation of automated report outside of excel', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (141, 'AGC2700', 4, '# of HIV tests performed through community outreach', 'Output', 'Number of HIV tests conducted by Syph elimination outreach', 'OCHIN EPIC', 'Augusto Frisancho', 'Outreach supervisor', 'Monthly', 'Number of HIV tests conducted by Syph elim outreach team. Previously this measure included CBO and FQHC testing numbers. The target may need to be revised.', 'Increase', NULL, NULL, 'Count', NULL, 'Clarify CBO and FQHC testing vs standard HIV tests, when these tests stopped being included in the count, and whether the target needs to be changed', false, NULL, NULL, 'OCHIN EPIC', 'Intake forms and on field data entry', NULL, 'Not applicable', 'Clarify report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (142, 'AGC2700', 4, '% clients achieving undetectable viral load', 'Outcome', 'Percentage of HIV-positive clients in care at BCHD clinics who achieve viral suppression (viral load <200 copies/mL).', 'CareWare', 'Stephon Effinger', 'Ryan White Careware administrator', 'Quarterly', 'Number of clients achieving viral suppression/Number of positive clients in care at the SHWC. The measure should be updated to say suppressed viral load, as that is more accurate metric', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'Careware', 'CAREWare data extraction; viral load lab results linked to client records', NULL, 'Not applicable', 'Clarify report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (143, 'AGC2700', 4, '% of newly diagnosed HIV patients who were interviewed for Partner Services', 'Efficiency', 'Percent of newly diagnosed HIV patients interviewed for partner services', 'NBS', 'Ebony Martin', 'DIS Supervisor - Public Health Representative III', 'Monthly with a data lag of a month', 'Number of newly diagnosed HIV patients interviewed for partner services/Number of newly diagnosed HIV patients', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'NBS', 'Partner services interview records in NBS', NULL, 'Not applicable', 'Clarify report name, would recommend changing to effectiveness type metric', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (144, 'AGC2700', 4, '# of times information and assistance were provided', 'Output', 'A service that: provides individuals with information on services available within the communities; links individuals to the services and opportunities that are available within the communities', 'OAAPS (BCHD/Aging)', 'Alice Huang', 'Assistant Commissioner', 'Quarterly', 'every one-on-one contact made to provide information and assistance', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Spreadsheets', 'Tracking log and quarterly reports', NULL, 'N/A', 'Clarify report name and any needed parameters/filters', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (145, 'AGC2700', 4, 'Total count of attendance in education programming', 'Output', 'Services designed to educate and provide support to older adults and providers in regards to health and in support of self-advocacy services', 'OAAPS (BCHD/Aging)', 'Alice Huang', 'Assistant Commissioner', 'quarterly', '# of participants at each education program', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Spreadsheets', 'Sign in sheet numbers transferred to data reports', NULL, 'N/A', 'Clarify report name and any needed parameters/filters, would recommend changing to outcome metric type', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (146, 'AGC2700', 4, 'Total count of attendance in recreation programming', 'Output', 'Services provide social and recreational activities in a supervised, protective, congregate setting during some portion of a day. Group activities are designed to promote the health and well-being of the whole person', 'OAAPS (BCHD/Aging)', 'Alice Huang', 'Assistant Commissioner', 'Quarterly', '# of participants at each recreation program', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Spreadsheets', 'Sign in sheet numbers transferred to data reports', NULL, 'N/A', 'Clarify report name and any needed parameters/filters, would recommend changing to outcome metric type', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (147, 'AGC2700', 4, '# of calls processed by Maryland Access Point', 'Output', 'Division of Aging and Community Support Maryland Access Point information and referral specialist field calls and assess constituents'' needs to identify resources and direct the caller with long-term and complex needs to options counseling.', 'Mitel System daily call reports', 'Chrystle Samuels', 'Director of Constituent Services', 'Weekly', 'Mitel System daily call reports', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Division of Aging and Community Support Maryland Access Point (MAP) use a tracking tools to store data.', 'Division of Aging and Community Support MAP services capture the date in call logs.', NULL, NULL, 'Clarify specific Mitel report', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (148, 'AGC2700', 4, '# of complaints closed by Long Term Care Ombudsman', 'Outcome', 'The Long-Term Care Ombudsman Program advocates for the health, safety, well-being, and rights of residents in assisted living and nursing homes. Ombudsmen work at the direction of the resident and only take action with the resident''s consent. Ombudsman services are resident-directed, confidential and provided free of charge.', 'National Ombudsman Reporting System (NORS)', 'Byron Pugh', 'Deputy Commissioner', 'Weekly', 'National Ombudsman Reporting System (NORS)', 'Increase', NULL, NULL, 'Count', NULL, 'What are the requirements for a complaint to be closed?', false, NULL, NULL, 'National Ombudsman Reporting System (NORS)', 'Ombudsman complaint closure files maintained by the Baltimore City Ombudsman Office.', NULL, NULL, 'Clarify specific NORS report, recommend changing to Output metric type', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (149, 'AGC2700', 4, '# of State Health Insurance Assistance Program (SHIP) Medicare benefits counseling sessions', 'Output', 'SHIP provides free unbiased help to Medicare-eligible beneficiaries, their families, and caregivers. SHIP reviews Medicare plan options and how to use Medicare, Trained staff and volunteer counselors are available for one-on-one assistance and community education that can help secure the right coverage.', 'SHIP Tracking and Reporting System (STARS)', 'Chrystle Samuels', 'Director of Consituent Services', 'Monthly', 'SHIP Tracking and Reporting System (STARS)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'SHIP Tracking and Reporting System (STARS)', 'Direct service delivery personnel data entry', NULL, NULL, 'Clarify report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (150, 'AGC2700', 4, '# of volunteers enrolled in Retired Senior Volunteer Program (RSVP)', 'Output', 'RSVP (the Retired and Senior Volunteer Program) is part of Senior Corps, a network of national service programs that provides older Americans the opportunity to apply their life experience to meeting community needs. RSVP volunteers serve in a diverse range of nonprofit organizations, public agencies, and faith-based groups. Among other activities, they mentor at-risk youth, organize programs, teach, and lend their business skills to community groups that provide critical social services.', 'Americorps Reporting System', 'Chrystle Samuels', 'Director of Constituent Services', 'Monthly', 'Americorps Reporting System', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Americorps Reporting System', 'Program Manangement Team enrollment information.', NULL, NULL, 'Clarify report name', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (151, 'AGC2700', 4, '# of new adult guardianship cases', 'Efficiency', 'Decrease', 'Maryland Department of Aging reporting system', 'Keidra Rowe', 'Senior Director, Office of Client Services', 'quarterly', 'Maryland Department of Aging reporting system', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Excel', 'Count', NULL, NULL, 'Provide clear details on what exactly this is measuring, how BCHD''s work contributes, and how the number is collected, stored, and calculated', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (152, 'AGC2700', 4, '# of new senior care clients', 'Outcome', 'New clients', 'Maryland Department of Aging  (MDoA) reporting system', 'Keidra Rowe', 'Senior Director, Office of Client Services', 'quarterly', 'Maryland Department of Aging  (MDoA) reporting system', 'Increase', NULL, NULL, 'Count', NULL, 'What is the registration process for senior care clients, how does BCHD affect this?', false, NULL, NULL, 'excel', 'counting', NULL, NULL, 'Clarify data source, recommend switching to Output metric type', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (153, 'AGC2700', 4, '# of new subsidy assisted living participants', 'Effectiveness', 'Filling new spots as they open', 'Maryland Department of Aging reporting system', 'Kiedra Rowe', 'Senior Director Office of Client Services', 'quarterly', 'Maryland Department of Aging reporting system', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, NULL, 'Excel', 'count', NULL, NULL, 'Provide clear details on what exactly this is measuring, how BCHD''s work contributes, and how the number is collected, stored, and calculated', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (154, 'AGC2700', 4, '# of senior companion volunteers', 'Outcome', 'Adding new volunteers', 'Americorps Reporting System', 'Chrystle Samuels', 'Director of Consituent Services', 'quarterly', 'Americorps Reporting System', 'Increase', NULL, NULL, 'Count', NULL, 'Explanation of the Senior Companion volunteer', false, NULL, NULL, 'Excel', 'counting', NULL, NULL, 'Give clear instructions for accessing the proper data to get the count', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (155, 'AGC2700', 4, '# of older adults and persons with disabilities receiving transportation subsidies through the TaxiCard program', 'Output', 'The number of residents utilizing TaxiCard as transportation service', 'TaxiCard Data system (operated by private contractor)', 'Alice Huang', 'Assistant Commissioner, Community Services', 'Quarterly', 'TaxiCard Data system (operated by private contractor)', 'Increase', NULL, NULL, 'Count', NULL, 'Explanation of what the TaxiCard program is', false, NULL, NULL, 'One Drive', 'Data provided by program management company, MJM Innovations, through quarterly and annual reporting', NULL, 'Currently, invoicing from the contractor provides an estimate number of participants per month', 'Give specific details about where in OneDrive the data lives and how exactly the metric is calculated', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (156, 'AGC2700', 4, '# of older adults receiving community-served meals', 'Output', 'The number of residents age 60 and older who participate in a community based meal program (Eating Together in Baltimore)', 'OAAPS (BCHD/Aging)', 'Alice Huang', 'Assistant Commissioner, Community Services', 'Quarterly', '# of older adults who participate in the program', 'Increase', NULL, NULL, 'Count', NULL, 'How many community based meal programs operate in the city?', false, NULL, NULL, 'spreadsheets and one drive', 'Data provided by program management company, MJM Innovations, through quarterly and annual reporting', NULL, 'Currently, monthly invoicing from the various vendors provide an estimate number of participants per month', 'Give clear instructions for accessing the proper spreadsheets to get the count', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
