    (158, 'AGC2700', 4, '% of congregate meal participants reporting satisfaction with community-based meal quality', 'Effectiveness', 'Satisfaction with meal quality based on participant surveys', 'BCHD/Aging', 'Alice Huang', 'Assistant Commissioner, Community Services', 'Annually', '# of responses indicating satisfied or higher / # of total responses', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, NULL, 'One Drive', 'An annual satisfaction survey is conducted across a sample size of participants', NULL, 'Our multisite managers visit each meal site on a regular basis and receive feedback directly from participants on a weekly basis.', 'Give clear instructions for accessing the proper spreadsheets to get the count', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (159, 'AGC3100', 4, '# of households that receive housing related services through CDBG (housing/foreclosure prevention counseling, lead paint remediation, housing rehab, etc.)', 'Output', 'Households that received housing services funded by CDBG through NPOs or City of Baltimore agencies', 'Quarterly activity reports submitted to the CPD via Neighborly by the NPO/City subrecipients', 'Mary Correia', 'Deputy Commissioner', 'Quarterly', 'N/A - Data is the actual number', 'Increase', NULL, NULL, 'Count', NULL, 'What are the federal requirements around CDBG reporting?', true, NULL, 'Neighborly', 'Data is verified by CDBG Monitors and then compiled by Chief of CDBG Compliance', 'Data is reported to the HUD and public via the annual CAPER. It also informs the CPD division during the proposal evaluation process', NULL, 'N/A - using actual reported numbers of households served.', 'The metric does not account for the scale of support (all housing related services are not equal in cost) so 100 households receiving housing/foreclosure prevention counseling could be qualitatively different from 20 receiving extensive housing rehabs. Additionally, provide specificity on what Neighborly report the data is stored on.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (160, 'AGC3100', 4, '% of Community Catalyst Grant Emerging Organizations that increased operation capacity of services and staff', 'Effectiveness', 'An effective grant award is measured by a grantee''s adherence to all Contract Terms including spend down, timelines, and quarterly reporting. No funds are disbursed to an organization who is out of compliance, or ineffective', 'Spenddown & Collecting Quarterly reporting, Neighborly, Airtable, Workday', 'Kelvin Appiah / Wendi Redfern', 'Program Analyst / DC', 'LIVE', 'Total Emerging Operating Grant Awards IN COMPLIANCE / Total Emerging Operating Awards Executed', 'Increase', NULL, NULL, 'Percent', NULL, 'Specificity around the timeline for reporting by organizations to DHCD, as well as specific definitions of "compliance" for grants and how the three systems listed store relevant data (what tables, which reports, etc.)', false, NULL, 'Spenddown & Collecting Quarterly reporting, Neighborly, Airtable, Workday', 'Spenddown & Collecting Quarterly reporting, Neighborly, Airtable, Workday', 'Data is used to assess risk level of Grant Contracts, need for extensions or budget reallocations, or future funding opportunities', NULL, NULL, 'The metric should be scaled by the monetary value of grants, rather than the number of grants.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (161, 'AGC3100', 4, '% of sub-recipients and City agencies that report on their contractual goals/accomplishments within 30 days of the end of each quarter', 'Efficiency', 'Number of CDBG Subrecipients who submit their quarterly reports within 30 days of the end of each quarter, compared to the total number of subrecipients.', 'Data is collected from Neighborly and then divided by the total expected.', 'Mary Correia', 'CDP Deputy Commissioner', 'Quarterly', 'Number of subs with Qtr. report submitted / Total number of subrecipients = Percent submitted on time', 'Increase', NULL, NULL, 'Percent', NULL, 'Identify the specific reports and locations for data in Neighborly.', true, NULL, 'Neighborly', 'Staff member reviews Neighborly submissions/reports to calculate the number of subrecipients who have submitted their quarterly report within the required timeframe (15 days after quarter close for NPOs; end of month after quarter close for COB agencies).', 'Data is used to determine needs for additional training/TA/monitoring to ensure compliance. Also used during weighted application scoring to ensure funding is going to organizations/agencies that consistently meet compliance requirements.', NULL, 'No proxy.', 'Provide the specific data sources/tables on Workday and any filtering instructions.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (162, 'AGC3100', 4, '# of children served (provided with childcare)', 'Output', 'attendance', 'Attendance sheets', 'Nicole Hart', 'Deputy Commissioner', 'Monthly', 'Total days attended for each registrant/Total number of days open for business x15', 'Increase', NULL, NULL, 'Count', NULL, 'What programs are included in this measure, and what is their maximum capacity? Additionally, what is the "x15" factor in the measure formula?', false, NULL, 'At facility location', 'Daily log', 'To ensure center is being used to maximum capacity', NULL, 'n/a', 'Following the provided improvement suggestion, digitize the forms and make it more accessible. Potentially better as a "% of maximum capacity" measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (163, 'AGC3100', 4, 'Average cost per child per year', 'Efficiency', 'Cost to operate', 'Monthly Budget Budget to Actuals', 'Nicole Hart', 'Deputy Commissioner', 'Monthly', 'Spend to date/static capacity', 'Increase', NULL, NULL, 'Currency', NULL, 'What programs are included in this measure? What are the requirements for fiscal reporting for these programs?', true, NULL, 'DHCD Fiscal, Workday', 'Budget to Actual Data in workday', 'To ensure funding is accurately appropriated to cover day to day activities and staffing for maximum capacity to be reached', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
