    (194, 'AGC3100', 4, '# of people referred to coordinated access', 'Output', '# of referrals of persons needing additional support', 'Neighborly Data', 'Nicole Hart', 'Deputy Commissioner', 'Quarterly', 'n/a', 'Decrease', NULL, NULL, 'Count', NULL, 'What is coordinated access? Is it just 50% AMI that is eligible, or are there additional criteria?', false, NULL, 'Neighborly Database', 'Staff input', 'To track persons under 50% AMI who may need additional rent support', NULL, 'n/a', 'Make it a more specific measure name. "Coordinated access" is rather vague, but "referred for additional rent support" is not.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
