    (196, 'AGC3100', 4, '# of meals served', 'Output', 'Number of meals served', 'MSDE Nutrition Program Claim Reimbursement Report', 'Tommy Williams', 'Assistant Commissioner of Homeownership & Housing Preservation', 'Summer Program Report filed monthly in June (rep submitted in 4th qrt), July and August', 'N/A', 'Increase', NULL, NULL, 'Count', NULL, 'What are the reporting requirements for the program?', true, NULL, 'HHP Fiscal Summer Food Services Claims 26', 'Daily during the summer months from all sites', 'Used to determine how many meals get served to kids and at how many sites', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (197, 'AGC3100', 4, '# of sites serviced', 'Output', 'Number of sites Summer meals are provided', 'Number of sites signed up to provided Summer Food Meals', 'Tommy Williams', 'Asst. Commissioner of Homeownership and Housing Preservation', 'We are able to determine daily but report out weekly if sites are operational.', 'N/A', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, '1135 Gilmor', 'Paper currently', 'Data used to determine how many sites actually delivered meals to kids', NULL, 'N/A', 'Change the measure name to something like "# of sites providing meal service" as right now it sounds like the program is servicing the sites rather than the sites providing meals.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (198, 'AGC3100', 4, '% of unused meals', 'Outcome', 'Number of unused meals', 'Accountability Sheet''Working on this', 'Tommy Williams', 'Asst. Commissioner of Homeownership and Housing Preservation', 'Currently data is collected daily but reporting is done weekly', 'Total of 1st and 2nd meals divided by total number of meals ordered', 'Decrease', NULL, NULL, 'Percent', NULL, 'What counts as an "unused meal?" Is there recycling of meals across days?', false, NULL, '225 summer food program sites throughout Baltimore city', 'Weekly meal count sheets', 'It helps determine of meals that have been unused', NULL, 'N/A', 'Change the name to something more in line with the intent ("% of meals unused") and provide a more clear formula.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (199, 'AGC3100', 4, '% of mystery shoppers reporting Area Clean/ Free of Trash', 'Effectiveness', 'We hire "mystery shoppers" to enter into the district and assess whether they found the area to be "Clean and Free of Trash" and then to identify how many pieces of trash they saw. We perfom 20 of these "shops" over the course of the year. This measure is the percentage of total shops that were denoted as "clean and free of trash"', 'Secret shopper reports provided by contractor', 'Matthew Kujava', 'Director of Operations', 'We receive individual reports within 2 weeks of the actual date of the mystery shopper event. We are able to pull summary statistics directly from the Contractor''s website with data that is current as of the most recent published report', 'Total mystery shops marked as "Clean and Free of Trash"  DIVIDED BY Total Mystery Shops = % of mystery shoppers reporting area clean/free of trash', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Contractor website; individual reports are emailed to us and filed', 'Waterfront Partnership pays a 3rd party contractor to perform mystery shops in the area; contractor provides reports to Waterfront Partnership with the results', 'This data is used to assess the effectiveness of our clean and safe teams, identify cleanliness trouble spots that may need extra attention on a regular basis, or identify specific events that may have led to unclean conditions that would require additional staffing and City support int the future', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (200, 'AGC3100', 4, 'Staff hours for clean/safety teams', 'Output', 'Measurement of the number of worker-hours spent on clean and safety team staff members that work within the Inner Harbor to keep the area clean and safe', 'Software maintained by Block By Block, our contractor for this service; Invoices', 'Matthew Kujava', 'Director of Operations', 'Monthly', 'Sum of hours', 'Not Applicable', NULL, NULL, 'Count', NULL, 'Is there a benchmark, and is it linked to seasonal demand?', false, NULL, 'Contractor-controlled system', 'Staff hours are tabulated based on daily staff time sheets', 'This data is used to assess whether Waterfront Partnership is adequately staffing services in the Inner Harbor to keep the area clean and inviting to visitors. Too few hours could lead to a lower "effectiveness" measure around whether the Inner Harbor is actually clean, and a reduced presence of Waterfront "Guides" which could lower public perception of safety and security in the Harbor. Above-target hours suggest that the volume and attendance of events and attractions in the Inner Harbor required additional services to maintain levels of cleanliness and safety.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (201, 'AGC3100', 4, '# of attendees at Live Baltimore events', 'Output', 'Attendance at virtual homebuyer events and Trolley Tours', 'Attendance count', 'Meghan McCorkell', 'Executive Director', 'We count attendance at each event', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Spreadsheet', 'Both Eventbrite and manually', 'We compare preivous years #''s with these to make sure programs continue to be high interest', NULL, NULL, 'Use a Microsoft Form linked to a database for more automated tracking.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (202, 'AGC3100', 4, '# of Live Baltimore customers who purchased a home in the city', 'Outcome', '# of people who attended LB program or created website profile and bought home in the same year', 'Tax Records compared to LB records', 'Meghan McCorkell', 'Executive Director', 'Annually on calendar year', 'Formula pending.', 'Increase', NULL, NULL, 'Count', NULL, 'How much information on customers do you collect for this comparison?', false, NULL, 'Spreadsheet', 'Data Analyst compare LB data to City tax records', 'Shows how many city homebuyers LB is impacting', NULL, 'We calculate our customer data measuring an increase/decrease in customers', 'Utilize automated reporting of sales from SDAT or some DHCD database to increase the frequency of data collection and aggregation.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (203, 'AGC3100', 4, '# of Live Baltimore customers who used a City or State incentive.', 'Output', '# of people who attended LB program or created website profile and bought home in the same year using an incentive', 'Tax Records compared to LB records', 'Meghan McCorkell', 'Executive Director', 'Annually on calendar year', 'Formula pending.', 'Increase', NULL, NULL, 'Count', NULL, 'Does a master list of incentives that are considered for this measure exist somewhere?', false, NULL, 'Spreadsheet', 'Data Analyst compare LB data to City tax records', 'Show LB customers using incentives', NULL, 'We calculate our customer data measuring an increase/decrease in customers', 'If possible, utilize automated reporting from state and city programs to calculate more frequently.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
