    (205, 'AGC3300', 4, 'Average time to answer a call in benefits (in seconds)', 'Efficiency', 'Average speed of answer (hh:mm:ss) for all benefits ACD phone lines.', 'ACD Phone System', 'Ray Gulhar', 'Chief of Benefits', 'Monthly', 'Total number of automated call distribution (ACD) calls and the average time to answer said calls. Abandoned calls are not included.', 'Decrease', NULL, NULL, 'Count', NULL, 'It would be helpful to know what they mean by time to "answer" the call. Does "answer" the call just mean picking up the phone or does it mean answering the callers'' questions/resolving their issue?', true, NULL, 'Mitel Phone system (CCMWeb)', 'Queue Performance by Month excel reports run by system', 'It is used to track the response time of Benefits staff to answer calls coming into the office.', NULL, NULL, 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (206, 'AGC3300', 4, 'Average # of days to provide eligibility list to agencies', 'Output', 'As part of the Time to Hire Metric we are measure a part of that porcess', 'Workday', 'Conrad Samuels', 'Chief, Recruitment', 'Live', 'Workday', 'Decrease', NULL, NULL, 'Count', NULL, 'Unclear how this data is recorded and what format it''s in', false, NULL, 'Workday', 'Report', 'This data is being used to determine the total Time per Hire in the City''s Recruitment process', NULL, NULL, 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
