    (208, 'AGC3300', 4, '% of new hires across City government that are City residents', 'Output', 'We are measuring the number of new City employees that are residents of Baltimore City', 'Workday', 'Robert Paige', 'Chief, HRIT', 'Live', 'Workday', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Workday', 'Addresses in Workday', 'This data is used to see if the City''s commitment to hire City Workers is increasing.', NULL, NULL, 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (209, 'AGC3300', 4, '% of employees engaging in Wellness programs', 'Outcome', 'This metrics is to determine how many employees are participating in Wellness Program', 'Wellness Tracking Sheet', 'Ray Gulhar', 'Chief of Benefits', 'Weekly.', 'Wellness Tracking Sheet', 'Increase', NULL, NULL, 'Percent', NULL, 'Its unclear whether the metric is [wellness attendees]/[wellness program sign-ups] or if its [welness program sign-ups]/[all employees]. Either serves a purpose, but its unclear which one theyre using', true, NULL, 'Wellness Tracking Sheet', 'This data is collected manually based on the enrollment of Wellness Class and the number of employees that show and participate', 'The data is used to determine the popularity of the programs and the effectiveness of the Wellness program.', NULL, NULL, 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (210, 'AGC3300', 4, '% of employees attending a training ”satisfied” or ”highly satisfied” with experience', 'Outcome', 'This metrics obtains feedback from users of online training content that was created the Learning and Development', 'Workday (COB curated and launched online content. This metric does not include vendor provided content or ILT. Workday report > All Evaluations)', 'Theresa Gjika', 'Chief, Learning and Development', 'Upon the complete of the training', 'Workday (COB curated and launched online content. This metric does not include vendor provided content or ILT. Workday report > All Evaluations)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Workday', 'Electronically in Workday', 'This data is used to see if the content of a training program needs to be changed based on feedback', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (211, 'AGC3300', 4, '% of Employee Assistance Program (EAP) cases successfully resolved (based on returns for the same reason)', 'Outcome', 'This metric measures the percentage of employees who successfully complete the EAP program without a return visit for the same issue within a year', 'EAP Case management software', 'Terri Hill', 'Chief,  EAP', 'This data is manually pulled from the EAP Case management software', 'EAP Case management software', 'Increase', NULL, NULL, 'Percent', NULL, 'How the formula accounts for employees who leave after completing the EAP program', false, NULL, 'EAP Case management software', 'The information is manually entered into the EAP case Management software', 'This data is used to determine the effectivessness of the EAP Program.', NULL, NULL, 'The metric seems to not account for folks who leave the city - voluntarily or otherwise - after completing an EAP program. Employees leaving city employment after completing the EAP program may be artificially inflating the metric when really it might be a signal that the EAP program is ineffective.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
