    (213, 'AGC3300', 4, '% of classification and compensation project requests completed within deadline', 'Outcome', 'The metric is measuring how long does is the process to complete classification and compensation projects.', 'C&C Project Log', 'Alisa Jordon', 'Chief, Classification and Compensation', 'Manually, Excel Spreadsheet', 'C&C Project Log', 'Increase', NULL, NULL, 'Percent', NULL, 'The Measure name and measure description are contradictory - is it the percent completed on time or a measure of how long on average it takes?', false, NULL, 'On a Shared Drive', 'Manually', 'This data is being used to review the process and procedures in our Classification and Compensation Unit as well to continue to review staffing levels.', NULL, NULL, 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (214, 'AGC3300', 4, '# of training enrollments', 'Outcome', 'This metrics measure the number of employees who have signed up for Training classes', 'Workday learning report > Learning Enrollment', 'Theresa Gjika', 'Chief, Learning and Development', 'Live', 'Workday learning report > Learning Enrollment', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Workday', 'Registration in Workday', 'This data is used to determine if employees are able to sign up for classes and how many are enrolling.', NULL, NULL, 'Change measure type to "Output"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (215, 'AGC3300', 4, '# of classification and compensation projects requested by city agencies', 'Effectiveness', 'This metrics is to outline the type and number of compensation related request that are received.', 'C&C Project Log', 'Alisa Jordon', 'Chief, Classification and Compensation', 'Manually in Excel Spreadsheet', 'C&C Project Log', 'Decrease', NULL, NULL, 'Count', NULL, 'Would be good to know why a CnC is requested. Does a request for a CnC mean that HR is fixing a faulty classification? If so, then I would consider this effectiveness.', true, NULL, 'Data is collected on a Class and Comp Excel Spreadsheet', 'The data is entered into Workday, and external form Wufoo', 'The data is being used to evaluate processes and turn around time of request', NULL, NULL, '"Output". Would be a better effectiveness measure if it was a percent of all job classifications in a given agency', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
