    (218, 'AGC3500', 4, '% of payout damages claimed', 'Outcome', 'Total amount of damages claimed/total amount of damages paid out (Labor & Employment suits and claims)', 'Internal reports (Case Log)', 'Gary Gilkey', 'Practice Group Chief, Labor & Employment', 'Quaterly', 'total amount of damages paid/total amount of damages claimedx100', 'Decrease', NULL, NULL, 'Percent', NULL, 'The measure description and measure formula contradict each other', false, NULL, 'City Hall', 'Administrative Data Review', 'The data is used to measure operational performance (attorney ability to negotiate or to defend the city from liability); financial impact (to the City''s budget)', NULL, 'The unit does not require proxy', 'Change measure type to "Effectiveness". The measure description and measure formula contradict each other', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
