    (220, 'AGC3500', 4, '% of clients rating services good or excellent', 'Output', 'Definition pending.', 'Source pending.', 'Owner pending.', 'Owner role pending.', 'Frequency pending.', 'Formula pending.', 'Not Applicable', NULL, NULL, 'Percent', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (221, 'AGC3500', 4, '# of misconduct cases resolved', 'Output', 'Determines the total number of reported misconduct cases that were fully resolved (BPD officers accepted discipline) within the reporting period', 'Reports/Evaluations (Consent Decree Monitoring Team)', 'Justin Conroy', 'Practice Group Chief, Police Legal Affairs', 'Quarterly', 'Total # of misconduct cases received - total # of misconduct cases fully resolved (within the reporting period)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Baltimore Police Department Public Integrity Bureau location', 'Data Collection and aggregation', 'Operational productivity and workload management; effectiveness of the investigations and compliance process', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (222, 'AGC3500', 4, '% of cases resolved prior to hearing', 'Outcome', 'Represents the proportion of civil cases that are fully resolved prior to formal hearing', 'Case Management System', 'Justin Conroy', 'Practice Group Chief, Police Legal Affairs', 'Quarterly', 'Total # of civil cases received/total # of cases resolved (settlement) before a trial board*100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Baltimore Police Department HQ', 'Data Collection and Aggregation', 'Determine how efficient the case management process (including negotiation) is; determine the effectivness of arly case resolution (cost-savings on resources and total settlement amounts)', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (223, 'AGC3500', 4, '# of appeals handled', 'Output', 'Total number of workers'' compensation appeals managed (assigned to an attorney) within a defined reporting period (does not suggest final determination of appeals)', 'Clio (case management software)', 'Ron Travers', 'Practice Group Chief, Workers'' Compensation', 'Quarterly', 'Clio (case management software)', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, '7 E. Redwood Street', 'Administrative Review/Data Report', 'Evaluate operational performance of unit; assess effectiveness of claims handling and dispute resolution processes; identify trends in frequency of appeals to inform policy (or safety improvements)', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (224, 'AGC3500', 4, '# of claims handled each year', 'Output', 'Total number of worker''s compensation claims that are received and assigned within a defined reporting period', 'Clio (case management software)', 'Ron Travers', 'Practice Group Chief, Workers Compensation', 'Quarterly', 'Clio (case management software)', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, '7 E. Redwood Street', 'Administrative Review/Data Report', 'Assess the City''s risk exposure (for employees); monitor workload for City agencies (units that handle workers compensation processes i.e., payroll, management, risk management)', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (225, 'AGC3500', 4, '% of yes/no issues tried and won', 'Outcome', 'The total of workers'' compensation cases that were contested (outcome of initial trial) and won', 'Clio (case management software)', 'Ron Travers', 'Practice Group Chief, Workers'' Compensation', 'Quarterly', 'Clio (case management software)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, '7 E. Redwood Street', 'Administrative Review/Data Reporting', 'Evaluate operational performance of unit; Assess effectiveness of legal defense strategies; support resource allocation (additional training)', NULL, 'N/A', 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (226, 'AGC3900', 4, '# of materials circulated', 'Output', 'Resource & Material Access. Providing access to a vetted collection is a core service that Pratt Library provides to the City of Baltimore. This includes online resources for school support, eBooks, journals, and physical items ranging from traditional books to items such as microscopes and musical instruments.', 'Physical Material Circulation: SirsiDynix Symphony integrated library system (ILS). eMaterials Circulation: Shared report prepared by the digital resources librarian, based on vendor-provided usage data.', 'Originating Data (Physical Materials: Zary Necheva; eMaterials: Tracy Thompson). Data Reporting: Jennifer Mange', 'Originating Data: (Physical Materials: ILS Administrator; eMaterials: Digital Resources Manager). Data Reporting: Analyst', 'Live (for ILS checkout). Monthly (for eResource data that originates with vendors/content providers)', 'Number of times Physical Materials circulated plus number of times eMaterials circulated', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Pratt Library''s Integrated Library System (ILS) for physical materials, and the Digital Resource Dept. for eMaterials and use of online resources', 'Physical Material Circulation: SirsiDynix Symphony integrated library system (ILS). eMaterials Circulation: Shared report prepared by the digital resources librarian, based on vendor-provided usage data.', 'Free access to physical materials and online resources is core to the Library''s mission "to empower, enrich, and enhance the quality of life for all through equitable access to information, services, and opportunity." Usage data informs decisionmaking on how to provide the best service.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (227, 'AGC3900', 4, '# of participants in Literacy and Lifelong Learning programs', 'Output', 'Foster literacy and lifelong learning though free programming for the entire community, birth to seniors, including early learning, after school programming, summer reading, adult literacy, author visits, social impact programming, and programs on health, financial literacy.', 'Tableau server, as well as additional shared Google forms/spreadsheets (Pratt Centers for Technology Training, Social Impact Programs, School and Class Visits)', 'Originating Data (Programs: Carly Reighard; Pratt Center for Technology Training: Millie Godfrey; Social Impact Partner Programs: Tara Bhardvaj). Data Reporting: Jennifer Mange', 'Originating Data (Director of Programming; Manager of Pratt Centers for Technology Training; IT Project Manager ). Data Reporting: Analyst', 'Tableau server updates daily on a 14-day lag. Other data entered/finalized monthly (Pratt Centers for Technology Training, Social Impact Programs, School and Class Visits).', 'Total number of participants at all Pratt Library public programs', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Tableau server, as well as additional shared Google forms/spreadsheets (Pratt Centers for Technology Training, Social Impact Programs, School and Class Visits).', 'Data entered manually via Localist online event portal (and stored in Tableau server), as well as shared Google forms/spreadsheets (Pratt Centers for Technology Training, Social Impact Programs, School and Class Visits).', 'Free access to programming that supports literacy and lifelong learning is core to the Library''s mission. Usage data informs decisionmaking on how to provide the best service.', NULL, 'N/A', 'Perhaps you could weight each unique participant with the amount of participation (how many sessions attended).', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (228, 'AGC3900', 4, '# of participants in Social Impact programs', 'Output', 'Total number of participants in all Social Impact Programs, including Social Worker in the Library (launched FY18), Lawyer in the Library (launched FY19), Peer Navigator (launched FY22), Healthcare in the Library (piloted FY23) and Housing Navigator (launched FY23)', 'Manual count of program participants by Library staff and partner organizations, summarized monthly in a shared Google sheet', 'Originating Data: Tara Bhardvaj. Data Reporting: Jennifer Mange', 'Originating Data: IT Project Manager. Data Reporting: Analyst', 'Monthly', 'Total number of participants in all Social Impact Programs, including Social Worker in the Library (launched FY18), Lawyer in the Library (launched FY19), Peer Navigator (launched FY22), Healthcare in the Library (piloted FY23) and Housing Navigator (launched FY23)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Shared Google sheet', 'Manual count of program participants by Library staff and partner organizations is summarized monthly via a shared Google sheet', 'Free assistance and advice to community members from lawyers, social workers, nurses, addiction recovery specialists and more is core to the Library''s mission. Usage data informs decisionmaking on how to provide the best service.', NULL, 'N/A', 'Use a Microsoft Form linked to a database for more automated tracking.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (229, 'AGC3900', 4, '# of visits to the library', 'Effectiveness', 'Total number of people who physically visit a library building or mobile services unit. (This does not include website use; a significant percentage of Pratt Library customers us the library mostly online.)', 'Traf-Sys people counting system', 'Originating Trafsys Data and Data Reporting: Jennifer Mange', 'Originating Trafsys Data and Data Reporting: Analyst', 'Daily', 'Total number of people who physically visit a library building or mobile services unit. (This does not include website use; a significant percentage of Pratt Library customers us the library mostly online.)', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Traf-Sys people counting system', 'Hardware installed at entrance of and strategic locations within library buildings captures visitor count', 'Usage data informs decisionmaking on how to provide the best service across all 22 locations and via mobile outreach.', NULL, 'N/A', 'Change measure type to Output (it relates directly to service delivery).', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (230, 'AGC3900', 4, '# of WiFi sessions and public computer sessions (in millions)', 'Output', 'Pratt Library provides resources to close the digital divide via public computers inside the Library, WiFi access that extends outside around branches, and through other methods including lending of hotspots, laptops, and projects such as WiFi-enabled mobile units. Number of computer (or WiFi) sessions is different than number of unique users. For example, if a customer comes in five times for 2 hours each time to work on a business plan or a resume and job applications on a Pratt computer that would be five sessions (but one unique customer).', 'WiFi Sessions: Data originates in server logs; summary data is shared via a Google sheet prepared by Systems Dept. Public Computer Sessions: SAM (Smart Access Manager) platform for PC management, connecting SirSiDynix to public computers and other work stations.', 'Originating Data (Wi-Fi Sessions: Michael Brown; Computer Sessions: Jasbir Singh). Data Reporting: Jennifer Mange', 'Originating Data (Wi-Fi Sessions: Director of Networks and Engineering; Computer Sessions: Desktop Engineering Supervisor ). Data Reporting: Analyst', 'Monthly', 'Sum of Internet connectivity (WiFi) sessions that the Library provides and number of customer sessions at library public computer stations. A session is a continuous period of time. This is not the same as a unique user.', 'Increase', NULL, NULL, 'Count', 'in millions', 'Why measure sessions and not unique users?', false, NULL, 'WiFi Sessions: Data originates in server logs. Public Computer Sessions: SAM (Smart Access Manager) platform for PC management.', 'WiFi Sessions: Data originates in server logs; summary data is shared via a Google sheet prepared by Systems Dept. Public Computer Sessions: SAM (Smart Access Manager) platform for PC management, connecting SirSiDynix to public computers and other work stations.', 'Digital equity is core to the Library''s mission. Usage data informs decisionmaking on how to provide the best service.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (231, 'AGC3900', 4, 'Net Promoter Score', 'Effectiveness', 'Net Promoter Score (NPS) is a customer experience metric calculated on a bi-weekly basis.', 'Orange Boy''s Savannah platform, a provider of public library customer engagement and data analytics', 'Originating Data: Nestor Diaz. Data Reporting: Jennifer Mange', 'Originating Data: Director of Marketing and Communications. Data Reporting: Analyst', 'Bi-weekly', 'Based on answers to a survey of a small percentage of library card holders every two weeks that asks, "On a scale from 0 to 10, how likely are you to recommend the Enoch Pratt Free Library to others?" NPS is the percentage of Promoters (i.e., those who score the Library a 9-10).', 'Increase', NULL, NULL, 'Count', NULL, 'Why are promoters only those who score 9 or 10?', true, NULL, 'Orange Boy''s Savannah platform, a provider of public library customer engagement and data analytics', 'Every two weeks a survey is sent to a small percentage of library card holders that asks, "On a scale from 0 to 10, how likely are you to recommend the Enoch Pratt Free Library to others?" NPS is the percentage of Promoters (i.e., those who score the Library a 9-10).', 'Usage data informs decisionmaking on how to provide the best service.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (232, 'AGC4301', 4, '# of agencies participating in CitiStat meetings', 'Output', 'This measures the number of distinct Baltimore City non-quasai agencies participating in a Stat meeting.', 'CitiStat Calendar', 'Danny Heller', 'Deputy Chief Performance Officer', 'We are able to calculate at any time, but the process is highly manual.', '# of agencies who attend 1 Stat in time period measaured. An agency should not be counted more than once, even if they attend multiple Stats.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CitiStat Outlook Calendar (citistat@baltimorecity.gov) and Invite Lists (Each Stat site has an invitation list)', 'Manual counting', 'This data is used to identify the number of agencies who participate in a Stat meeting during a time period. It is a measure of programmatic reach.', NULL, NULL, 'Change the metric to "# of agencies sending representatives to present or serve on the panel in CitiStat meetings." Passive observers do not equal participation.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (233, 'AGC4301', 4, '% of CitiStat meeting primary stakeholders that agree/strongly agree with the value of the meeting', 'Outcome', 'Measure Description: Calculated percentage of CitiStat attendees that would agree or somewhat agree with the value of their monthly stats.  This is calculated by aggregating responses which a range from agree to disagree.', 'Microsoft Form (created by OPI for tracking)', 'Danny Heller', 'Deputy Chief Performance Officer, OPI', 'Monthly and manual', 'Total count of ''agree'' and ''somehwat agree'' dividied by the total # of responses', 'Increase', NULL, NULL, 'Percent', NULL, 'Which responses are considered to be from "primary stakeholders?" Is this a 5-point scale (strongly disagree to strongly agree)?', true, NULL, 'This manually manged data is held on a form within OPI''s Sharepoint environment', 'Manual, using the Excel spreadsheet', 'To improve the Stat program/offering.  We need agency buy-in and satsfaction to ensure continued success of the Stat program', NULL, NULL, 'Replace "primary stakeholders" with "attendees" since the survey is anonymized and not everyone who attends is a primary stakeholder.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (234, 'AGC4301', 4, 'Average # of CitiStat meetings per quarter', 'Output', 'The measure looks at the average number of CitiStat meetings held in a quarter.', 'CitiStat team Outlook Calendar', 'Danny Heller', 'Deputy Chief Performance Officer', 'The data is always available, but the process is currently highly manual.', '# of meetings/# of quarters
Q1-7/1-9/30
Q2-10/1-12/31
Q3-1/1-3/31
Q4 4/1-6/30', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CitiStat Outlook Calendar', 'We count the number of meetings held on the calendar. We can validate using meeting folders in our shared drive.', 'The data is used to assess the frequency of CitiStat meetings held by the CitiStat program. It can also be used to assess the time commitment of CitiStat staff and City leaders who attend the meetings.', NULL, NULL, 'Rather than the average # of meetings, change it to "% of meetings held as scheduled." This is a measure of efficiency/effectiveness.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (235, 'AGC4301', 4, 'Average number of inspections per quarter', 'Output', 'The total # of confirmed inspections during the quarter', 'CitiStat Asana Inspections calendar', 'Danny Heller', 'Deputy Chief Performance Officer', 'Monthly.', 'Total # of Inspections divided by number of quarters (116/1)', 'Increase', NULL, NULL, 'Count', NULL, 'What do inspections entail, and what are the outputs of an inspection?', false, NULL, 'Online web calendar (password protected) Asana website', 'Manual.  Counting of confirmed entries within the Asana calendar', 'To determine and balance the workload of inspectors responsible for the CitiSat program', NULL, NULL, 'We should consider a metric more aligned to an SLA for inspections, so we could present this as an "on-time rate" measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (236, 'AGC4301', 4, '# of individuals reached across MIMA''s  communication channels', 'Output', 'MIMA''s shares multilingual information with community members and partners through its monthly email newsletter (published through GovDelivery), Facebook page, Instagram page, and service provider WhatsApp group. This measure sums the total number of content interactions across those four platforms to assess the impact and efficacy of MIMA''s digital communications strategy.', '"Unique Opens" of monthly newsletters from GovDelivery Bulletin Reports; "Content Interactions" on Facebook and Instagram pages from Meta Business Suite Insights; number of "Media, links and docs" shared in "Baltimore City Resources" chat from WhatsApp', 'Angela Ra', 'Communications and Strategic Policy Manager', 'Live; scraped monthly', '# of "Unique Opens" of MIMA''s monthly newsletter + # of "Content Interactions" on MIMA''s Facebook page + # of "Content Interactions" on MIMA''s Instagram page + # of "Media, links and docs" shared in "Baltimore City Resources" WhatsApp group', 'Increase', NULL, NULL, 'Count', NULL, 'Need more info on "# of "Media, links and docs" shared in "Baltimore City Resources" WhatsApp group" - feels like a risk for number inflation', true, NULL, 'Stored in GovDelivery, Meta Business Suites, and WhatsApp; manually scraped at end of each calendar month; and compiled in a spreadsheet in the MIMA SharePoint at "\Documents\Communications\Internal\Performance Metrics\MIMA Comms Performance Metrics.xlsx"', 'Automatic
GovDelivery: # of unique email accounts that open a specific email
Meta Business Suites: # of reactions, saves, comments, shares, and replies for the content on Facebook or Instagram page
WhatsApp: # of media, links, and documents shared to chat', 'This measure is used to assess the efficacy and impact of MIMA''s communications strategy. The relative performance and trends in engagement of the respective platforms guide the allocation of time and labor costs dedicated to developing and publishing content across those platforms. The overall trend in the total interactions across all platforms provides a measure of accountability, representing the digital communications strategy''s performance in consistently engaging and growing its reach to MIMA''s target constituencies.', NULL, 'Not applicable', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (237, 'AGC4301', 4, '# of language access services accessed by city agencies', 'Outcome', 'MIMA manages the City''s language access program, which entails the provision of ongoing technical assistance to City agencies as they serve individuals with limited English proficiency (LEP). MIMA has centralized access to key language access services (interpretation, translation, and training), and this metric reflects the number of services requested and accessed by City agencies through MIMA.', 'Telephonic interpretation call data from Language Line automated reports; Workday training reports from DHR; interpretation requests submitted to and fulfilled by MIMA from internal Microsoft Lists tracker', 'Joy Scalabrin (joy.scalabrin@baltimorecity.gov)', 'Language Access Coordinator', 'Live', 'Number of telephonic interpretation calls + Number of employees who have completed the Language Access WorkDay training + Number of in-person interpretation requests + Number of documents translated completed', 'Increase', NULL, NULL, 'Count', NULL, 'Looks like they count unrelated numbers as one count. Strongly suggest splitting this up into several metrics', true, NULL, 'Language Line (telephonic interpretation vendor); DHR (Workday training); email, "General Language Access Request Form" Microsoft Form (compiled in Microsoft List, "FY26 Language Access Requests Tracker," in MIMA''s SharePoint)', 'Language Line: telephonic interpretation call data (time, minutes, language, City agency)
DHR: course enrollees and status (enrolled, in progress, completed)
On-site interpretation and translations: requests by email or MS Forms; compiled in MS Lists', 'This metric is used to understand the volume of requests that MIMA is receiving for language access services. The data help us measure the growth of service usage across City agencies, as it reflects a growing awareness by City employees of the availability of services and willingness to use them when serving a constituent with LEP. This is directly tied to MIMA''s work to address the adaptive challenge of language access implementation.', NULL, 'Not applicable', 'Change measure type to "Output"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (238, 'AGC4301', 4, '% of agencies with Language Access Plans', 'Output', 'MIMA manages the City''s language access program, which entails the provision of ongoing technical assistance to City agencies as they serve individuals with limited English proficiency (LEP). MIMA has established an onboarding process for City agencies to achieve language access compliance, which includes completing a four-factor analysis survey, translating vital documents, training their staff, and writing a language access plan. This metric reports on the progress of language access onboarding by reporting the number of agencies that have completed writing their plans, which is considered the capstone of the onboarding process.', 'Total of completed language access plans submitted to MIMA and saved in MIMA''s SharePoint divided by total number of agencies that have completed language access onboarding', 'Joy Scalabrin (joy.scalabrin@baltimorecity.gov)', 'Language Access Coordinator', 'Live', 'Total number of agencies with updated Language Access Plans / Total number of agencies required to submit Language Access Plans', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'As agencies complete their language access plans, they are saved in the MIMA SharePoint within "\Documents\Language Access\Language Access Plans." Plans are organized by year of completion.', 'Agencies that are required to submit language access plans are identified by a pre-determined onboarding schedule set by MIMA. Upon completion of language access onboarding, language access plans are emailed to MIMA and saved in MIMA''s SharePoint.', 'This measure monitors the progress made by onboarded City agencies in finalizing their respective language access plans, which provide robust frameworks for interacting with and serving residents with LEP. The measure is intended to capture the quality of MIMA''s technical assistance to ensure that City agencies are adequately equipped to complete their respective language access plans and to adhere to agreed upon timelines. Through this measure, we are able to gauge which agency relationships may require less or more guidance and oversight from MIMA to further those City agencies'' language access readiness.', NULL, 'Not applicable', 'Change measure type to "Effectiveness"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (239, 'AGC4301', 4, '% of selected participants who complete the New American Leadership Institute course', 'Outcome', 'The New American Leadership Institute (NALI) is an annual in-person, four-session civics academy held in the fall for emerging immigrant and refugee leaders to learn about the structure of local government, hone leadership skills, network with peers, and identify opportunities for civic participation. Participants are required to attend at least three out of the four sessions to graduate from the program. This metric reports the percentage of individuals who were accepted into the program that satisfied this requirement.', 'Total number of NALI graduates (assessed from in-person attendance sign-in records in Microsoft Forms) divided by total number of NALI accepted applicants (assessed from Microsoft Form submissions)', 'Masuma Lonczak (masuma.lonczak@baltimorecity.gov)', 'Deputy Director', 'Weekly at session dates over the duration of the program (in FY26, 9/13/2025 to 10/2/2025)', 'Total number of graduates / Total number of accepted applicants', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Sign-in form and application form created in Microsoft Forms. Respective responses saved in the MIMA SharePoint within "\Documents\Civic Engagement\New American Leadership Institute (NALI)\NALI 2025\Forms."', 'Sign-in form is made available to the participants at each in-person session. NALI Intern ensures that participants present at each session complete the sign-in form on their mobile phones. Following each session, Deputy Director consolidates the data.', 'This data capture both the efficacy and impact of one of MIMA''s signature programs. First, tracking graduation outcomes allows us to assess participant retention, completion rates, and our ability to provide a compelling and effective curriculum. This information helps us determine appropriate cohort sizes, staffing needs, and facilitation capacity, while also identifying opportunities to strengthen participant engagement and address barriers to completion. Second, the number of graduates represents the ouput of our having successfully prepared New Americans to now serve as advocates for their communities through civic engagement opportunities.', NULL, 'Not applicable', 'Change measure type to "Output"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (240, 'AGC4301', 4, '# of participants (youth/young adults) who have initiated an intake, assessment and case management process', 'Output', '•	Number of unduplicated youth and young adults who complete the Connect 2 Success intake and initial assessment during the reporting period.', '•	Monthly Excel Tracker
•	CAP60 Data Management System', 'Tracey Estep', 'Chief of Operations', '•	Monthly', 'Monthly Tracker (numerical count of completed intakes)ily League Data Tracker', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, '•	Monthly Excel Tracker (primary calculation file)
•	CAP60', '•	Information is collected during:
o	Initial participant encounter
o	Completion of intake and assessment forms
o	Development of the Personal Growth Plan
o	Documentation of early engagement activities', 'Data is used to:
*Monitor program reach and access to participants

*Identify trends in engagement across neighborhoods, age groups, or referral sources

*Inform staffing, mentor assignments, and resource allocation

*Support quarterly and annual reporting to leadership, funders, and community partners

Ensure compliance with performance management and accountability requirements', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (241, 'AGC4301', 4, '% of participants (youth/young adults) who have acheived 2 or more personal goals within 90 days', 'Effectiveness', '•	Number and percentage of active Connect 2 Success participants who complete two or more goals identified in their Personal Growth Plan within the 90 day period.', '•	Monthly Program Tracker
•	CAP60 Data Management System', 'Tracey Estep', 'Chief of Operations', '•	Available monthly
•	Calculated after participants reach the 90-day engagement threshold
•	Adjusted for documented early exits and participants not yet time-eligible', '•	Numerator: 109 participants completing ≥2 goals
•	Denominator: 137 participants on task (excluding early exits and those under 90 days)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, '•	Monthly Excel Tracker (primary calculation file)
•	CAP60 (source documentation and validation)', 'Data is obtained through:
•	Initial intake and assessment
•	Development of the Personal Growth Plan
•	Ongoing mentor and navigator engagement
•	Documentation of goal progress and completion
•	Monthly review and verification by program staff', '•	Monthly and quarterly performance monitoring
•	Identification of participants needing additional support
•	Inform mentor assignments and service intensity
•	Guide program improvements and resource allocation
•	Required reporting for OPI, Squeegee Collaborative, Internal and External  stakeholders', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (242, 'AGC4301', 4, '% of participants engaged attending school or job-readiness program', 'Outcome', '•	Number and percentage of Connect 2 Success participants who are actively enrolled in school or employed during the reporting period.', '•	Monthly Program Tracker
