    (306, 'AGC4326', 4, 'Equivalent advertising value of free, positive editorial coverage secured for Baltimore (in millions)', 'Output', 'Public relations activities (proactive pitching, hosting journalists for in market visits, etc.) generate free advertising for Baltimore’s tourism products and services.', 'Burrelles, Critical Mention, and PR Track', 'Craig Walters-Vay', 'CFO', 'Annually', 'For each article: Unique Visitors per Month(UVPM) * 0.025 * 0.37', 'Increase', NULL, NULL, 'N/A', 'in millions', 'N/A', true, NULL, 'Burrelles, Critical Mention, and PR Track', 'Outside agency assistance', 'Used to evaluate the reach and effectiveness of Visit Baltimore’s communications and public relations efforts in promoting Baltimore as a destination, serving as a proxy for market visibility and brand exposure.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
