    (309, 'AGC4326', 4, 'Total hotel taxes collected in the City (Fiscal year realized, in millions)', 'Output', 'Influenced by the increasing number of actualized hotel room nights projected in the City (e.g. volume of overnight traffic) and the average daily rates of the City''s hotel community.', 'City BBMR - Dept of Finance', 'Craig Walters-Vay', 'CFO', 'Annually', 'Total amount of Hotel Tax paid by the hotels to the City', 'Increase', NULL, NULL, 'Currency', 'in millions', 'N/A', true, NULL, 'City BBMR - Dept of Finance', 'Email from City BBMR', 'Used as a high-level indicator of overall tourism activity and economic health, reflecting the downstream fiscal impact of visitor spending influenced by Visit Baltimore’s work.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
