    (336, 'AGC4356', 4, '% of grant receipients who identify as women artists or organizations who ae majority led by women', 'Effectiveness', 'Percent of grant recipients identifying as women artists or women-led organizations.', 'Grantee demographic reporting', 'Tamara Robinson / JaMel Johnson', 'DOF/COO', 'Annual', 'Nothing provided', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'BOPA/CB', 'Post-award demographic reporting', 'Evaluate representation in grant awards', NULL, 'FY26 target used while reporting is pending', 'You can make this a live measure by building some kind of app or tracking sheet that looks at all active grants and the demographic information you collected.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (337, 'AGC4356', 4, 'Return on investment for City dollars', 'Efficiency', 'Return on investment for City dollars invested in arts, culture, and  programming.', 'Attendance data and financial reporting', 'Tamara Robinson / JaMel Johnson', 'DOF/COO', 'Quarterly', 'Nothing provided', 'Not Applicable', NULL, NULL, 'N/A', NULL, 'What is considered in the ROI formula?', false, NULL, 'BOPA/CB', 'Finance-calculated using attendance and investment data', 'Evaluate value generated by City-funded programming', NULL, 'Attendance-based valuation proxy', 'Provide formulas/measures of ROI.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (338, 'AGC4356', 4, '% of Latinx artists featured in exhibitions/performances at Bromo', 'Effectiveness', 'Percent of artists featured in exhibitions or performances who identify as Latinx/Hispanic.', 'Artist demographic self-reporting', 'Tamara Robinson / JaMel Johnson', 'DOF/COO', 'Annual', 'Nothing provided', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Bromo Seltzer Arts Tower', 'Artist intake and curatorial records', 'Inform equitable curatorial planning', NULL, 'FY26 target used while reporting is pending', 'Create a live tracker spreadsheet with this information, or even some kind of dashboard for internal reporting.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (339, 'AGC4356', 4, '% of total studio space rented', 'Output', 'Percent of total Bromo Seltzer Arts Tower studio space that is rented or leased during the reporting period.', 'Facilities lease records', 'Tamara Robinson / JaMel Johnson', 'DOF/COO', 'Quarterly', 'Nothing provided', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Bromo Seltzer Arts Tower', 'Studio lease tracking maintained by Facilities staff', 'Monitor occupancy trends and inform leasing strategy', NULL, 'Not applicable', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (340, 'AGC4356', 4, 'Annual attendance', 'Output', 'Total attendance served at Bromo Seltzer Arts Tower programs and events during the reporting period.', 'Facilities attendance logs', 'Tamara Robinson / JaMel Johnson', 'DOF/COO', 'Quarterly', 'Nothing provided', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Bromo Seltzer Arts Tower', 'Manual counts and post-event attendance estimates', 'Assess public engagement and program reach', NULL, 'Attendance estimates used when exact counts are unavailable', 'Create a master tracker for all events at the Tower.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (341, 'AGC4356', 4, '# of Baltimore City student participating in free school programs', 'Output', 'each student registered for a guided, self-led, or Discovery Visit. Does not include Teen labs, photography workship, Teen Takeover, Career Panels, or other free educatioal programs for students', 'tour booking data', 'Roz Kreizenbeck', 'Director of Education and Interpretation', 'Monthly', 'each number = one student', 'Increase', NULL, NULL, 'Count', NULL, 'Do you have a goal/target number of buses and/or schoolchildren served on these buses per year?', true, NULL, 'Education department; shared Google spreadsheet', 'Tour registration form, completed by teacher/educator', 'Shows how many City students are serviced; used to calculate percentage of total to ensure City students remain the highest served', NULL, NULL, 'Identify the speciifc process and locations within the sheet for pulling the total number of students participating in free school programs and how to filter for those who are Baltimore City students.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (342, 'AGC4356', 4, '# of schoolchildren served through the free bus subsidy program', 'Efficiency', '# of students from Title I or FARMS rating of 40% who were allocated bus subsidies for their Walters visit. Actual reimbursement timelines can vary', 'tour booking data, as requested by teachers.', 'Roz Kreizenbeck', 'Director of Education and Interpretation', 'Weekly', '1 bus = max of 40 students', 'Not Applicable', NULL, NULL, 'Count', NULL, 'Do you have a goal/target number of buses and/or schoolchildren served on these buses per year?', true, NULL, 'Education department; shared Google spreadsheet', 'Tour registration and bus request forms (teachers indicate the number of students they will bring)', 'Demonstrates need for bus subsidies to private donors; tracks reimbursements; ensures Baltimore City Title I schools receive priority', NULL, NULL, 'Identify the speciifc process and locations within the sheet for pulling the quantity of students on the buses approved for the free bus subsidy.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (343, 'AGC4356', 4, 'Total # individuals participating in education programs', 'Output', 'actual attendance (K-12 tours + programs, family programs, lectures, art making, performances, festivals, teen, college, and adult offerings)', 'multiple sources including program registration sheets, counts at programs which are recorded after each program', 'Laurel Miller', 'Chief Learning, Experience, & Community Engagement Officer', 'Monthly', 'Formula pending.', 'Increase', NULL, NULL, 'Count', NULL, 'Clarify whether the availability of the data is indeed monthly or if it''s quarterly as suggested in the Method of Collection response.', false, NULL, 'Education department; shared Google spreadsheet', 'each unit keep tracks of program participants and records it at least weekly in their own data tracker; this is then added at least quarterly', 'shows how many people take part in a structured educational program or tour at the Walters; attendance by program demonstrates effectiveness of each program in reaching audiences.', NULL, NULL, 'Identify the speciifc process for how to pull the number of individauls in edcuation programs in the Google sheet. Can it be calculated in one column or is it a sum of multiple sheets or tabs?', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (344, 'AGC4361', 4, '# of attendees attributed to In-House (non-VB) bookings', 'Output', 'This is the number of attendees to events that are attributed to "18 month business" that is booked by the BCC sales staff (not Visit Baltimore).', 'We receive the number of attendees from our clients, following the event.  It is then stored in our EMS.', 'Philip Costa', 'Deputy Director', 'We receive this info in the days following an event.', 'This is a simple addition of the attendance numbers from all confirmed events, after they occured. This data does not include events that were booked by VB.', 'Increase', NULL, NULL, 'Count', NULL, 'What is "18 month business" and why is it different from Visit Baltimore?', false, NULL, 'Event Management Software, virtual event files, and Power BI', 'We collect this data from our event clients.', 'This helps gauge goals and success of our internal sales team, and the ability to fill in gaps in our schedule with local/regional events.', NULL, NULL, 'Consider a way to weight attendees by the number of days they attend, similar to the suggestions around the "# of events within fiscal year" measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (345, 'AGC4361', 4, '# of events within fiscal year', 'Output', 'We are measuring the number of events held at the Baltimore Convention Center.', 'This comes from the number of contracted events that take place at the BCC. This information kept within our Event Management System (momentus) when booking and settling events.', 'Philip Costa', 'Deputy Director', 'This is updated in real time when an event is contracted, and is settled after the event occurs.', 'Count total', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Event Management System (momentus) when booking and settling events.', 'Sales/Contracting team inputs information when an event is contracted and "settled" after occuring', 'This data is used to compare the number events for year over year comparison, and quarter/month comparison.  This helps identify trends and "pace" for the number of events.  It helps support our sales team in their efforts.  With that being said, "not all events are created equal", because 1 event could be significantly smaller than another. So this is a guiding datapoint, it is not the only/entire story.', NULL, NULL, 'Could an additional or alternative measure be "# of event-days," factoring in the length of the event and weighting multi-day events more highly?', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (346, 'AGC4361', 4, 'FY revenue generated from events (in millions)', 'Outcome', 'This is the revenue generated by the BCC (through rent and ancillary charges) and the commissions that we receive from our service partners (food, av, internet, utilities).', 'This is stored in our event management software and is validated by our contract and commission reports/payments from service partners.', 'Philip Costa', 'Deputy Director', 'This revenue data is typically available in the weeks following an event once all bills are paid and settled from the BCC and it''s service partners.', 'This is added from our event invoices and commission revenue received', 'Increase', NULL, NULL, 'Currency', 'in millions', 'N/A', false, NULL, 'Event Management Software (momentus)', 'we receive this data from our billing/contracts with clients + receiving the commissions from our service partners based on their reported revenues', 'This is used to understand the economic impact of the BCC. This revenue is also what helps lower the deficit of the BCC that is paid by the City and State.  This information helps us know the return on investment and helps drive our sales/booking efforts.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (347, 'AGC4361', 4, 'Overall client satisfaction', 'Output', 'This is a weighted average from our event survey. After each event we send out our event survey to clients, asking about everything from the sales process through the event and post event process.  We receive results and create a weighted average from these different sections, which is reported as our overall client satisfaction.', 'Customer Satisfaction Surveys, which are filled out from clients after events', 'Philip Costa', 'Deputy Director', 'monthly, as completed by clients', 'This is a weighted average from various sections of the survey.  The weights are:
Sales Process=15%
Planning Process= 15%
Overall Experience= 17.5%
Onsite Experience= 15%
Partner Experience= 10%
AV= 5%
F&B= 10%
Telecom= 5%
IATSE= 2.5%
Utility= 5%', 'Increase', NULL, NULL, 'Count', NULL, 'How were the weights determined? Are the questions a 5-point Likert scale (strongly disagree to strongly agree)?', true, NULL, 'this data is stored in power bi', 'we email the survey to clients and follow up/encourage them to fill out the survey, by offering incentives to complete', 'This data is shared with staff and reviewed by leadership to find ways to improve our service provided to clients', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (348, 'AGC4361', 4, 'Total # of attendees within fiscal year', 'Output', 'This is the number of attendees that attend events held at the BCC. For a conference, this could be 1 person who attends a conference 3 days in a row (under one registration).  For a "public show" this may mean total visitors over the span of the event.', 'We receive this information from the event clients, and input it in our event management software. Our CSM''s request this information at the conclusion of an event.', 'Philip Costa', 'Deputy Director', 'We receive this information in the days/weeks following an event and input it into our EMS.', 'This is a simple addition from all confirmed events that have taken place.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Event Management Software (Momentus), virtual event files, and PowerBI.', 'We receive this information from the events, who have various ways of collecting this data.', 'We use this to help support economic impact calculations, drive sales efforts, and tell the impact of how many visitors are coming through the BCC and City.', NULL, NULL, 'Consider a way to weight attendees by the number of days they attend, similar to the suggestions around the "# of events within fiscal year" measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (349, 'AGC4381', 4, '# of clients enrolled in Homeless Prevention Services', 'Outcome', '# of clients who were actively enrolled in any homeless prevention program at any point during the reporting period', 'Homeless Management Information System (HMIS) Active Client List', 'Ernestina Simmons', 'Agency Director', 'Live', 'Unduplicated count of clients with active enrollments in homeless prevention at any point during the reporting period', 'Increase', NULL, NULL, 'Count', NULL, 'Why are individuals and households mixed into the generic term "client?"', true, NULL, 'HMIS', 'HMIS Data Entry', 'This measure uses HMIS enrollment data to track how many unique individuals and households received homeless prevention services during the reporting period', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (350, 'AGC4381', 4, '% of homeless households who are first time homeless', 'Outcome', '% of unique households  served who did not have a previous enrollment in ES, SH, TH or PH over the past 2 years', 'HUD System Performance Measure report-  5.2', 'Ernestina Simmons', 'Agency Director', 'Live', 'Deduplicating unique case IDs for households, percent of households who had an entry into ES, SH, TH or PH that didn''t have one in the past 2 years', 'Decrease', NULL, NULL, 'Percent', NULL, 'What are the "ES, SH, TH or PH" conditions?', false, NULL, 'HMIS', 'HMIS Data Entry', 'This measure uses HMIS history to identify households entering homeless services for the first time in the past two years.', NULL, 'N/A', 'Rather than say "first time homeless," explicitly title it "previously housed within prior 2 years" or something similar.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (351, 'AGC4381', 4, '% of persons who exit from street outreach to shelter, transitional housing or Permanent Housing', 'Outcome', '% of clients who have a successful exit from street outreach', 'HUD System Performance Measures report 7a.1', 'Ernestina Simmons', 'Agency Director', 'Live', 'Using HUD''s measure of Street outreach clients who exited to a PH, ES, SH, or TH destination', 'Increase', NULL, NULL, 'Percent', NULL, 'What are PH, ES, SH, or TH destinations? Additionally, what is the cadence for data updating?', true, NULL, 'HMIS', 'HMIS data entry', 'This measure uses HMIS exit destination data to track successful transitions from street outreach to shelter or housing. It helps evaluate outreach effectiveness in moving people off the street and into safer, more stable environments.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (352, 'AGC4381', 4, '% of Street Outreach enrollments with Coordinated Access Enrollment', 'Outcome', '% of street outreach clients with an enrollment in coordinated access', 'HMIS Active Client List', 'Ernestina Simmons', 'Agency Director', 'Live', '% of total number of unduplicated clients with street outrecah enrollments that also have CA enrollments', 'Increase', NULL, NULL, 'Percent', NULL, 'What constitutes coordinated access?', false, NULL, 'HMIS', 'HMIS Data Entry', 'This measure uses HMIS to determine how many outreach clients are also enrolled in Coordinated Access.
 It is used to assess how effectively outreach efforts are connecting people experiencing homelessness to the housing placement system.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (353, 'AGC4381', 4, 'Number of street outreach enrollments.', 'Outcome', '# of unduplicated clients  actively enrolled in any street outreach program at any point during the reporting period', 'HMIS Active Client List', 'Ernestina Simmons', 'Agency Director', 'Live', 'Unduplicated count of clients with active enrollments in street outreach at any point during the reporting period', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'HMIS', 'HMIS Data Entry', 'This measure uses HMIS enrollment data to count the number of unduplicated clients engaged through street outreach during the reporting period. It helps evaluate the scope of outreach activities', NULL, 'N/A', 'Make it "number of clients enrolled through street outreach."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (354, 'AGC4381', 4, 'Average length of time that persons are homeless in emergency shelter, housing and transitional housing projects', 'Outcome', 'Average length of time clients are continuously enrolled in ES, SH, and TH programs', 'HUD System performance Measures report 1a.2', 'Ernestina Simmons', 'Agency Director', 'Live', 'Using HUD''s measure, average length of time (in days) that clients are continuously enrolled between ES, SH and TH programs', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'HMIS', 'HMIS Data Entry', 'This measure uses HMIS enrollment dates to calculate the average number of days clients spend continuously enrolled in emergency shelter, safe haven, and transitional housing. It helps evaluate system efficiency and progress toward reducing the length of homelessness.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (355, 'AGC4381', 4, 'Point In Time (PIT) results for unsheltered and sheltered persons', 'Outcome', 'Count of sheltered (ES, SH, TH) and unsheltered persons in Baltimore City on a given night', 'Previous FY PIT report', 'Ernestina Simmons', 'Agency Director', 'Annually', 'PIT results for sheltered & unsheltered persons', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'HDX', 'Annual PIT count', 'This measure uses PIT data to track the total number of people experiencing homelessness, both sheltered and unsheltered, on a single night. It provides a system-wide snapshot used for federal reporting and long-term planning.', NULL, 'n/a', 'If possible, increase the frequency of collection. Also, given that there is already a measure capturing unsheltered persons, make this measure solely for sheltered persons.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (356, 'AGC4381', 4, '# of emergency shelter beds', 'Output', 'Total number of beds in ES projects', 'Previous FY Housing Inventory count', 'Ernestina Simmons', 'Agency Director', 'Annually', 'HIC inventory for total emergency shelter beds', 'Increase', NULL, NULL, 'Count', NULL, 'What qualifies as an emergency shelter versus other types of shelters?', false, NULL, 'HDX', 'Homless service providers provide data for housing inventory count', 'This measure uses the annual Housing Inventory Count to track the total number of emergency shelter beds available. It is used to monitor shelter capacity and guide system planning and Federal funding decisions.', NULL, 'n/a', 'If possible, increase the frequency of collection by mandating quarterly or monthly reports on # of shelter beds.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (357, 'AGC4381', 4, '% exit to permanent housing', 'Outcome', 'Percent of clients exited from TH, ES, and SH who exited to a PH destination', 'HUD System Performance Measures report 7b.1', 'Ernestina simmons', 'Agency Director', 'Live', 'Using HUD''s measure of percent of persons who exited from ES, SH, TH and RRH to a PH destination', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'HMIS', 'HMIS data entry', 'This measure uses HMIS exit destination data to track the percentage of clients leaving emergency shelter, transitional housing, or safe haven programs for permanent housing. It is used to assess how effectively temporary housing programs support housing placement.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (358, 'AGC4381', 4, '% of adults enrolled in temporary housing that increased their earned income', 'Outcome', '% of adults who were enrolled in TH, ES, or SH at any point in the reporting period who saw an increase to earned income including both those who left the program and those who stayed', 'HUD System Performance Measures report 4', 'Ernestina Simmons', 'Agency Director', 'Live', 'Percent of adults enrolled (leavers and stayers) that saw an increase in wage and non-wage income. Pull SPM for temporary housing. Add total leavers and stayers (4.1, 4.4) and divide by total adults with increased income (4.3, 4.6)', 'Increase', NULL, NULL, 'Percent', NULL, 'What is the reporting cadence for income data?', true, NULL, 'HMIS', 'HMIS data entry', 'This measure uses HMIS income data to track  changes in earned income for adults enrolled in housing programs. It is used to assess employment outcomes and economic progress among participants.', NULL, 'n/a', 'This metric should use a benchmark for increased income (10%, 25%) rather than just a simple "increased their earned income."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (359, 'AGC4381', 4, '% of adults enrolled in temporary housing that increased their non-employment income', 'Outcome', '% of adults who were enrolled in TH, ES, or SH at any point in the reporting period who saw an increase to non-employment income including both those who left the program and those who stayed', 'HUD system performance measures report 4', 'Ernestina Simmons', 'Agency Director', 'Live', 'Percent of adults enrolled (leavers and stayers) that saw an increase in wage and non-wage income. Pull SPM for temporary housing. Add total leavers and stayers (4.1, 4.4) and divide by total adults with increased income (4.3, 4.6)', 'Increase', NULL, NULL, 'Percent', NULL, 'What is the reporting cadence for income data?', true, NULL, 'HMIS', 'HMIS data entry', 'This measure uses HMIS non employment income data(SSI, SSDI, etc) to track changes in earned income for adults enrolled and leavers in temporary housing programs. It is used to assess employment outcomes and economic progress among participants.', NULL, 'n/a', 'This metric should use a benchmark for increased income (10%, 25%) rather than just a simple "increased their earned income."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (360, 'AGC4381', 4, 'Point In Time (PIT) results for unsheltered persons', 'Outcome', 'Count of unsheltered persons on a single night in Baltimore City', 'Previous FY PIT Report', 'Ernestina Simmons', 'Agency Director', 'Annually', 'PIT results for unsheltered persons', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'HDX', 'Annual PIT count', 'This measure uses annual PIT count data to track the number of people experiencing unsheltered homelessness on a single night. It is used to monitor trends in unsheltered homelessness and inform outreach and housing strategies.', NULL, 'N/A', 'If possible, increase the frequency of collection.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (361, 'AGC4381', 4, '# of permanent housing beds', 'Output', 'Total number of PSH and OPH beds', 'Previous FY Housing Inventory Count', 'Ernestina Simons', 'Agency Director', 'Annually', 'HIC inventory for total Permanent Supportive Housing and Other Permanent Housing beds', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'HDX', 'Housing providers provide count of beds for HIC', 'This measure uses the annual Housing Inventory Count (HIC) to track the total number of permanent housing beds available in the system. It is used to monitor system capacity and inform planning and resource allocation.', NULL, 'n/a', 'If possible, increase the frequency of collection.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (362, 'AGC4381', 4, '% homeless households retaining permanent housing', 'Outcome', '% of households who maintain their permanent housing  through out the reporting period either through staying in PH programs or exiting to a PH destination', 'HUD SPM 7b.2', 'Ernestina Simmons', 'Agency Director', 'Live', 'Raw data deduplicated based on household ID, to find % of  households who have maintained PH', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'HMIS', 'HMIS Data Entry', 'This measure uses HMIS household-level data to track whether households remain housed throughout the reporting period or exit to permanent housing destinations. It is used to assess housing stability and the effectiveness of permanent housing programs.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (363, 'AGC4381', 4, '% of adults enrolled in permanent housing that increased their earned income', 'Outcome', '% of adults who were enrolled in PH at any point in the reporting period who saw an increase to earned income including both those who left the program and those who stayed', 'HUD System Performance Measures report 4', 'Ernestina Simmons', 'Agency Director', 'Live', 'Percent of adults enrolled (leavers and stayers) that saw an increase in wage and non-wage income. Pull SPM for PSH & RRH. Add total leavers and stayers (4.1, 4.4) and divide by total adults with increased income (4.3, 4.6)', 'Increase', NULL, NULL, 'Percent', NULL, 'What is the reporting cadence for income data?', true, NULL, 'HMIS', 'HMIS data entry', 'This measure uses HMIS income data to track changes in earned income for adults enrolled in permanent housing. This measure is part of a broader set of metrics that assess the effectiveness of homeless service systesm in ending homelessness. The data collected for this measure helps HUD evaluate the progress of CoC Communities in addressing homelessness.', NULL, 'n/a', 'This metric should use a benchmark for increased income (10%, 25%) rather than just a simple "increased their earned income."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (364, 'AGC4381', 4, '% of adults enrolled in permanent housing that increased their non-employment income', 'Outcome', '% of adults who were enrolled in PH at any point in the reporting period who saw an increase to non-employment income including both those who left the program and those who stayed', 'HUD System Performance Measure report 4', 'Ernestina Simmons', 'Agency Director', 'Live', 'Percent of adults enrolled (leavers and stayers) that saw an increase in wage and non-wage income. Pull SPM for PSH & RRH. Add total leavers and stayers (4.1, 4.4) and divide by total adults with increased income (4.3, 4.6)', 'Increase', NULL, NULL, 'Percent', NULL, 'What is the reporting cadence for income data?', true, NULL, 'HMIS', 'HMIS data entry', 'This measure uses HMIS non employment income data(SSI, SSDI, etc) to track changes in earned income for adults enrolled and leavers in housing programs. It is used to assess employment outcomes and economic progress among participants.', NULL, 'n/a', 'This metric should use a benchmark for increased income (10%, 25%) rather than just a simple "increased their earned income."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (365, 'AGC4381', 4, '% of homeless households who return to a homeless services project within 2 years of an exit to permanent housing', 'Outcome', '% of households who return to  homelessness after exiting to PH two years prior or less', 'HUD System Performance Measures report 2', 'Ernestina Simmons', 'Agency Director', 'Live', 'Raw data deduplicated based on household ID, to find % of households who return to  homelessness after exiting to PH two years prior or less', 'Decrease', NULL, NULL, 'Percent', NULL, 'Why a 2 year lookback?', true, NULL, 'HMIS', 'HMIS Data entry', 'This measure evalutes the extet to which individuals and families who leave homelessness experience additional spells of homelessness. This measure tracks exits to permanent housing and subsequent returns to outreach, shelter, transitional housing, and safe havens. The measure aims to assess the effectiveness of the system in preventing homelessness and provide stable housing options.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (366, 'AGC4383', 4, '# of hearings conducted using Language Line interpretation services', 'Output', 'The number of hearings where an interpreter is used', 'System report', 'Richard Chambers', 'Deputy Director', 'monthly', 'System report', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'ECB''s case management system, which was built by BCIT.', 'Monthly report', 'The data is largely used to helps us determine necessary translation services as a whole. Additionally, it informs us of how to more equitably provide the hearing process to the most common LEP groups that engage our office.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (367, 'AGC4383', 4, '% of first hearings scheduled within 60 days', 'Efficiency', 'The percentage of people that are notified of their hearing date and time withing 60 days of submitting their hearing request.', 'System report', 'Brittany (Vendryes) Richardson & Becky Freeberger', 'Executive Director and Office Supervisor', 'ad hoc request', 'System report', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Mainframe', 'Report request from BCIT', 'This data helps us to see how quickly we are moving cases. We do not want people waiting too long for a hearing. Outside of the general anxiety caused by a long wait time, evidence can also get lost/become stale. Additionally, citations can be liens that hold up the sale of a property. We don''t want to impact property sales while the person waits to be heard.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (368, 'AGC4383', 4, '% of upheld appeals to the board', 'Effectiveness', 'Respondents who are unhappy with the hearing officer''s decision can appeal that decision to the Board. This measure tracks how often the Board agrees with the hearing officer''s decision.', 'Tracking Spreadsheet', 'Richard Chambers', 'Deputy Director', 'live', '# of upheld appeals / total # of appeals', 'Increase', NULL, NULL, 'Percent', NULL, 'How are the review requests received and ingested into the tracking document?', true, NULL, 'Shared Drive', 'Manually- We organize Board decisions by saving them in folders per year. We go through the folder when it''s time to report out.', 'We use the data to verify that the Board agrees with the decisions that are being made by the hearing officers.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (369, 'AGC4383', 4, 'Average # of days for the hearing officer to respond to assigned correspondence', 'Efficiency', 'The turnaround time from when the hearing officer is delegated a request to when their decision is sent.', 'Tracking spreadsheet', 'Becky Freeberger', 'Office Supervisor', 'live', 'Average # of days between the correspondence being flagged for hearing officer review and the Hearing Officer''s decision', 'Decrease', NULL, NULL, 'Count', NULL, 'How are the review requests received and ingested into the tracking document?', true, NULL, 'Shared Drive', 'Manual - we track when the request is received and when the decision is sent out', 'We use this data to track the efficiency of the process.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (370, 'AGC4383', 4, 'Average # of days to complete tax sale review', 'Efficiency', 'We are measuring turn around times for requests for review. Specifically reviewing', 'Tracking spreadsheet', 'Brittany Richardson or Becky Freebgerger', 'Executive Director and Office Supervisor, respectively.', 'annually - this is a seasonal program that occurs from Feb-May', 'Average # of days between a review request being submitted and the Hearing Officer''s decision', 'Decrease', NULL, NULL, 'Count', NULL, 'How are the review requests received and ingested into the tracking document?', true, NULL, 'Spreadsheet saved on a Shared Drive', 'Manual - we track when the request is received and when the decision is sent out', 'We use this to track the efficiency of the process since tax sale is a time-sensitive issue. If we are able to speed up our delivery of decisions, it gives people more time to pay citations or enter into a payment agreement.', NULL, 'n/a', 'Should there be a weighting towards the amount of money involved in the tax sale?', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (371, 'AGC4392', 4, '% of treasury reports submitted on time', 'Output', 'The percent of reports to the US Treasury that are submit on time.', 'Recovery Office', 'Alexander Rouse', 'Data Project Manager', 'Always available.  Calculated quarterly after each treasury report is submit.', '# of reports submitted to treasury on time / number of reports due to treasury', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'What is the reporting cadence?', false, NULL, 'US Treasury portal.', 'Calculating the # of reports submitted to treasury on time / number of reports due to treasury', 'It is to measure compliance with federal reporting standards.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (372, 'AGC4392', 4, 'ARPA funds expended', 'Output', 'The total amount of ARPA funds expended over the life of the grant.', 'Workday', 'Alexander Rouse', 'Data Project Manager', 'Monthly.', 'Total funds disbursed from the ARPA allocation provided to Baltimore City', 'Increase', NULL, NULL, 'Currency', NULL, 'N/A', false, NULL, 'Workday.', 'The Find Journal Lines report.', 'The ARPA funds need to be expended by December 31, 2026 and tracking this helps in ensuring all funds are spent by the dealine.', NULL, 'N/A', 'This should be a measure of spend-down rather than just dollars spent.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (373, 'AGC4392', 4, 'Number of performance/technical assistance meetings held per month', 'Output', 'The number of performance/technical assistance meetings held with recipients of ARPA funding.', 'Recovery Office Project Managers', 'Alexander Rouse', 'Data Project Manager', 'Aggregated quarterly.', 'Sum of all meeetings held between Recovery Office project managers and funding recipients', 'Not Applicable', NULL, NULL, 'Count', NULL, 'Are these meetings required or upon request of the grant receipients?', false, NULL, 'Microsoft calendars.', 'Project managers provide the number of meetings to the data project manager to be calculated.', 'The data measures the levels of interaction between projects and ARPA funding recipients over time.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (374, 'AGC4392', 4, 'Number of small businesses served', 'Output', 'Number of small businesses receiving funds from ARPA.', 'Treasury Report', 'Alexander Rouse', 'Data Project Manager', 'Monthly.', 'Total number of small businesses served ARPA funded projects.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'The quarterly treasury report.', 'ARPA funded projects submit data monthly or quarterly.', 'The data tracks support provided to small businesses which were heavily impacted by the COVID19 pandemic.', NULL, 'N/A', 'This should be a measure of the average level of monetary support given to small businesses rather than a raw count of the number of small businesses.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (375, 'AGC4392', 4, 'Total followers on Instagram, Twitter, and LinkedIn', 'Outcome', 'Total followers from Instagram, Twitter (now X), and LinkedIn combined.', 'Social Media platforms', 'Alexander Rouse', 'Data Project Manager', 'Live, but it is recorded quarterly when the measure is aggregated.', 'Sum of followers on each platform', 'Increase', NULL, NULL, 'Count', NULL, 'Why was this added as a metric? What part of the mission does this align with?', true, NULL, 'The office social media accounts', 'Collecting individual totals from each apps metrics', 'It measures the reach of the offices social media content.', NULL, 'N/A', 'If kept, should be the number of unique followers across the 3 identified platforms to account for duplication.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (376, 'AGC4500', 4, '# of students attending non-traditional high school accessing workforce development services through the YO Academy', 'Output', 'Count of unique students referred by BCPS who received job exploration or placement assistance from YO Academy', 'Kidsmart', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Unique count of Referral IDs associated with "Futures - Monthly Report" for site "YO Academy" during the period of analysis', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Kidsmart', 'Staff enter into system', 'MOED maintains a contract with BCPS to support a specific number of students. This information is used to show MOED is fulfilling the requirements of this contract.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (377, 'AGC4500', 4, '% of Baltimore City School enrolled middle or high school students who have had a touchpoint with a Career Coach', 'Effectiveness', 'Percent of students who attended an workshop or event hosted by a Career Coach or received one-on-one assistance from a Career Coach', 'AppSheet + SchoolLinks', 'James Hughes', 'Data Analyst, Blueprint', 'Live', 'Number of non-chronically absent BCPS students with a touchpoint with a Career Coach divided by number of non-chronically absent students', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'AppSheet + SchoolLinks', 'Students provide "Exit Tickets" from attended events or staff enter information directly into the system', 'BluePrint Accountability and Implementation Board, which funds the initiative, includes it as a required metric for local districts to report', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in AppSheet +SchoolLinks.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (378, 'AGC4500', 4, '% of enrolled Baltimore City Public Schools students (grades 6-12) who have completed or are on track to complete a post-secondary plan', 'Effectiveness', 'Percent of students with a complete post-secondary plan or who attended all workshops expected for their grade level as part of plan development', 'AppSheet + SchoolLinks', 'James Hughes', 'Data Analyst, Blueprint', 'Live', 'Number of non-chronically absent BCPS students who have completed all exit tickets described in the scope and sequence for their grade level divided by number of non-chronically absent students', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'AppSheet + SchoolLinks', 'Students provide "Exit Tickets" indicating attendance at events and providing information to support plan development', 'Blueprint Accountability and Implementation Board, which funds the initiative, includes it as a required metric for local districts to report. Post-Secondary Plan completion is one of the few outcomes described in Blueprint legislation.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in AppSheet +SchoolLinks.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (379, 'AGC4500', 4, '% of students who are placed in an unsubsidized job, participate in work study, job shadow, or internship including a summer subsidized job', 'Effectiveness', 'Portion of unique clients who received job exportation or placement assistance from YO Academy, who are placed in an unsubsidized job, work study, job shadow, internship, or summer job', 'Kidsmart', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Count of individuals with an applicable placement or work experience activity from YO Futures Report divided by unique count of individuals in the YO Futures report for the period of analysis', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Kidsmart', 'Staff enter into system', 'MOED maintains a contract with BCPS to support a specific number of students. This information is used to show MOED is fulfilling the requirements of this contract. It demonstrates how effectively MOED is able to assist individuals in attaining work experiences.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (380, 'AGC4500', 4, '# of Baltimore City participants receiving Mayor''s Office of Employment Development/ Workforce Reception Center Services though the agreement with Baltimore City Department of Social Services', 'Output', 'Number of individuals referred by Baltimore City Department of Social Services provided workforce services by MOED', 'State Department of Human Services  WORKS System', 'Kim Neal', 'Systems Technician II', 'Monthly', 'Number of unique individuals served in period of analysis', 'Not Applicable', NULL, NULL, 'Count', NULL, 'Beyond being required to track this for reporting, indicating how it is used to inform programming and strategy would be helpful.', false, NULL, 'TANF Current TANF Flex Report', 'Staff enter into system', 'MOED maintains a contract with Baltimore City DSS, that requires this metric for reporting. This fulfills reporting requirements.', NULL, 'N/A', 'Provide clarification between TANF and the State Department of Human Services  WORKS System.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (381, 'AGC4500', 4, '% of participants that gain employment remained employed after 6 months', 'Outcome', 'Portion of individuals referred by Baltimore City Department of Social Services provided workforce services by MOED who maintained employment 6 months after starting work', 'State Department of Human Services  WORKS System', 'Kim Neal', 'Systems Technician II', 'Monthly', 'Number of individuals where 6 months elapsed since placement who were working divided by number of individuals where 6 months elapsed since placement in reporting period', 'Increase', NULL, NULL, 'Percent', NULL, 'Beyond being required to track this for reporting, indicating how it is used to inform programming and strategy would be helpful.', false, NULL, 'TANF Current TANF Flex Report', 'Staff enter into system', 'MOED maintains a contract with Baltimore City DSS, that requires this metric for reporting. This fulfills reporting requirements.', NULL, 'N/A', 'Provide clarification between TANF and the State Department of Human Services  WORKS System.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (382, 'AGC4500', 4, '% of participants who remain employed after 6 month continue employment for 12 months', 'Outcome', 'Portion of individuals referred by Baltimore City Department of Social Services provided workforce services by MOED who maintained employment 12 months after starting work', 'State Department of Human Services  WORKS System', 'Kim Neal', 'Systems Technician II', 'Monthly', 'Number of individuals where 12 months elapsed since placement who were working divided by number of individuals where 12 months elapsed since placement in reporting period', 'Increase', NULL, NULL, 'Percent', NULL, 'Beyond being required to track this for reporting, indicating how it is used to inform programming and strategy would be helpful.', false, NULL, 'TANF Current TANF Flex Report', 'Staff enter into system', 'MOED maintains a contract with Baltimore City DSS, that requires this metric for reporting. This fulfills reporting requirements.', NULL, 'N/A', 'Provide clarification between TANF and the State Department of Human Services  WORKS System.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.816075'),
    (383, 'AGC4500', 4, '# of Baltimore City residents receiving Intensive services through the Community Job Hubs', 'Output', 'Number of individuals receiving one-on-one career services from Community Job Hub Career Development Facilitators', 'MD Workforce Exchange', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Unique count of State IDs tied to services deemed intensive services with Actual Begin Dates during the period of analysis that are delivered as part of the Community Jobs Hub Programs in MWE', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'Staff enter data into system', 'Demonstrates scale of intensive services delivered by CJH', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in MD Workforce Exchange', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (384, 'AGC4500', 4, '# of Baltimore City residents that obtain job placements through the Adult Service Career Centers including the Community Job Hubs', 'Outcome', 'Number of individuals receiving placements tied to a Community Job Hub, Northwest Career Center, or Eastside Career Center', 'MOED Placement Data System', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Unique count of Client ID numbers tied to placements with start dates that occurred in the period of analysis', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'MOED Placement Data System', 'Staff enter data into system', 'Topline outcome of center work that is used to understand net impact of agency', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in MOED Placement Data System', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (385, 'AGC4500', 4, '# of City residents who visited Community Job Hubs', 'Output', 'Number of individuals receiving career services by the community job hub', 'MD Workforce Exchange', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Unique count of State IDs tied to services with Actual Begin Dates during the period of analysis that are delivered as part of the Community Jobs Hub Programs in MWE', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'Staff enter data into system', 'Demonstrates scale of services delivered by CJH', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in MD Workforce Exchange', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
