    (387, 'AGC4500', 4, '% of jobseekers who commence service delivery from the one stop centers and are also employed one year later', 'Outcome', 'Portion of individuals who were served by MOED Career Center Network in Wagner Peyser programming who were employed in the 4thcalendar quarter following their exit from services between 1.5 and 2.75 years ago', 'Data provided by the MD State Department of Labor based on participant data in the Maryland Workforce Exchange and unemployment insurance wage record match', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Quarterly', 'For each person who exited Wagner Peyser services in MD Workforce Exchange between 6 and 10 quarters ago, what portion of them were employed in the 4th quarter after their exit based on wage records and supplemental employment reports', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'MD DOL calculates and sends a report each quarter', 'Federal WIOA regulations mandate these outcomes are reported on a quarterly basis. Consistent inability to hit state-mandated goals may yield greater oversight from state and risk federal funding.', NULL, 'Reports can be run in MWE to estimate what outcomes may be for upcoming quarters', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (388, 'AGC4500', 4, '% of jobseekers who commence service delivery from the one stop centers and obtain employment and remain employed for at least 120 days', 'Outcome', 'Portion of individuals who were served by MOED Career Center Network in Wagner Peyser programming who were employed in the 2nd calendar quarter following their exit from services between 1 and 2.25 years ago', 'Data provided by the MD State Department of Labor based on participant data in the Maryland Workforce Exchange and unemployment insurrance wage record match', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Quarterly', 'For each person who exited Wagner Peyser services in MD Workforce Exchange between 4 and 8 quarters ago, what portion of them were employed in the 2nd quarter after their exit based on wage records and supplemental employment reports', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'MD DOL calculates and sends a report each quarter', 'Federal WIOA regulations mandate these outcomes are reported on a quarterly basis. Consistent inability to hit state-mandated goals may yield greater oversight from state and risk federal funding.', NULL, 'Reports can be run in MWE to estimate what outcomes may be for upcoming quarters', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (389, 'AGC4500', 4, '# of Baltimore City returning citizens who receive employment assistance services through the Re-entry Center', 'Output', 'Number of individuals who were justice involved that received any services from the Northwest Career Center Re-Entry Program', 'MD Workforce Exchange', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Unique count of State ID for individuals with services tied to MOED Re-Entry Programs whose Actual Begin Date is in the period of analysis', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'Staff enter into system', 'MOED maintains a contract with the Department of Public Safety and Correction Services to provide services, that requires this metric for reporting. This fulfills reporting requirements.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data for the MOED Re-entry Program data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (390, 'AGC4500', 4, '# of job ready Baltimore City returning citizens who received at least one service and obtain employment', 'Outcome', 'Number of individuals who were justice-involved and served by Northwest Career Re-Entry Programs who have a placement following service delivery', 'MOED Placement Data System; MD Workforce Exchange', 'Jonathan Smeton Devenport', 'Director of Performance, Evaluation, Data, & Support', 'Live', 'Number of unique justice-involved individuals with a placement in MOED placement system where a service in MWE for MOED Re-Entry Programs preceded or aligned with the date of the placement during the period of analysis.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'MOED Placement Data System; MD Workforce Exchange', 'Staff enter data into systems', 'MOED maintains a contract with the Department of Public Safety and Correction Services to provide services, that requires this metric for reporting. This fulfills reporting requirements.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in MD Workforce Exchange/MOED Placement Data System.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
