    (395, 'AGC4500', 4, '# of Baltimore City youth ages 14-21 offered paid, summer work experience through YouthWorks', 'Output', 'Number of unique individuals offered a YouthWorks job for the session that overlaps the period of analysis', 'YouthWorks Digicon System', 'Diautonia Saunders', 'MIS Supervisor', 'Live', 'Unique count of Registration IDs that have a site assignment or indication of a status change on in their record', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'YouthWorks Digicon System', 'Staff enter data into systems', 'YouthWorks monitors offers to ensure alignment with budget and employer capacity', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in YouthWorks Digicon System.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (396, 'AGC4500', 4, '% of employers who said they would recommend YouthWorks to other orgs seeking entry-level employees', 'Effectiveness', 'Portion of employers surveyed who would recommend YouthWorkers to other employers', 'YouthWorks Post Program Employer Survey', 'Elle Burton', 'Data Specialist', 'Collected only once per year', 'Number of surveyed YW hosts/employers who "Agreed" or "Strongly Agreed" with the statement, "I would recommend YouthWorks to a colleague or partner organization" divided by number of employers surveyed', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'YouthWorks Post Program Employer Survey', 'Employers complete surveys following end of YouthWorks period', 'YouthWorks reviews employer satisfaction to understand how best to recruit, retain, and support employment partners each summer', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (397, 'AGC4500', 4, '% of youth who increase their work readiness', 'Effectiveness', 'Portion of youth surveyed who stated a gain in work readiness', 'YouthWorks Post Program Participant Survey', 'Elle Burton', 'Data Specialist', 'Collected only once per year', 'Number of surveyed YouthWorkers who selected "Yes" to the question, "Do you feel like you gained new skills from your work experience?" divided by the number of surveyed YouthWorkers', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'YouthWorks Post Program Participant Survey', 'YouthWorkers complete surveys in last week or after YouthWorks summer job', 'YouthWorks reviews youth skill gain perceptions to understand site selection and supports they can provide to participants during the summer', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (398, 'AGC4500', 4, '# of participants served', 'Output', 'Number of individuals enrolled in WIOA in-school or out-of-school youth training', 'MD Workforce Exchange', 'Diautonia Saunders', 'MIS Supervisor', 'Live', 'Number of unique State IDs tied to the WIOA Youth Program in MWE for the period of analysis', 'Not Applicable', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'Staff enter into system based on contracted provider reports', 'MOED maintains a contract with MD DOL to support a specific number of trainees. This information is used to show MOED is fulfilling the requirements of this contract.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in in MD Workforce Exchanget to pull State IDs for WIOA participants', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (399, 'AGC4500', 4, '% of enrolled youth who earn an occupational or educational credential by the end of the program', 'Effectiveness', 'Number of individuals enrolled in WIOA in-school or out-of-school youth training that have received an recognized credential', 'MD Workforce Exchange', 'Diautonia Saunders', 'MIS Supervisor', 'Live', 'Number of unique State IDs tied to the WIOA Youth Program who have a Credential after enrollment in MWE for the period of analysis', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'Staff enter into system based on contracted provider reports', 'MOED maintains a contract with MD DOL to attain a certain credential rate. This information is used to show MOED is fulfilling the requirements of this contract.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in MD workforce Exchange to calculate the numerator and denominator.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (400, 'AGC4500', 4, '% of youth enrolled in an educational or occupational training program who receive an academic gain, training milestone or skills progression by the end of the year', 'Effectiveness', 'Portion of individuals enrolled in WIOA in-school or out-of-school youth training that have received a Measurable Skills Gain', 'MD Workforce Exchange', 'Diautonia Saunders', 'MIS Supervisor', 'Live', 'Number of unique State IDs tied to the WIOA Youth Program who have a Measurable Skill Gain after enrollment in MWE for the period of analysis', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'MD Workforce Exchange', 'Staff enter into system based on contracted provider reports', 'MOED maintains a contract with MD DOL to attain a certain measurable skills gain rate. This information is used to show MOED is fulfilling the requirements of this contract.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the numerator and denominator.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (401, 'AGC5500', 4, '# of Collaborative meetings, forums & presentations convened between community and the Wage Commission', 'Output', 'This measure tracks the number of collaborative meetings, forums, and presentations convened by the Wage Commission with community members and stakeholders. These activities support education, outreach, and engagement by increasing awareness of wage laws, worker protections, and compliance requirements, while strengthening relationships that promote proactive compliance and trust.', 'Wage Matrix', 'Aracely Stafford', 'Chief, Wage Commission', 'Data for this measure is available in real time through internal tracking of meetings, forums, and presentations as they occur, allowing for ongoing and accurate reporting of engagement activities.', 'Wage Matrix', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Wage tracking system, wage matrix', 'Engagement activities are recorded in real time through internal logs and calendars, with each meeting, forum, or presentation documented as it occurs.', 'The data is used to track outreach and engagement activity, assess community participation, and evaluate the Commission’s efforts to increase awareness of wage laws and worker protections.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (402, 'AGC5500', 4, '# of late payroll violations issued', 'Output', 'This measure tracks the number of late payroll violations issued by the Wage Commission during the reporting period. A reduction in late payroll violations demonstrates the Commission’s proactive efforts to ensure contractor compliance, including early outreach, guidance, and monitoring to promote timely payroll submissions.', 'Wage Matrix', 'Aracely Stafford', 'Chief, Wage Commission', 'Data for this measure is readily available through weekly violation reports generated by the Wage Commission, which capture all late payroll violations issued during the reporting period.', 'Wage Matrix', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Payroll compliance software (Lcp Tracker) Wage Matrix', 'Data is collected through reports generated from the payroll compliance software. Late payroll submissions are identified through these reports, and violations are then issued directly to each non-compliant contractor.', 'The data is used to identify late payroll submissions, issue violations to non-compliant contractors, monitor compliance trends, and evaluate the effectiveness of proactive enforcement efforts.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (403, 'AGC5500', 4, '% of restitution collected', 'Outcome', 'This measure tracks the percentage of restitution collected for wage enforcement cases that have been fully resolved and closed. A case is considered compliant only after all restitution owed to impacted workers has been collected in full.', 'Wage Matrix', 'Aracely Stafford', 'Chief, Wage Commission', 'Data for this measure is available in real time through the Wage Commission’s case tracking and payment verification systems. Restitution amounts are recorded and updated as payments are received.', 'Wage Matrix. (Total restitution collected ÷ Total restitution owed for closed cases) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Wage Commission’s case tracking system, Wage matrix.', 'Restitution payments are recorded in real time in the case tracking system and verified before a case is closed.', 'Restitution data is used to confirm that workers have been fully paid before cases are closed, to monitor enforcement effectiveness, and to report performance outcomes related to wage recovery.', NULL, 'Confirmation of case closure with verified restitution payment is used as a proxy for full restitution collection when reporting detailed payment data is not required.', 'Identify the speciifc reports and locations for pulling the data in Wage Matrix to calculate the numerator and denominator.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (404, 'AGC5500', 4, '% of wage cases closed in under 6 months', 'Efficiency', 'This measure tracks the percentage of wage enforcement cases that are fully resolved and closed within six (6) months of intake. A case is considered closed only after impacted workers have received all restitution owed and any applicable penalties assessed for violations have been paid to the City.', 'Wage Matrix', 'Aracely Stafford', 'Chief, Wage Commission', 'Data is available through the Wage Commission’s case management and enforcement tracking systems. Case intake dates, closure dates, restitution payments to workers, and penalty payments to the City are documented and tracked for each case.', 'Wage Matrix (Number of wage enforcement cases closed within six (6) months ÷ Total number of wage enforcement cases closed) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Wage Commission''s case tracking system, Wage Metrix.', 'Staff record when a case is opened and closed, confirm that workers have received all restitution, and verify that any penalties owed to the City have been paid. This information is use to calculate and report case closure timelines.', 'The case intake date is used as the starting point to measure how long it takes to resolve a case. The case closure date is used to confirm when the investigation is complete and all restitution and penalties have been paid. The time between these two dates is used to determine whether a case was closed within six (6) months for performance reporting purposes.', NULL, 'Real-time case activity—such as documented communications, enforcement actions, and confirmation of restitution and penalty payments—is used as a proxy to monitor case progress and timely resolution when reporting by formal time intervals is not required.', 'Identify the speciifc reports and locations for pulling the data in Wage Matrix to calculate the numerator and denominator.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (405, 'AGC5500', 4, '# of existing or proposed policies, programs, or legislation reviewed through an equity lens', 'Output', 'Any instance in which the referenced Commission members or staff participated in review and comment on a policy or legislative matter. Commissions include Women''s Commission, Veteran''s Commission, Mayor''s Commission on Disabilities, and Equity Coordinator Monthly meeting.', 'MOGR City Council Teams Channel, MGA Egagifii Software', 'Zachary Wellman', 'Equity Legislative Analyst', 'Monthly', 'Tracking the number of bills assigned to OECR by MOGR.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Microsoft Teams, Airtable, and Engagifii software.', 'Any instance in which the referenced Commission members or staff participated in review and comment on a policy or legislative matter.', 'Ensure compliance with CB18-0223 Equity Assessment Program.', NULL, NULL, 'Identify the speciifc reports and locations for pulling the data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (406, 'AGC5500', 4, '# of public meetings and forums, or outreach events held or participated in by the service', 'Output', 'Any public meeting or outreach event hosted, partnered on or attended where education or resources about the referenced Commission were made available for the public. Commissions include Women''s Commission, Veteran''s Commission, Mayor''s Commission on Disabilities and Equity Coordinators Monthly Meetings.', 'Events listed on Outlook calendar for office and validated by personal attendance at the event.', 'Kristerfer Burnett', 'Divison Chief', 'Monthly', 'Number of events in Outlook calendar.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Outlook and Sharepoint', 'Events listed on Outlook calendar for office and validated by personal attendance at the event.', 'Data is used to track engagement of Commission members and the public.', NULL, NULL, 'There needs to be a data tracking mechanism where the data is stored and can be pulled that''s not just referencing Outlook calendars.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (407, 'AGC5500', 4, '# of agency trainings provided on anti-discrimination and harassment', 'Output', 'Total number of structured training sessions (in‑person or virtual) provided by the agency during the fiscal year where the primary focus is anti‑discrimination, harassment prevention, and/or related civil rights obligations, using a defined curriculum or agenda.', 'Case Log One drive', 'Danielle Burton', 'Chief', 'Annually', 'Each distinct training session delivered by the agency within the fiscal year.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Training and outreach data are stored in the agency’s designated tracking system (e.g., training/outreach log, learning management system, or shared spreadsheet) maintained by the education and outreach program.', 'Staff enter each anti‑discrimination and harassment training into the tracking system, recording at minimum: date, title/topic, audience type, delivery method (in‑person/virtual), and whether the training was internal or external.', 'To support reports to City leadership and the public by documenting non‑enforcement work that promotes equitable, harassment‑free environments.', NULL, NULL, 'Identify the speciifc fields and instructions for pulling the data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (408, 'AGC5500', 4, '# of education and outreach meetings', 'Output', 'How CRC is engaging with the community', 'Outreach Log One drive', 'Danielle Burton', 'Chief', 'Live', 'Outreach Log One drive', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'One drive outreach and education log', 'Sign in sheets, event attendance', 'To identify gaps in engagement by geography, population, or sector and prioritize future outreach to under‑served neighborhoods and protected classes.', NULL, NULL, 'Identify the speciifc fields and instructions for pulling the data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (409, 'AGC5500', 4, '# of informational and public hearings', 'Output', 'Total number of informational, investigative, and other public hearings or briefings convened by the Commission or a designated panel', 'Outreach Log One drive', 'Danielle Burton', 'Chief', 'Data is collecteed live', 'Outreach Log One drive', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'One drive excel spreadsheet', 'Event attendance sheet', 'To show city leadership and the public the level of Commission activity in examining systemic civil rights issues through public, on‑the‑record proceedings.', NULL, NULL, 'Identify the speciifc fields and instructions for pulling the data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (410, 'AGC5500', 4, '# of total complaints authorized closed annually', 'Output', 'Total number of complaints for which the agency:

(1) formally authorized the complaint for investigation (or equivalent “accepted” status), and

(2) recorded a final closure during the fiscal year (e.g., no cause, cause/conciliation, settlement, withdrawal, administrative closure, hearing decision).', 'Case‑management system fields capturing complaint status, authorization date/status, and closure date/status.', 'Danielle Buton', 'Chief', 'Where authorization and closure statuses/dates are consistently recorded, the annual count can be produced reliably and, if needed, broken out by program area (employment, housing, public accommodations, etc.).', 'Each distinct complaint that has both been authorized and closed.', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Complaint data are stored in the agency’s electronic case‑management system, which tracks each complaint’s status, authorization decision, and closure information. As well as the EEOC case-management system', 'For each complaint, staff record key events in the case‑management system, including:
Date and status when the complaint is authorized (accepted) for investigation, and

Date and status when the complaint is closed (e.g., no cause, cause/conciliation', 'To monitor workload management: comparing complaints closed to complaints received each year and to prior years.', NULL, NULL, 'Identify the speciifc fields and instructions for pulling the data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (411, 'AGC5500', 4, '% of complaints closed within 1 year of authorization', 'Efficiency', '% of complaints closed within 1 year of authorization', 'Case Log One drive', 'Danielle Burton', 'Chief', 'Annually', 'total number of cases closed within 1 year / total number of cases', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Case management systems  EEOC-ARC and Creatio', 'Case management system used to track complaint lifecycle (with fields such as authorization date, closure date, and closure status).', 'To monitor trends in processing time, identify bottlenecks, and set targets for improving the share of cases closed within one year of authorization', NULL, NULL, 'Identify the speciifc fields and instructions for pulling the data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (412, 'AGC5500', 4, '# of meetings, presentations, and outreach sessions held', 'Output', 'Total number of PAD-led meetings, presentations, and outreach sessions held during the reporting period. This includes ACC meetings, PAB meetings (including emergency meetings), and PAD outreach events.', 'Sharepoint', 'Marlon Marion', 'Chief of Police Accountibility Division', 'Live in SharePoint; updated after each event.', 'The total number of folders created during the reporting period is used to calculate the number of meetings/presentations/outreach sessions held. PAD also provides regular updates to the External Affairs Division, which serves as an additional log/verific', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'Sharepoint', 'Each week, PAD creates a SharePoint folder for each meeting, presentation, and outreach event.', 'This measure tracks PAD’s engagement and operational activity by documenting the number of meetings, presentations, and outreach sessions held.', NULL, NULL, 'As noted in the Measure Improvement column, a standardized tracker as opposed to countng Sharepoint folders would be a much more effective way to track this data.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (413, 'AGC5500', 4, '% of Cases returned with either a request for more information or a disciplinary recommendation under 30 days of receipt from the Law Enforcement Agency', 'Efficiency', 'Percent of Cases returned with either a request for more information or a disciplinary recommendation under 30 days of receipt from the Law Enforcement Agency', 'CMTS', 'Marrlon Marion', 'Chief of Police Accountability Division', 'Weekly', '(Number of cases returned by the LEA within 30 days with either a request for additional information or a disciplinary recommendation ÷ Total number of cases received by the LEA) × 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CMTS', 'A query is run in CMTS to pull the total number of cases received by the LEA and the number of those cases returned within 30 days with either a request for additional information or a disciplinary recommendation.', 'This measure is used to track timeliness of LEA case processing and responses. It helps identify delays and improve accountability by ensuring cases are returned within 30 days with either a request for additional information or a disciplinary recommendation.', NULL, NULL, 'More information on the query and where to use the query in CMTS would be helpful.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (414, 'AGC5500', 4, '% of Complaints received directly by the Police Accountability Board that are forwarded to the relevant Law Enforcement Agency under three (3) days', 'Efficiency', 'Percent of complaints received directly by PAB that are forwarded to the relevant LEA within three (3) calendar days of PAB receipt.', 'CMTS', 'Marlon Marion', 'Chief of Police Accountability Division', 'Live (tracked in CMTS and reported quarterly).', 'We used CMTS queries to count total complaints received and the number forwarded within three (3) days, then calculated the percentage of timely forwards: (Complaints forwarded within 3 days ÷ total complaints received) × 100.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'CMTS (Complaint Management Tracking System).', 'The Intake Specialist records in CMTS the date the Police Accountability Board forwards the complaint to the relevant law enforcement agency.', 'This measure tracks PAB timeliness and operational compliance to ensure complaints move quickly to the correct LEA for action and oversight.', NULL, NULL, 'More information on the query and where to use the query in CMTS would be helpful.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (415, 'AGC5700', 4, '% of items scheduled for UDAAP review within 60 days', 'Effectiveness', 'The share of items scheduled for Urban Design and Architecture Advisory Panel (UDAAP) review within 60 days measures the responsiveness of program staff to applicant requests. The measure calculation is based on date of receipt of complete final plans submittal and the date staff schedule a project for UDAAP review (not the panel meeting date).', 'Internal tracking spreadsheet; file "DOP-LUUD/03_UDAAP/UDAAP-Project-Tracking.xlsx"', 'Eli Pousson', 'Data Lead', 'Monthly', '[# of items scheduled for UDAAP review within 60 days] / [Total # of items scheduled for UDAAP review]', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the 60-day expectation communicated to the requestor? Is there a separate expectation for how long to actually conduct the review?', true, NULL, 'DOP-LUUD SharePoint site', 'The Urban Design Team Principal routinely updates a tracking spreadsheet for UDAAP agenda items to record the date applicants submit plans for review and the scheduled date of the UDAAP review meeting.', 'Program staff monitor the timeliness of scheduling for UDAAP items as part of general operations.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (416, 'AGC5700', 4, '% of recommendations on BMZA appeals submitted two business days prior to hearing.', 'Efficiency', 'The share of staff recommendations on Board of Municipal and Zoning Appeals (BMZA) cases measures the timeliness of staff review which may impact the ability of appellants to prepare in advance for the BMZA hearing on their case. Typically, BMZA hearings are scheduled on Tuesdays and staff submit reports by uploading the files to the BMZA website by the Friday prior.', 'Internal trInternal tracking spreadsheet, "BMZA Log 2023 Onward.xlsx"', 'Eli Pousson', 'Data Lead', 'Monthly', '[# of recommendation reports on BMZA appeals submitted 2 business days prior to scheduled hearing] / [Total # of recommendation reports submitted to BMZA]', 'Increase', NULL, NULL, 'Percent', NULL, 'Are these recommendations given to BMZA or the appellant?', true, NULL, 'Planning directory in Baltimore City network file server', 'The designated BMZA Liaison routinely updates a tracking spreadsheet for appeals planned/scheduled for BMZA hearings.', 'Supervisors for the BMZA Liaison staff routinely review the timeliness of recommendation reports as part of general operations.', NULL, 'N/A', 'Consider adding "at least" prior to the "two business days" in the measure name.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (417, 'AGC5700', 4, '% of subdivision reviews receiving Planning Commission review within 45 days', 'Efficiency', 'The share of subdivision applications with completed submissions scheduled for required review by the Planning Commission within 45 days (approx. 6-7 weeks) measures the responsiveness of Subdivision Program staff. The calculation of this measure is based on date a complete final plans submittal is received by staff and the date a program is scheduled for Planning Commission review (not the meeting date itself).', 'Internal tracking spreadsheet, "Subdivision Index - 2011 to Now.xlsx"', 'Eli Pousson', 'Data Lead', 'Monthly', '[# of subdivision applications reviewed by Planning Commission review within 45 days of final plan submission] / [# of subdivision applications reviewed by Planning Commission]', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the 45-day expectation communicated to the requestor? Is there a separate expectation for how long to actually conduct the review?', true, NULL, 'Planning directory in Baltimore City network file server', 'Subdivision Program staff routinely update a tracking spreadsheet with details on the subdivision application and key dates in the review/approval process.', 'Supervisors for the Subdivision Program staff routinely review the status of applications to ensure timely review as part of general operations.', NULL, 'N/A', 'If the relevant date is not the actual review but the scheduling of the review, change the measure name to "% of subdivision reviews scheduled for Planning Commission review within 45 days."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (418, 'AGC5700', 4, '% of completed Authorization-to-proceed applications processed within two business days', 'Efficiency', 'The share of Authorization-to-proceed applications that are processed (receive a preliminary review) within two business days measures the responsiveness of staff to permit applications in CHAP Historic Districts. Note that two business days may translate to four or five calendar days depending on the date an application is received relative to the weekends and holidays.', 'Internal Authorization-to-Proceed tracking spreadsheet on DOP-CHAP SharePoint site; Filed authorization-to-proceed documents provide an alternate data source', 'Eli Pousson', 'Data Lead', 'Live', '[# of authorization-to-proceed applications processed w/in 2 business days] / [Total # of authorization-to-proceed applications received and processed]', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'DOP-CHAP SharePoint site', 'Planners in the Historical and Architectural Preservation division collaboratively maintain a Microsoft Excel workbook that tracks basic details for each Authorization-to-Proceed application and staff review (including the application dates and review dat', 'Division leadership added a field in the staff tracker to show the number of days to process the application in spring 2025. Staff routinely review the tracking spreadsheet used as a data source as part of reviewing authorization-to-proceed application.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (419, 'AGC5700', 4, '% of preliminary reviews completed for tax credit applications within 30 business days', 'Efficiency', 'The share of preliminary reviews for CHAP Historic Tax Credit applications completed within 30 business days (up to 38 calendar days including weekends and holidays) of the completion of the application. An application is complete when all application materials for a project have been accepted by program staff and Department of Finance staff submit an appraisal of the property.', 'Internal tracking spreadsheet, "DOP-CHAP/ATPs and Permits/Tax Credit Status Spreadsheet - Copy.xlsx"', 'Eli Pousson', 'Data Lead', 'Live', '[# of preliminary reviews completed w/in 30 business days] / [Total # of tax credit applications received and completed]', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the 30 business day expectation communicated to the applicant?', true, NULL, 'Internal tracking spreadsheet, "DOP-CHAP/ATPs and Permits/Tax Credit Status Spreadsheet - Copy.xlsx"', 'Planners in the Historical and Architectural Preservation division collaboratively maintain a tracking spreadsheet that records basic details for each Authorization-to-Proceed application and staff review (including the date received and date preliminary', 'Program staff monitor the timeliness of CHAP Tax Credit reviews as part of general operations.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (420, 'AGC5700', 4, 'Number of engagements CHAP staff has with organizations or individuals regarding historic designation, local historic district activities and educational affairs', 'Output', 'The number of engagement activities (including calls, presentations, meetings, or other events) that CHAP staff has with organizations and individuals measures the scope of outreach efforts to inform residents, property owners, and other stakeholders about the CHAP process for historic designation and related programs.', 'Internal tracking spreadsheet on DOP-CHAP SharePoint site', 'Eli Pousson', 'Data Lead', 'Quarterly', '[# of tracked engagement activities with organizations/individuals]', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'DOP-CHAP SharePoint site', 'Planners in the Historical and Architectural Preservation division send basic information on engagement events to the division director to compile into a Microsoft Excel workbook on a quarterly basis.', 'The measure is shared with the Commission for Historical and Architectural Preservation as part of occasional presentations on program operations and impacts.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (421, 'AGC5700', 4, '% of map requests submitted to DOP completed within two weeks', 'Output', 'The share of map requests completed within a two-week period measures the responsiveness of the DOP GIS Team to data and map requests submitted by DOP staff, other city staff, elected officials, and residents. Requests that include more complex data analysis projects or application development are typically categorized as "Complex Projects" are excluded from the request counts when calculating this measure.', '"GIS Requests - DoP" SharePoint list on the DOP-POLICYDATA SharePoint site populated from submissions to a public Microsoft Form.', 'Eli Pousson', 'Data Lead', 'Live', '[# of map requests submitted to DOP completed within two weeks] / [Total # of map requests submitted to DOP]', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the SLA for 2 week completion entirely internal or communicated back to the requestor?', true, NULL, 'DOP-POLICYDATA SharePoint site', 'Requests are submitted using a Microsoft Form. A Power Automate Flow creates new items in a GIS Requests SharePoint list for each submission. Staff update the status and completion date for each request as part of the process of responding to requests. St', 'Staff monitor map requests as part of general operations for the DOP GIS Team but do not use the measure to evaluate performance or capacity on a routine basis.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (422, 'AGC5700', 4, '% of permits that receive initial review within three days', 'Output', 'The share of "Urban Renewal Review" tasks assigned to "DOP Comm Planning and Revitalization" in the Accela permit system that receive an initial review within three days measures the responsiveness of the community planners in the DOP Community Planning and Revitalization Division with active Urban Renewal Plans in their assigned Planning District. Initial review is defined as setting the status of the task in Accela to "Approved" or "Additional Info Required".', 'Construction and Code Enforcement (CCE) permit systemAccela permit system (since Jan. 2025); Construction and Code Enforcement (CCE) permit system (prior to Jan. 2025)', 'Eli Pousson', 'Data Lead', 'Live', '[# of permits that receive initial review within three days] / [Total # of permits assigned to CPR Division staff]', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the 3-day SLA calendar or business days? And is this communicated to the applicant, initial permit intake, etc.', true, NULL, 'Accela permit system', 'As of January 2026, Chad Hayes (CPR Division Chief) requests a report from BCIT provided as a Microsoft Excel workbook with all Urban Renewal Tasks in the Accela permit system assigned to "DOP Comm Planning and Revitalization".', 'Supervisors routinely review timeliness of permit review to the extent possible within Accela and require staff members to identify a back-up reviewer for assigned tasks when they expect to be out of the office and unable to review/approve permits.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (423, 'AGC5700', 4, '# of customers engaged and/or equipped by the Office of Sustainability to promote and/or implement sustainable practices   (% increase)', 'Output', 'The number of customers (including City residents and other stakeholders) engaged is tracked based on event sign-ins, mailers, social media posts and other interactions with Office of Sustainability program staff and measures the scope of program outreach.', 'Microsoft Excel tracking workbook (since FY2024); STATS database (prior to FY2024)', 'Eli Pousson', 'Data Lead', 'Annually', '[Total # of staff engaged/equipped for each tracked engagement activity]', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'DOP-Sustainability SharePoint site', 'Office of Sustainability staff manually compile basic information on outreach events and other engagement activities into a Microsoft Excel workbook to sum the total number of customers engaged.', 'The measure is reported publicly in the annual Sustainability Report.', NULL, 'N/A', 'This currently collapses a number of distinct activities (e.g., social media interactions, mailers, and actual event attendance) into one measure. It would be better to develop a more detailed methodology for a weighted engagement count.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (424, 'AGC5700', 4, '# of staff engaged to meet climate and sustainability goals across the city.', 'Output', 'The number of City staff is tracked based on attendance in climate or related trainings, workshops or other climate-related professional development actions as well as City staff participating in internal efforts such as the Mayor''s Sustainability and Resiliency Subcabinet. The number measures the scope of outreach efforts to internal City stakeholders.', 'Microsoft Excel tracking workbook (since FY2024); STATS database (prior to FY2024)', 'Eli Pousson', 'Data Lead', 'Annually', '[Total # of staff engaged/equipped for each tracked engagement activity]', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'DOP-Sustainability SharePoint site', 'Office of Sustainability staff manually compile basic information on staff engagement into a Microsoft Excel workbook to sum the total number of customers engaged.', 'The measure is reported publicly in the annual Sustainability Report.', NULL, 'N/A', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (425, 'AGC5700', 4, '% of Baltimore Sustainability Plan strategies initiated or advanced annually', 'Outcome', 'The share of recommendations from the Baltimore Sustainability Plan (2019) determined by staff to be initiated or advancing is a measure of progress towards implementation of the Sustainability Plan by City agencies and supporting partners. Staff use a wide range of additional data sources to assess progress on individual recommendations.', 'Microsoft Excel tracking workbook (since FY2024); STATS database (prior to FY2024)', 'Eli Pousson', 'Data Lead', 'Annually', '[# of Baltimore Sustainability Plan strategies marked as initiated/advanced] / [Total # of Baltimore Sustainability Plan strategies]', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'DOP-Sustainability SharePoint site (since FY2025); BCIT-hosted STATS Database (prior to FY2025)', 'Office of Sustainability staff manually review the list on an annual basis to collected related status updates and compile information into a consolidated report using a Microsoft Excel workbook.', 'The measure is reported publicly in the annual Sustainability Report.', NULL, 'N/A', 'Provide specific definitions for "initiated" and "advanced" for these strategies.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (426, 'AGC5700', 4, '% of Climate Action Plan (CAP) recommendations completed or progressed annually', 'Outcome', 'The share of recommendations from the Baltimore Climate Action Plan Update (2024) determined by staff to be completed or progressing is a measure of progress towards implementation of the Action Plan by City agencies and supporting partners. Staff use a wide range of additional data sources to assess progress on individual recommendations.', 'Microsoft Excel tracking workbook (since FY2024); STATS database (prior to FY2024)', 'Eli Pousson', 'Data Lead', 'Annually', '[# of CAP recommendations marked as completed/progressing] / [Total # of CAP recommendations]', 'Increase', NULL, NULL, 'Percent', NULL, 'Are there different timelines for recommendations, and are these recommendations all within the City''s power to move without significant public buy-in?', false, NULL, 'DOP-Sustainability SharePoint site', 'Office of Sustainability staff manually review a list of recommendations on an annual basis and use a variety of secondary data sources, including outreach to other city agencies and partner organizations, to determine the current status of each recommend', 'The measure is reported publicly in the annual Sustainability Report.', NULL, 'N/A', 'Provide specific definition for what it means to have the CAP recommendation "progressing."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (427, 'AGC5700', 4, 'Total Healthy Food Priority Area (HFPA) Funds invested in the City''s food system through grant agreements with community organizations and urban farms', 'Output', 'The total amount of Healthy Food Priority Area (HFPA) Funds awarded to community organizations and urban farms measures the outcome of program staff working to solicit applications and establish grant agreements. The status of program applications and grant agreements is tracked by staff using an internal spreadsheet and grant outcomes are tracked through annual reports and interviews with grantees.', 'HFPA Funds tracking spreadsheet; invoices in Workday may be used for cross-checking amounts.', 'Eli Pousson', 'Data Lead', 'Live', '[Total $ in HFPA funds awarded to community orgs./urban farms through grant agreements]', 'Increase', NULL, NULL, 'Currency', NULL, 'What is the HFPA Funds?', true, NULL, 'Google Drive for Food Policy and Planning Division', 'HFPA program staff maintain a tracking spreadsheet for grant awards with details on awardees, amounts, and the current status of each award (e.g. MOU in development, Law Department review in progress).', 'The measure is used by FPP program management staff for evaluating current program status and program impact over time.', NULL, 'N/A', 'Measure could be a % of funds spent down. Alternatively, if the HFPA funds are invested in other ventures besides community organizations and urban farms, "% of funds invested in community organizations and urban farms."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (428, 'AGC5900', 4, 'Average hours for analytics portal request turnaround', 'Efficiency', 'Turnaround time for Watch Center portal requests submitted under the Crime Analysis and Mapping category is measured by comparing the request received time and the completion time for requests with a “Work Complete” status. Routine reports are excluded from this measure. Requests assigned to the Intelligence Analysis Unit are also excluded, as they are not subject to the 72hr turnaround time goal.', 'gangnet.watch_center_portal_details', 'Kai Ji', 'Doctor', 'Live', 'Calculated as the average difference, in hours, between the request received date/time and the completion date/time for crime analysis requests', 'Not Applicable', NULL, NULL, 'Count', 'hours', 'N/A', false, NULL, 'ITD Oracle Server', 'Automated system extraction of Watch Center Poral Request data', 'DDS strives to complete Crime Analysis portal requests within 72 hours when feasible. However, some requests involve complex analyses that require longer turnaround times. Overall, DDSaims to keep the average turnaround time under 72 hours, though it may fluctuate depending on the nature and complexity of the requests received.', NULL, 'N/A', 'I would say "Average turnaround time for analytics portal requests"', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (429, 'AGC5900', 4, '% sworn hires from Baltimore City', 'Output', '# of Sworn Hires from Baltimore City', 'HR Sworn & Professional Hiring Vs. Attrition Report', 'Brian R. Davis', 'HR Generalist II', 'Report compiled weekly.', 'Total Baltimore City Sworn Hires Over Total Sworn Hires', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'BPD Share Drive', 'Database system of record notification & HR processor data verification.', 'Data is distributed to internal management, executive command & Baltimore City leadership for executive decision making purposes.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (430, 'AGC5900', 4, '% of time patrol officers spend on proactive policing', 'Effectiveness', 'Call level Calls for Service (CFS) data (PCalls) from the ArcGIS Server are used as the primary data source to remain consistent with previously reported measures since DDS assumed responsibility. The analysis is limited to CFS with durations between 0 and 480 minutes to prevent results from being skewed by data outliers, errors, or overtime. Quarter and year are derived from the date and time field. Patrol units are filtered based on unit numbers that conform to patrol unit format. Proactivity is defined using current proactivity measures, including calls coded as 20B (foot patrol), 20C (business check), 20P (bike patrol), and 25 (car stop). The total time spent on proactive calls, measured in minutes, is divided by the total time spent on all CFS. Duration values from the PCalls data are aggregated for both proactive calls and total CFS to calculate the proactivity percentage.', 'BPDGISDATA.PCALLS', 'Kai Ji', 'Research Analyst Supervisor', 'Live (Pcalls is updated on a daily basis)', 'The total time patrol units spent on proactive calls divided by the total time spent on all CFS at call level', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'BPD ArcGIS Enterprise Server', 'Automated system extraction of Calls for Service data provided by ITD/BCIT', 'This measure references the commonly used patrol 60/40 guideline, which serves as a benchmark for balancing proactive and reactive patrol activities.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (431, 'AGC5900', 4, '% of Requests Completed', 'Outcome', 'How many requests for service are completed as a function of how many requests are made', 'JusticeTrax', 'Ethan Conway', 'Deputy Director', 'Weekly', 'Requests Completed over Total Requests', 'Increase', NULL, NULL, 'Percent', NULL, 'Clarify the types of requests', true, NULL, 'JusticeTrax', 'Manually running reports from Justice Tax Software', 'This metric indicates the creation or deletion of backlog, greater than 100% is a decrease in a backlog while less than 100% indicates an increase in a backlog', NULL, 'N/A', 'Should be broken down by request types and outcomes', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (432, 'AGC5900', 4, '% of random audits of Level 2 use of force by PRB (Performance Review Board)', 'Outcome', 'Review of 10% of Level 2 Uses of Force looking at the following metrics: Event initiation; Tactical Approach; De-escalation; Use of Force tactics; Rendering Aid; Post Incident Response; Health and Wellness; and Supervisors investigation score', 'IAPro and SharePoint', 'Shannon Sullivan', 'Chief', 'Quarterly', 'Random 10% of Level 2 uses of force that were completed in the quarter.  Formula: number of completed use of force cases per quarter, which varies every quarter. 10% is pulled from that number', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'BPD shared drive, BlueTeam, Axon Evidence; Axon Records and SharePoint', 'Information is pulled from BWC, use of force reports and SharePoint', 'It is a requirement of the decree and it helps the Department review uses of force. PRB members are required to review the use of force investigation materials, any other supporting documents such as the incident report and the BWC prior to the PRB', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (433, 'AGC5900', 4, '% of public safety assessments completed on time', 'Effectiveness', 'Number of public safety assessments completed.', 'OpenGov', 'Alicia White', 'Major', 'Weekly/ Monthly/ or as needed', 'N/A- This formula is only determined by the percentage of permitted events assessed.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Opengov, spreadsheet shared drive for Special Events Unit', 'Permitted BPD staffed events through Opengov needing assessments.', 'To determine the percentage of permitted events needing public safety assessments.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (434, 'AGC5900', 4, '% of patrol officers who''ve received CIT (Crisis Intervention Training)', 'Output', 'The number of officers that have completed the 40hr CIT training that are assigned to patrol.', 'Acadis', 'Shannon Sullivan', 'Chief', 'Data is updated when a CIT class is completed. BPD typically holds 4 to 6 classes a year.', 'Total number of officers assigned to patrol for each shift and district (the constant) over number of CIT certified officers', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Acadis', 'After each class is completed, the CIT Coordinator uses district staffing charts that include all three shifts and determines the percent CIT trained based off of each shifts constant.', 'This data is used in Comstat and is a requirement of the consent decree so it is used by the Monitoring Team to determine compliance.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (435, 'AGC5900', 4, '% of paragraphs that have entered the implementation phase', 'Output', 'The number of paragraphs scored 4c "initial compliance" by the court appointed monitoring team', 'Wrike', 'Shannon Sullivan', 'Chief', 'Whenever the Monitoring Team publishes an assessment. There is no set schedule for this.', 'Number of paragraphs available for assessment vs the number of paragraphs assessed and scored 4c', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Wrike', 'Monitoring Team assessments (these are all on BPD''s website)', 'Once every paragraphs within a consent decree section is scored 4c, the section moves into Full and Effective Compliance. After a successful one to two year sustainment period that section of the decree is removed from federal oversight.', NULL, 'This is the responsibility of the Monitoring Team', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (436, 'AGC5900', 4, '% of OID (Operational Intelligence Division) reports distributed within 2 hours of receiving essential, accurate information', 'Effectiveness', 'Turnaround time for Watch Center portal requests submitted under the OID – Person Report category is calculated by comparing the request received time and the completion time for requests with a “Work Complete” status. To ensure the measure includes onlyOID reports requiring immediate dissemination following a shooting or homicide, the assignee’s sequence number must match the requester’s sequence number. The metric is calculated as the number of OID requests completed within 2 hours divided by the total number of OID requests in the portal.', 'gangnet.watch_center_portal_details', 'Kai Ji / Zachary Novak', 'Doctor / Sergeant', 'Live', 'Count (Completed Timeframe (Completed (Date/Time) - Request (Date/Time)) <=2 hrs)/ Total  reports', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'ITD Oracle Server', 'Automated system extraction of Watch Center Poral Request data', 'DDS strives to distribute OID - Person Reports for homicide and shooting victims within 2 hours after accurate and essential information has been received from the incident.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (437, 'AGC5900', 4, '% of non-fatal shooting cases cleared annually', 'Outcome', 'We are measuring how effective detectives are at clearing non-fatal shooting cases', 'Axon; Victim/Suspect Analysis/Clearance spreadsheets', 'John Herzog', 'Colonel', 'On demand', 'Number of NFS closures / # of NFS Victims in a Calendar year', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Axon', 'Axon', 'It helps inform how effective we are, resource allocation, process improvements, and workload.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (438, 'AGC5900', 4, '% of Level 3 use of force reviewed by PRB (Performance Review Board)', 'Effectiveness', 'Level 3 Use of Force incidents that are investigated by Special Investigation Response Team (SIRT). Level 3 Use of Force — Includes:  Strikes to the head, neck, sternum, spine, groin, kidneys, or kidney area with an impact weapon,  Firearm discharges by a BPD member, intentional or unintentional, that place a person at risk of injury, excluding discharges by a member while performing administrative unloading of a weapon where no BPD members or members of the public are at risk,  Applications of more than three (3) CEW cycles in a single encounter, regardless of the mode or duration of the application, and regardless of whether the applications are by the same or different members,  CEW application for longer than 15 seconds whether the application is a single continuous application or from multiple applications,  Uses of Force resulting in death, Serious Physical Injury, loss of consciousness, or requiring hospitalization, and  Uses of Deadly Force/Lethal Force, such as: o Intentionally striking a person’s head against a hard, fixed object such as a roadway, concrete floor, wall, or iron bars; o Knee strikes or kicks to a person’s head or neck; o Any strikes to a person’s throat; o “Knee drops” against a prone or supine person’s head, neck, or torso; o Chokeholds/Neck Holds; o Shooting someone in the head, neck, chest, or back, with a Less-Lethal Launcher at close range. o The use of any force on a person whose health, age, condition, or circumstances make it likely death or Serious Physical Injury will result. o Intentional CEW deployment to the head, neck, face, chest, or groin.', 'IAPro', 'Jerome Forrest', 'Lieutenant', 'Updated live.', 'Count (Level 3 Use of Force cases submitted)/Count (Level 3 Use of Force)', 'Not Applicable', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'In IAPro', 'Information was retrieved from IAPro', 'The data is analyzed to assess deficiencies.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (439, 'AGC5900', 4, '% of investigations completed within 180 days', 'Effectiveness', 'Assessing the percentage of cases (Internal, External and Ethics) completed within 6 months.', 'IAPro', 'Jerome Forrest', 'Lieutenant', 'Updated live.', 'Total cases completed in 180 days divided by total cases in Q2, then multiply by 100 to get the percentage.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'In IAPro', 'Information was retrieved from IAPro.', 'The data is analyzed to assess deficiencies.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (440, 'AGC5900', 4, '% of homicide cases cleared annually', 'Outcome', 'We are measuring the effectiveness of detectives to identify murder suspects and clear cases', 'Axon and Victim/Clearances spreadsheets', 'John Herzog', 'Colonel', 'On demand', 'Total number of homicide clearances / total number of homicide victims in calendar year', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Axon', 'Axon', 'This data is used to determine effectiveness, workload, resource allocation, and process improvements', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (441, 'AGC5900', 4, '% of high risk warrants served were resolved without injury to officers, victims or suspects', 'Outcome', '# of high risk warrants that required SWAT deployment.', 'SWAT Mission Log Database', 'Chris O''Ree', 'Lieutenant', 'Live (based on when the entry is made to the Mission Log Database).', '(V2-V1) / (V1) x 100 = % change', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'SWAT''s internal Mission Log Microsoft Access Database.', 'SWAT records individual search warrant where they record if there are any injuries to any parties. Desired outcome is increase unless it''s at 100%.', 'Review incidents to determine if any preventative measures should have been taken or adjust training protocols and standard operating procedures, as needed.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (442, 'AGC5900', 4, '% of findings in alignment with ACC''s (Administrative Charging Committee) findings', 'Output', 'The ACC agreement compared to PID''s finding after the investigation is completed. -	All ACC cases includes, Internal, External, Ethics and SIRT cases that are ACC eligible.', 'IAPro', 'Jerome Forrest', 'Lieutenant', 'Updated live.', 'Total disagreement divided by total completed ACC cases, then multiplied by 100. Then minus that amount from 100.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'In IAPro', 'Information was retrieved from IAPro.', 'The data is analyzed to assess deficiencies.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (443, 'AGC5900', 4, '% of custom notifications delivered', 'Outcome', 'message of non violence delivered by the outreach team, consists of an offer of services and support while explaining the consequences of and accountability if violence continues. The goal is to persuade the person to step away from violent behavior by combining supportive resources with a clear deterrent message', 'Lotus Notes Custom Notifications Delivered', 'M. Yezzi', 'Detective', 'Live', 'number completed over total number of identified indivudals', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Lotus Notes / BPD GVRS Cases', 'Manual entry by detectives', 'Ensures that those identified for outreach communications are completed, also allows for ease of sharing data with MONSE', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (444, 'AGC5900', 4, '% of calls for service diverted from patrol to online or telephone reporting', 'Effectiveness', 'percentage of eligible calls diverted from patrol to online reporting or TRU.', 'InPursuit; Coplogic', 'Shannon Sullivan', 'Chief', 'monthly, quarterly, annually', 'divide total number of reports from online reporting and TRU by the total number of CFS', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Axon and CAD data', 'InPursuit; Coplogic', 'data is used to determine the effectiveness of diverting these call types from patrol', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (445, 'AGC5900', 4, '% of audited OID (Operational Intelligence Division) reports in compliance with DDSD standards', 'Effectiveness', 'To measure how accurately and consistently unit personnel complete OID Person Reports in accordance with established best practices, documentation standards, and instructional guidance.', 'Watch Center "OID Person Profile Reports"', 'Novak, Zachary', 'Sergeant', 'Monthly (benchmark tests are issued 1 per month).', 'Total # of Benchmark Scores / Total # of Tests in the Period = Watch Center Average', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Watch Center Benchmark Results - Microsoft Excel Sheey', 'Data is collected through a standardized quality assurance review of a randomly assigned OID Person Report for each employee on a monthly basis. Each report is evaluated using a predefined scoring rubric across required sections, with scores recorded and', 'This measure is used to assess the accuracy, consistency, and standards compliance of OID Person Reports across the unit. Results inform operational decisions by identifying training needs, quality trends, and process gaps, while supporting accountability and continuous improvement.', NULL, 'The current scoring process is highly manual and labor-intensive, requiring case-by-case human review of each OID Person Report. At present, there is no efficient or automated mechanism to conduct routine quality control or extract standardized scoring data outside of individual reviewer assessments.Improving this measure would require a technology solution capable of structured data capture and scoring support (e.g., embedded validation rules, standardized scoring fields, or reporting dashboards). Investment in such a solution would reduce staff time devoted to manual reviews, increase consistency and reliability of scoring, enable more timely monthly measurement, and allow resources to be reallocated from administrative review to higher-value operational and analytical work.', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (446, 'AGC5900', 4, '% of audited interactions that are fully compliant with procedural justice policy', 'Outcome', 'Compliance with Procedural Justice policy', 'Axon Evidence', 'Shannon Sullivan', 'Chief', 'Monthly', 'Reviewets answer 23 questions for each audit either Yes, No, or NA.  Compliance score are then calculated with the following formula (Total # of Yes Responses)/(Total # of Yes and NO Responses). Responses of NA are not factored', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'BPD shared drive', 'vidence.com is utilized to generate a population list of police interactions with the public for all nine (9) Districts,. Once the population list of police interactions with the public is determined and totaled, a random number generator is used to selec', 'It is used at Comstat and in relation to compliance with the Fair and Impartial Policing and Stops, Searches and Arrests sections of the Consent Decree.', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (447, 'AGC5900', 4, '% homicide warrants served', 'Output', 'The percentage of homicide warrants served (Homicide warrants served / total homicide warrants)', 'Lotus Notes', 'John Herzog', 'Colonel', 'Weekly', 'Homicide Warrants Served / total number of homicide warrants obtained', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Lotus Notes', 'Retreiving from Lotus Notes', 'It helps us determine how effectively WATF is locating murder suspects and serving the warrants', NULL, 'N/A', 'straight-forward', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
