    (472, 'AGC6100', 4, '% of Missed Pick-ups (Mixed Refuse)', 'Outcome', 'This measure tracks how often mixed refuse pick‑ups are not completed as scheduled. A “missed pick‑up” is defined as a mixed refuse collection that was not serviced on its assigned day and is verified through Salesforce SW-Mixed Refuse service requests. The measure compares the number of missed mixed refuse pick‑ups to the total number of scheduled mixed refuse pick‑ups.', 'SalesForce', 'Michael Lucas', 'Solid Waste Division Chief', 'Live as needed.', '% of missed Mixed Refuse pick-ups
(Calc''d based on the 190000*52 for weekly recycling)', 'Decrease', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Salesforce', 'The data is collected from Salesforce using a standardized report. The report should:
•Filter for SW-Mixed Refuse SRs. The count is the total number of SW-Mixed Refuse SRs
•	Calculate total SW-Mixed Refuse SRs divided by 190000*52', 'This measure provides a clear indicator of service reliability and operational performance. It reflects how consistently mixed refuse routes are completed as planned and helps identify areas where operational improvements may be needed.', NULL, NULL, 'The measure can be improved by removing cancelled mixed refuse pickups from the denominator and providing clarity on why 190000*52 is used.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (473, 'AGC6100', 4, '% of Missed Pick-ups (Recycling)', 'Outcome', 'This measure tracks how often recycling pick‑ups are not completed as scheduled. A “missed pick‑up” is defined as a recycling collection that was not serviced on its assigned day and is verified through Salesforce SW-Recycling service requests. The measure compares the number of missed recycling pick‑ups to the total number of scheduled recycling pick‑ups.', 'SalesForce', 'Michael Lucas', 'Solid Waste Division Chief', 'Live as needed', '% of missed Recycling pick-ups
(Calc''d based on the 190000*52 for weekly recycling)', 'Decrease', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Salesforce', 'The data is collected from Salesforce using a standardized report. The report should:
•	Filter for SW-Recycling SRs. The count is the total number of SW-Recycling SRs
•	Calculate total SW-Recycling SRs divided by 190000*52', 'This measure provides a clear indicator of service reliability and operational performance. It reflects how consistently recycling routes are completed as planned and helps identify areas where operational improvements may be needed.', NULL, NULL, 'The measure can be improved by removing cancelled recycling pickups from the denominator and providing clarity on why 190000*52 is used.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (474, 'AGC6100', 4, '% of SRs completed within one day (Mixed Refuse)', 'Efficiency', 'This measure tracks how quickly the service responds to recycling‑related requests—such as missed mixed refuse pickups--by calculating the proportion of requests that are closed within one day of their creation date. It compares the number of mixed refuse service requests completed within one day to the total number of mixed refuse requests closed during the reporting period.', 'SalesForce', 'Michael Lucas', 'Solid Waste Division Chief', 'Live as needed.', 'one day completion rate = # of SW-Mixed Refuse requests completed within 1 day/total # of SW-Mixed Refuse requests completed x 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Sales force', 'The data is collected from Salesforce using a standardized report. 
•Filter for SW-Mixed Refuse SRs. The count is the total number of SW-Mixed Refuse SRs
•Filter the age of 1 and less days for the count of  SW-Mixed Refuse SRs closed in one day or less.', 'This measure provides a clear indicator of operational responsiveness and service quality for mixed refuse services. It reflects how effectively the service addresses resident needs in a timely manner and supports overall customer satisfaction.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (475, 'AGC6100', 4, '% of SRs completed within one day (Recycling)', 'Efficiency', 'This measure tracks how quickly the service responds to recycling‑related requests—such as missed recycling pickups--by calculating the proportion of requests that are closed within one day of their creation date. It compares the number of recycling service requests completed within one day to the total number of recycling requests closed during the reporting period.', 'SalesForce', 'Michael Lucas', 'Solid Waste Division Chief', 'Live as needed', 'one day completion rate = # of SW-Recycling requests completed within 1 day/total # of SW-Recycling requests completed x 100', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Salesforce', 'The data is collected from Salesforce using a standardized report. 
•Filter for SW-Recycling SRs. The count is the total number of SW-Recycling SRs
•Filter the age of 1 and less days for the count of  SW-Recycling SRs closed in one day or less.', 'This measure provides a clear indicator of operational responsiveness and service quality for recycling services. It reflects how effectively the service addresses resident needs in a timely manner and supports overall customer satisfaction.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (476, 'AGC6100', 4, 'Tonnage collected - Mixed Refuse', 'Output', 'This measure captures the total weight of municipal solid waste materials collected through the City’s curbside collection services.', 'Manual input from Routine Services', 'Michael Lucas', 'Solid Waste Division Chief', 'Monthly', 'Manual input from Routine Services', 'Decrease', NULL, NULL, 'Count', 'tons', 'N/A', false, NULL, 'Operational logs', 'Monthly aggregated weight of curb-side collections of resident municpal solid waste.', 'This measure provides a quantitative indicator of curbside collection activity of municpal solid waste. It reflects resident participation, operational capacity, and the effectiveness of collection services.', NULL, NULL, 'Indicate where the operationals logs are stored and how to pull the data to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (477, 'AGC6100', 4, 'Tonnage Collected - Recycling', 'Output', 'This measure captures the total weight of recyclable materials collected through the City’s curb-side collection recycling program.', 'Manual input from Routine Services', 'Michael Lucas', 'Solid Waste Division Chief', 'Monthly', 'Manual input from Routine Services', 'Increase', NULL, NULL, 'Count', 'tons', 'N/A', false, NULL, 'Operational logs', 'Monthly aggregated weight of curb-side collections of resident recycling.', 'This measure provides a quantitative indicator of recycling activity and diversion efforts. It reflects resident participation, operational capacity, and the effectiveness of recycling services in reducing landfill disposal.', NULL, NULL, 'Indicate where the operationals logs are stored and how to pull the data to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (478, 'AGC6100', 4, '$ generated from the small hauler program at QRL (Quarantine Road Landfill) and NWTS (Northwest Transfer Station)', 'Outcome', 'Revenue dollars generated from small haulers who use QRL and NWTS to dispose of materials.', 'Data input manually by Disposal Services', 'Antwan Byrd', 'Solid Waste Division Chief', 'Monthly', 'Data input manually by Disposal Services', 'Increase', NULL, NULL, 'Currency', NULL, 'N/A', false, NULL, 'Operational logs', 'Dollars collected from small haulers are aggregated to monthy revenue collected from small haulers.', 'Tracking the revenue generated from the small hauler program at QRL (Quarantine Road Landfill) and NWTS (Northwest Transfer Station) is meaningful because it provides insight into both the financial health of the program and the broader waste‑management system. This measure matters because:
- It reflects program utilization
Higher revenue indicates strong participation from small haulers—contractors, small businesses, and residents—who rely on DPW facilities for proper waste disposal.
- It supports operational cost recovery
Revenue helps offset the costs of operating disposal and transfer facilities, including staffing, equipment, maintenance, and environmental compliance.
- It contributes to long‑term financial sustainability
Understanding revenue trends helps DPW plan for future capital needs, such as landfill cell construction, transfer‑station upgrades, or equipment replacement.
- It helps identify shifts in waste‑disposal behavior
Changes in revenue can signal broader trends—such as increased construction activity, shifts in private hauling, or changes in illegal dumping patterns.
- It informs budgeting and rate‑setting decisions
Reliable revenue data supports transparent, data‑driven decisions about tipping fees, program adjustments, and resource allocation.
- It strengthens accountability and transparency
Tracking revenue from the small hauler program demonstrates responsible stewardship of public facilities and provides a clear metric for leadership and stakeholders.
Overall, this measure is meaningful because it connects day‑to‑day facility operations to the financial stability of the City’s waste‑management system and helps ensure that disposal services remain accessible, efficient, and sustainable.
- It informs budgeting and rate‑setting decisions
Reliable revenue data supports transparent, data‑driven decisions about tipping fees, program adjustments, and resource allocation.', NULL, NULL, 'Indicate where the operationals logs are stored and how to pull the data to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (479, 'AGC6100', 4, '% of waste in tonnage collected by DPW that goes to recycling', 'Outcome', 'This measure calculates the share of material collected by DPW—across residential routes,—that is sent to recycling facilities. It compares the tonnage of recyclable materials collected to the total tonnage of all waste collected during the reporting period.', 'Data input from Routine Services manually', 'Michael Lucas', 'Solid Waste Division Chief', 'Monthly', 'Curbside recycling tonnage(curbside recycling tonnage+curbside trash tonnage)', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Operational logs', 'Aggregated of weights of recyclable materials collected from resident curbside collections.', 'The percentage of total DPW‑collected waste that is diverted to recycling is a key indicator of the City’s progress toward waste‑reduction and sustainability goals. This data is used to:
- Monitor overall recycling performance
It shows how effectively the City is diverting material away from landfills and whether recycling efforts are increasing, decreasing, or holding steady.
- Evaluate program effectiveness
By comparing diversion rates over time, DPW can assess the impact of outreach campaigns, route changes, new recycling programs, or policy shifts.
- Identify opportunities for improvement
Low or declining diversion rates can signal issues such as contamination, resident confusion, insufficient capacity, or operational challenges.
- Guide resource allocation
The data helps determine where to invest in education, staffing, equipment, or infrastructure to improve recycling outcomes.', NULL, NULL, 'Indicate where the operationals logs are stored and how to pull the data to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (480, 'AGC6100', 4, 'Projected Life (years) Remaining of the Landfill', 'Outcome', 'The remaining life expectancy of the landfill. This is based on the overall permitted tonnage, landfill fill in plan, annual flyover, and monthly tonnage reports', 'Tonnage reports reviewed by Disposal Services', 'Antwan Byrd', 'Chief of Disposal Services', 'Monthly', 'Tonnage reports reviewed by Disposal Services', 'Increase', NULL, NULL, 'Count', 'years', 'N/A', false, NULL, 'Permits (provides the permitted tonnage), Annual Flyover, Landfill Fill in plan - DPW internal compliance sharepoint site
Monthly tonnage reports - Desert Micros (internal landfill data management system)', 'Review of tonnage reports', 'The data provides an outlook into how long the operation can accept material before another option is necessary.', NULL, NULL, 'Indicate where the operationals logs are stored and how to pull the data to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (481, 'AGC6100', 4, 'Tonnage disposed', 'Output', 'This measure captures the total weight of non‑recyclable, non‑compostable, and non‑diverted materials that are transported to and deposited at landfill facilities. Tonnage is recorded using certified scales at disposal sites and reflects the volume of material that is not diverted through recycling, reuse, or other waste‑reduction programs.', 'Data input from Disposal Services manually', 'Antwan Byrd', 'Solid Waste Division Chief', 'Monthly', 'Data input from Disposal Services manually', 'Decrease', NULL, NULL, 'Count', 'tons', 'N/A', false, NULL, 'Operational Logs', 'At the landfill, each truck is weighed using certified scales.  All  scale tickets are totaled to calculate the monthly tonnage disposed. This total becomes the measure value for the reporting period.', 'Tracking the tonnage of waste disposed in landfill is meaningful because it provides a direct indicator of the City’s environmental impact and the effectiveness of its waste‑diversion efforts. This measure matters because:
- It reflects overall waste‑management performance
Rising or falling landfill tonnage shows whether the City is generating more waste, improving diversion, or facing operational challenges.
- It helps evaluate recycling and diversion programs
If landfill tonnage decreases while recycling or composting increases, it signals that diversion strategies are working. If landfill tonnage rises, it may indicate contamination, low participation, or gaps in service.
- It informs operational planning
Understanding disposal volumes helps DPW plan for staffing, equipment needs, transfer‑station capacity, and landfill‑contract management.
- It provides a baseline for policy decisions
Leaders use this measure to assess the need for new programs, education campaigns, or regulatory changes aimed at reducing waste.', NULL, NULL, 'Indicate where the operationals logs are stored and how to pull the data to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (482, 'AGC6100', 4, '# of confirmed distribution system samples outside EPA/MDE compliance', 'Outcome', 'measuring the presence or absence of chlorine residuals, bacteria, and pathogens
in drinking water found throughout the distribution system. Minimum 360 samples collected monthly.', 'Water Quality Laboratory Data sheets', 'Deneen Gordon', 'Division Chief, Laboratory Operations Division', 'Data is collected daily except holidays. Complied monthly.', 'Water Quality Laboratory Data sheets', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Data is stored in the LIMS system.', 'Field data is reported into an app during time of collection.', 'This measure informs operations in the service of areas within the distribution system where there is deteriorating water quality conditions that could impact public health.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (483, 'AGC6100', 4, '# of Safe Drinking Water Act Violations', 'Outcome', 'Measuring includes any and all parameters listed within the regulations of the Safe Drinking Water Act. These include Primary and Secondary Standards for contaminants that have health effects or cosmetic/aesthetic effects respectively.', 'Water Quality Laboratory data reports/spreadsheets', 'Deneen Gordon', 'Division Chief, Laboratory Operations', 'Most data is compiled on a monthly basis, with some depending on the regulation compiled and reported quarterly, annually.', 'Water Quality Laboratory data reports/spreadsheets', 'Decrease', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'LIMS system, spreadsheets', 'Data results are analyzed internally or through a third -party lab and entered into the LIMS system.', 'Data informs operation of potential hazardous chemicals in the source water, plant effluent water, and water in the distrbution system that posed health effects. For aesthetic effects, changes to the surrounding environment and deteriorating conditions.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (484, 'AGC6100', 4, 'Cost of treatment per million gallons (MG)', 'Efficiency', 'Dosing & treatment efficiencies/cost of chemicals/raw water quality', 'Water Facilities spreadsheets', 'Herbert Naylor', 'Division chief', 'Database, chemical cost invoices', 'Water Facilities spreadsheets', 'Decrease', NULL, NULL, 'Currency', 'per million gallons', 'N/A', true, NULL, 'Plant database SCADA, spreadsheets', 'gallons per raw water, chemical cost, treatment process', 'Calculate efficiency, improve operation, validate potable water cost', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (485, 'AGC6100', 4, 'Million gallons of water treated per day, on average (MGD)', 'Efficiency', 'Electronic flow devices measuring MGD', 'Elecronic flow meters recording MGD. Water Treatment spreadsheets', 'Herbert Naylor
410-396-6642', 'Chief - Water Facilities Division', 'Data is collected daily and calculated monthly. Data is saved on historical database', 'Water Treatment spreadsheets', 'Increase', NULL, NULL, 'Count', 'million gallons per day', 'N/A', true, NULL, 'Historian database/SCADA systems database', 'Electronic flow devices measuring in MGD. recorded into database', 'The data is use to calculate flow pacing of chemicals and other treatment needs.', NULL, 'Estimating flow with spreadsheets.', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (486, 'AGC6100', 4, 'Total Breaks Per 100 Miles/Year', 'Outcome', 'This measure is an important indicator of distribution system reliability as impacted by age, condition, and other factors.  It is used to trend overall reliability performance on a system-wide level against targets and can be used to gauge the effectiveness of rehabilitation, renewal, and replacement programs over time.  It is expressed as the total number of main breaks and leaks per 100 miles of distribution mains per year.  For a water utility, distribution system reliability has important implications for customer service, operations and maintenance, asset management, and finance.  This metric reports the frequency of occurrence but does not measure the impact of events (i.e. duration or customers affected).  This measure can show seasonal variations in performance such as a higher number of events during winter and summers during extreme temperatures.  Although monthly variations can be acceptable, this measure should be monitored for discernable trends over time.  Rolling averages can be useful indicators to monitor long term trends.', 'Cityworks', 'Babatunde Oyinloye', 'Data management supervisor', 'Live', '(100) * (Total number of break and leaks during reporting period)/Total miles of distribution main', 'Decrease', NULL, NULL, 'Count', 'per 100 miles/year', 'N/A', true, NULL, 'Cityworks', 'N/A', 'Used in Condition and Criticality formula, tracking overall system health.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (487, 'AGC6100', 4, '% of accounts billed', 'Output', 'Percentage of eligible accounts billed', 'UMAX', 'Antonine Ross', 'Deputy Chief, DPW Customer Support and Service Division', 'Daily, Weekly, Monthly, Annually', 'UMAX', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'KPI Dashboard', 'Export data into excel', 'This data is used to ensure our staff are performing in line with the KPI success rate target of 98% for eligible accounts billed.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (488, 'AGC6100', 4, '% of bills produced per cycle (15 total cycles)', 'Efficiency', 'Percentage of eligible accounts bills produced per cycle, 15 total cycles', 'UMAX', 'Antonine Ross', 'Deputy Chief, DPW Customer Support and Service Division.', 'Daily, Weekly, Monthly, Annually', 'UMAX', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'KPI Dashboard', 'Export reporting into excel', 'This data is used to ensure our staff are processing bills in line with the KPI success rate target of 98% for eligible bills produced per cycle.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (489, 'AGC6100', 4, '% of calls answered within 1 minute', 'Efficiency', 'Percentage of calls answered within 1 minute', 'MTE', 'Antonine Ross', 'Deputy Chief, DPW Customer Support and Service Division', 'Daily, Weekly, Monthly, Annually', 'MTE', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Mitel Client Contact Center', 'Export data into excel', 'This data is used as a measure of performance of our CSSD Call Center staff ability to quickly answer incoming calls from constituents.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (490, 'AGC6100', 4, 'Average rating given in customer service survey', 'Outcome', 'Customer Service Survey', 'Water/Wastewater Customer Service Survey', 'Antonine Ross', 'Deputy Chief, DPW Customer Support and Service Division', 'Daily, Weekly, Monthly, Annually', 'Water/Wastewater Customer Service Survey', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', true, NULL, 'Sharepoint folder', 'Export raw data into excel for analysis', 'The customer service survey data is used to assess how staff are meeting the customer service needs of our constituents in line with our KPI customer service rating of 4 or higher.', NULL, NULL, 'Include the numerator and denominator for the measure and which columns/questions from the survey should be used for analysis.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (491, 'AGC6100', 4, 'Call answer rate', 'Effectiveness', 'Call answer rate measures staff performance with answer calls and minimizing abandoned calls.', 'MTE', 'Antonine Ross', 'Deputy Chief, Customer Support and Services Division', 'Daily, Weekly, Monthly, Yearly', 'MTE', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Mitel Client Contact Center application', 'Export data into an excel file', 'The call answer rate data is used to measure the rate at which our call center staff are answering calls and minimizing abandoned calls.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (492, 'AGC6100', 4, '% of Significant Industrial Users inspected and sampled', 'Effectiveness', 'Number of SIU''s inspected versus number required for the given period', 'monthly monitoring reports', 'Robert Hindt; Pat Boyle', 'Division Chief WW Facilities; Pollution Control Administrator', 'Monthly', 'number of SIU''s inspected for the time period divided by the total number of SIU''s', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Excel sheets and inspection reports maintained by Pollution Control', 'Compiled within spreadsheets of records', 'To measure success in montioring significant dischargers to the treatment facilities as they can seriously impact the influent quality with unpermitted discharges. Resulting in excessive costs, etc.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (493, 'AGC6100', 4, '% of time in National Pollutant Discharge Elimination System (NPDES) Permit compliance', 'Outcome', 'Number of permit excursions', 'monthly Discharge Monitoring Reports (DMR) and Monthly Operating Reports (MOR)', 'Robert Hindt', 'Division Chief, WW Facilities', 'Monthly', '1.0 - number of permit excursions divided by total permit measurements', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Net DMR and excel sheets from lab', 'Collected daily', 'Determine operational performance against WEF/AWWA standards.', NULL, 'N/A', 'Identify the speciifc process for accessing and pulling the data. Also, the measure name says that it''s measuring the % of time in compliance, but the formula doesn’t indicate that the calculation is for time in compliance, but rather the % of permit excursions out of all permit measurements.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (494, 'AGC6100', 4, 'Cost of treatment per million gallons', 'Outcome', 'sum of all operational and maintenance costs associated with treatment, conveyance, and administration functions associated with BackRiver, Patapsco and pumping stations', 'monthly expenditure report and effluent meters', 'Robert Hindt', 'Division Chief, Wastewater Facilities', 'Monthly', 'sum of costs on monthly expenditure reports divided by the sum of effluent meters', 'Decrease', NULL, NULL, 'Currency', 'per million gallons', 'N/A', true, NULL, 'SCADA and Workday', 'Automated updates (Daily and Monthly)', 'To identify potential savings points. Examples would be increase chemical costs, high labor/OT, excessive equipment replacement/repair costs, etc.yearly benchmarking against WEF data', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (495, 'AGC6100', 4, 'Million gallons of wastewater treated per day (MGD)', 'Output', 'Effluent discharge flow', 'effluent flow meters', 'Robert Hindt', 'Division Chief, WW Facilities', 'daily', 'sum of effluent flow meters from Patapsco and Back Rier', 'Decrease', NULL, NULL, 'Count', 'million gallons per day', 'N/A', true, NULL, 'SCADA from Back River and Patapsco', 'automated flow meters through SCADA', 'To gauge the amount of treated flow to assess additional costs as well as future planning. Once a plant has reached 80% of it''s design capacity (on annual average), there will be additional expansion requirements which will include Significant capital investments', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (496, 'AGC6100', 4, '% of construction sites inspected every 2 weeks', 'Effectiveness', 'The number of inspections completed within the expected timeframe', 'Spreadsheet', 'DPW - OREP - Plans Review and Inspections', 'Inspection Supervisor', 'Weekly', 'Spreadsheet', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'City Server', 'Manual Input', 'The data gives the expecations to the contractors and tracks contractors compliance with approved plans.', NULL, NULL, 'Identify the speciifc process for accessing and pulling the data, and also include the formula (numerator and denominator.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (497, 'AGC6100', 4, '% SWM/ESC Plans Review responses within 14 days', 'Effectiveness', 'The percentage of reviews returned to the PreojectDox System within the allotted amount of time.', 'ProjectDox', 'DPW - OREP - Plans Review and Inspections', 'Plans Review and Inspections Section Chief', 'Live', 'ProjectDox', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'ProjectDox system, Server Excel sheet', 'generative reports, manual input', 'The data gauges the timeframe needed for city review  outside of the applicant''s control and highlights the section''s performance.', NULL, NULL, 'Identify the speciifc process for accessing and pulling the data, and also include the formula (numerator and denominator.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (498, 'AGC6100', 4, '# of Sanitary Sewer Overflows (SSOs) during the reporting period per 100 miles of sewer', 'Output', 'A SSO overflow is an uncontrolled release, and DPW strives to reduce this number.  This measure can identify issues with sewer capacity, blockages, and collapses by tracking events that discharge sewage outside of the collection system.  This measure provides DPW with consideration proactive and reactive maintenance and capital investment strategies. Categories/types of SSOs are captured and reported (i.e. laterals and mainline/manhole) to help with analysis.  This indicator is a good measure of overall collection system reliability and capacity, and can help drive the effectiveness of inspection, maintenance, renewal, and cleaning programs.  This is an especially important metric for DPW under the current Modified Consent Decree.', 'Cityworks', 'Babatunde Oyinloye', 'Data management supervisor', 'Live', '(100) * (Total number of SSOs during reporting period)/Total miles of pipe in the wastewater collection system', 'Decrease', NULL, NULL, 'Count', 'per 100 miles', 'N/A', true, NULL, 'Cityworks', 'N/A', 'This measure provides DPW with consideration proactive and reactive maintenance and capital investment strategies.  This indicator is a good measure of overall collection system reliability and capacity, and can help drive the effectiveness of inspection, maintenance, renewal, and cleaning programs.  This is an especially important metric for DPW under the current Modified Consent Decree.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (499, 'AGC6100', 4, '# of water quality complaints during the reporting period per 100 water accounts', 'Outcome', 'Measures the total number of customer complaints investigated by DPW technical staff.  It is expressed as the total number of validated complaints per reporting period per 100 customer accounts.  For a water utility, distribution system quality and reliability has important implications for customer service and operations and maintenance.  Issues can be indicative of poor asset condition, restricted flows, low residual chlorine, and/or poor turnover of water in the distribution system.   This indicator quantifies the total number of complaints but does not measure the impact of events (i.e. duration or customers affected).  A stable and relatively low frequency is desirable, assuming that there are always some minor ongoing issues present in any distribution system.  Complaints should be tracked by type (Discoloration, Taste and Odor, Low Pressure) in order to track root cause of the problem and determine the most appropriate and effective method of resolution.  This measure should be monitored for discernible trends over time.', 'Cityworks', 'Babatunde Oyinloye', 'Data management supervisor', 'Live', '(100) * (Total complaints during reporting period, by type)/Total number of water accounts', 'Decrease', NULL, NULL, 'Count', 'per 100 accounts', 'N/A', true, NULL, 'Cityworks', 'N/A', 'Used in Condition and Criticality formula, tracking overall system health.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (500, 'AGC6100', 4, '% of project tasks completed on time and within budget', 'Effectiveness', 'Measure the number (percentage) of projects completed within budget and on time.', 'Unifier', 'Eric Atandi', 'Engineer Supervisor', 'Live', 'Number of Projects completed on Time and Budget/ Total number of projects completed in the period', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Unifier', 'The administrator runs a report.', 'Helps us to gauge the level of effeciency in project delivery', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (501, 'AGC6100', 4, '% of WICs (Water in Cellar) during reporting period per 100 customer accounts', 'Outcome', 'This indicator is a good measure of overall DPW collection system reliability and capacity.  Additionally, it can provide indication of impacts to customers. Sewer Basement Backup incidents are one of the most visible sewer system service levels for DPW customers, and can cause significant property damage and nuisance.   Backups can be caused by many factors, and can often impact specific portions of the system more than others.  This indicator only includes events that are city responsibility and specifically excludes non-city responsibility (i.e. customer plumbing issues).  Investigations are also typically performed to track root cause of the event to help determine strategies to rectify persistent issues.  Repeat Backups are also tracked to focus performance on specific customers with a history of repeat events, develop capital and maintenance strategies, and to address specific problems across the system.', 'Cityworks', 'Babatunde Oyinloye', 'Data management supervisor', 'Live', '(100) * (Total number of WICs during reporting period)/Total number of sewer connections', 'Decrease', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Cityworks', 'N/A', 'This indicator is a good measure of overall DPW collection system reliability and capacity.  Additionally, it can provide indication of impacts to customers', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (502, 'AGC6100', 4, 'Cumulative monthly MBE& WBE (Minority) invoiced', 'Output', 'Payments made to minorities in every pay invoice for capital improvement p[rojects', 'Unifier', 'Eric Atandi', 'Engineer Supervisor', 'live', 'payment to Minorities/Total payment', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', true, NULL, 'Unifier', 'Captured in reports from Unifier', 'This is important to ensure that OEC meets the requirements set by SMBAD as per the city charter.', NULL, 'N/A', 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (503, 'AGC6100', 4, 'Linear Feet of wastewater collection system rehabilitated/replaced', 'Outcome', 'The amounts of rehabilitation and replacement is measure based Linear footage.', 'Unifier', 'Carlos Stephenson', 'Engineer II', 'Confirmation of the data is done on a monthly basis when the resident inspector or City representation meets with the Contractor to review the quantities for monthly payment. Following that meeting the final confirmed quantities are put into Unifier', 'CM14', 'Increase', NULL, NULL, 'Count', 'linear feet', 'N/A', true, NULL, 'The information is stored in Unifier', 'The information is collected by field inspection staff and input into Unifier has part of their reports', 'Information is utilized as a basis of payment for the Contractor performing the work.', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (504, 'AGC6100', 4, 'Linear mileage of installed pipe in the 15 mile per year target (Capital Improvement Program)', 'Output', 'linear footage for the 15 miles from each construction project', 'unifier', 'Tarnisha Bailey', 'Engineer II', 'the data is collected monthly', 'unifier', 'Increase', NULL, NULL, 'Count', 'linear miles', 'N/A', true, NULL, 'Unifier', 'the inspector collects the information and repsorts at the end of the month', 'to track the milage and use to help pay the contractor for the work that they have done for the month', NULL, NULL, 'Identify the speciifc reports  and locations for pulling the data in to calculate the measure.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (505, 'AGC6300', 4, '% of scheduled days that outdoor pools are open to the public excluding weather during the summer season (Memorial Day through Labor Day)', 'Effectiveness', 'How many days outdoor pools are available for use to the public', 'Internally Tracked: Chief of Aquatics', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Live', '(Scheduled days pools are open / all scheduled pool days) - weather days', 'Increase', NULL, NULL, 'Percent', NULL, 'How are weather days tracked in the report? Are all days considered equal (i.e., half-days, partial openings, etc.)?', false, NULL, 'CivicRec/Excel', 'Civic Rec report', 'This measure informs BCRP: (1) the availability of our outdoor pools to the public; and (2) whether BCRP is efficient in the inspection, cleaning, and maintenance of outdoor pools (since this would be a major contributing factor within BCRP''s control of whether a pool is available to the public).', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (506, 'AGC6300', 4, 'Total attendees at outdoor pools during the summer season (Memorial Day through Labor Day)', 'Output', 'How many days the public uses our outdoor pools during the summer season', 'Database', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Live', 'Number of logs/scans in the BCRP database', 'Increase', NULL, NULL, 'Count', NULL, 'How often is the CivicRec data updated?', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the frequency of use at our pools and whther there are certain pools used more than others; this ties into future capital development and improvement of BCRP pools.', NULL, NULL, 'BCRP should change the measure name to "total # of visits" as one person could go to the pool everyday while another only goes once.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (507, 'AGC6300', 4, '% of Playgrounds Inspected (Amount of playground inspections completed every 60 days)', 'Efficiency', 'The amount of playgrounds inspected each 60 day cycle', 'Internally Tracked: Playground Saftety Coordinator', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Weekly', 'Completed playground inspections every 60 days', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the 60-day SLA tracked internally or externally (i.e., does the public know of this 60-day cycle)? How does this get tracked in Salesforce?', false, NULL, 'Salesforce/Excel', 'Salesforce report', 'This measure informs BCRP of the maintenance of playground structures across Baltimore City. This impacts the: (1) safety of equipment installed by BCRP; and (2) enjoyment of play spaces for youth.', NULL, NULL, 'Clarify what the measure is supposed to capture: either the timeliness of the playground inspections, or the number of inspections completed each reporting period.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (508, 'AGC6300', 4, 'Percentage of parks mowed every seven days during growing season', 'Efficiency', 'The amount of parks mowed each seven day cycle', 'Internally Tracked: Chief of Park Maintenance', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Weekly', 'Entire inventory of parks mowed every seven days between April 1-November 30 (Growing Season)', 'Increase', NULL, NULL, 'Percent', NULL, 'Is the 7-day SLA tracked internally or externally (i.e., does the public know of this weekly cycle)? How does the mowing get tracked in Salesforce or some other work system? How are contracted mowers inputting their work?', false, NULL, 'Salesforce/Excel', 'Salesforce report', 'This measure informs BCRP of the maintenance of green spaces across Baltimore City. This impacts the: (1) safety of green spaces; (2) use of contractors for maintenance purposes; and (3) enjoyment of green spaces by the public.', NULL, NULL, 'Clarify what the measure is supposed to capture: either the timeliness of the mowing, or the number of mows completed each reporting period.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (509, 'AGC6300', 4, '# of participants enrolled in a Youth sports program', 'Output', 'The amount of youth that enroll in a youth sports program ran by BCRP''s Youth and Adult Sports Division', 'Internally Tracked: Database', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Number of enrolled participants on the BCRP database roster', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of how many youth participate in sports programs ran by BCRP''s Youth and Adults Sports Division. This impacts the: (1) type of sports programming provided; (2) quantity of programming offered; and (3) availability of spaces allotted for participants.', NULL, 'n/a', 'BCRP could adopt a weighted measure that takes into account individuals enrolled in multiple activities/programs.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (510, 'AGC6300', 4, '# of participants enrolled in adult sports programs', 'Output', 'The amount of adults that enroll in an adult sports program ran by BCRP''s Youth and Adult Sports Division', 'Internally Tracked: Database', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Number of enrolled participants on the BCRP database roster', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of how many adults participate in sports programs ran by BCRP''s Youth and Adults Sports Division. This impacts the: (1) type of sports programming provided; (2) quantity of programming offered; and (3) availability of spaces allotted for participants.', NULL, 'n/a', 'BCRP could adopt a weighted measure that takes into account individuals enrolled in multiple activities/programs.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (511, 'AGC6300', 4, '# of individuals aged 13-17 enrolled in at least one activity at the Recreation Centers', 'Output', 'The amount of youth (unduplicated) ages 13-17 that participate at one of BCRP''s recreation centers', 'Internally tracked: Database', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Number of enrolled participants on the BCRP database roster, grouped by age', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the amount of youth ages 13-17 that participate in an activity or program at a BCRP recreation center. This impacts the: (1) types of services provided to this age group; (2) usage of space; and (3) future capital development of similar spaces across Baltimore City.', NULL, 'n/a', 'BCRP could adopt a weighted measure that takes into account individuals enrolled in multiple activities.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (512, 'AGC6300', 4, '# of individuals aged 5-12 enrolled in at least one activity in the Recreation Centers', 'Output', 'The amount of youth (unduplicated) ages 5-12 that participate at one of BCRP''s recreation centers', 'Internally tracked: Database', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Number of enrolled participants on the BCRP database roster, grouped by age', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the amount of youth ages 5-12 that participate in an activity or program at a BCRP recreation center. This impacts the: (1) types of services provided to this age group; (2) usage of space; and (3) future capital development of similar spaces across Baltimore City.', NULL, 'n/a', 'BCRP could adopt a weighted measure that takes into account individuals enrolled in multiple activities.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (513, 'AGC6300', 4, '# of individuals enrolled in Summer Recreation Camps', 'Output', 'The amount of youth (unduplicated) enrolled at one of BCRP''s summer camps', 'Internally tracked: Database', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Number of enrolled participants on the BCRP database roster', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the amount of youth that enroll in summer camp programming. This impacts the: (1) location of summer camps; (2) quantity of participants per camp; (3) types of summer camps provided; and (4) future improvements to existing camps.', NULL, 'n/a', 'If the camps have a maximum enrollment limit, then the measure could be "% of maximum enrollment."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (514, 'AGC6300', 4, 'Total Cost Recovery by special facilities', 'Effectiveness', 'Tracking of expenditures versus revenue at BCRP special facilities', 'Internally Tracked: Fiscal Division', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Live', 'Budget analysis', 'Increase', NULL, NULL, 'Percent', NULL, 'What are the special facilities included for these calculations?', false, NULL, 'Workday/Excel', 'Workday report', 'This measure informs BCRP of the sustainability and ability for special facilities to thrive in the long-term.This impacts BCRP''s ability to continue serving the public''s need as it relates to the special services provided.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (515, 'AGC6300', 4, '# of visitors to Cylburn Arboretum', 'Output', 'The number of visitors that visit Cylburn Arboretum throughout the year', 'Onsite tracking', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', '# of attendees who visited the Cylburn Arboretum', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec/Excel', 'Civic Rec report', 'This measure informs BCRP of how often the public visits the arboretum and utilizes its facilities for events, programming, and leisure activities. This impacts the: (1) preservation of plants, trees, and trails maintained by BCRP; (2) future capital improvement; and (3) future programming and events for the public.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (516, 'AGC6300', 4, '# of visitors to Rawlings Conservatory', 'Output', 'The number of visitors that visit Rawlings Conservatory throughout the year', 'Onsite tracking', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', '# of attendees who visited the Rawlings Conservatory', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec/Excel', 'Civic Rec report', 'This measure informs BCRP of how often the public visits the horticultural conservatory. This impacts the: (1) preservation of plants maintained by BCRP; (2) future capital improvement to the historic structure; and (3) mental well-being of the public.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (517, 'AGC6300', 4, 'Attendance at city-wide senior programming', 'Output', 'The amount of older adults 50+ that attend city-wide senior programming', 'Internally Tracked: Program Manager for Senior Division', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Total number of participants', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the amount of adults 50+ that attend senior programming sponsored by or in conjunction with BCRP. This impacts the: (1) type of older adult program provided; and (2) location of programs.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (518, 'AGC6300', 4, '% of programs operating at 75% capacity or greater', 'Effectiveness', 'The capacity rate of therapeutic recreation programs', 'Internally Tracked', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'The registration number for each program is compared to the capacity for that program.  The number of programs that meet at least 75% capacity is divided by the total number of programs and multiplied by 100 to give the percentage of programs at 75% capacity.', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of how many participants enroll in therapeutic recreation programming versus availability of spaces. This impacts the: (1) amount of services provided; and (2) types of programming and services provided per season.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (519, 'AGC6300', 4, 'Total attendance at therapeutic recreation programming', 'Output', 'The amount of people with special needs that attend a therapeutic recreation program', 'Internally Tracked', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Total number of participants', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the amount of participants with special needs attend therapeutic recreation programming. This impacts the: (2) type of inclusion services BCRP provides; (2) quality of existing programming and services; (3) future improvement to existing programs; and (4) partnerships with organizations that provides special needs services.', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (520, 'AGC6300', 4, '# of Special Events offered city-wide', 'Output', 'The amount of special events sponsored by or in conjunction with BCRP throughout the year', 'Internally Tracked: Chief of Special Events', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Total number of Special Events sponsored by BCRP', 'Increase', NULL, NULL, 'Count', NULL, 'N/A', false, NULL, 'CivicRec', 'Civic Rec report', 'This measure informs BCRP of the amount of special events sponsored by or in conjunction with BCRP. This impacts the: (1) type of special events provided; (2) amount of passive programming provided to the public; and (3) future improvement to exisiting events.', NULL, 'n/a', 'If event attendance is tracked, that could be a better metric of public engagement with special events, as fewer but more attended events would be considered equivalent to many lesser attended events. Alternatively, could be "% of Special Events approved" or some measure of timeliness by the BCRP permit office.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (521, 'AGC6300', 4, '% of tree-related SRs closed on-time', 'Effectiveness', 'The rate of timely completion for tree-related SRs', 'Internally Tracked: Chief of Urban Forestry', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Weekly', 'Count of SR''s related to tree stumps and other tree requests in the system', 'Increase', NULL, NULL, 'Percent', NULL, 'N/A', false, NULL, 'Salesforce/Cityworks', 'Salesforce report', 'This measure informs BCRP of the maintenance of trees in Baltimore City; this impacts quality of living for residents including air quality, flooding risks, and services provided by sister agencies (e.g., sidewalk and street improvement).', NULL, 'n/a', 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (522, 'AGC6300', 4, 'Increase the Tree Canopy Citywide', 'Outcome', 'Growth of tree canopy by BCRP in Baltimore City', 'Internally Tracked: Chief of Urban Forestry', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Monthly', 'Count of trees in current inventory minus count of trees in previous year''s inventory', 'Increase', NULL, NULL, 'Count', NULL, 'Do we use the live version of the tree inventory that lives on balt-gslistener, and that can be auto-updated through Cityworks work orders?', false, NULL, 'Internally tracked', 'Excel tracking', 'This measure informs BCRP of the increase of ecosystem services BCRP provides Baltimore City and its residents. This impacts services such as greenhouse gas emissions, carbon sequestration, and removal of pollutants the air, soil, and water.', NULL, 'n/a', 'Tree canopy is not just a count of trees, but also tree coverage as % of total land area.', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (523, 'AGC6300', 4, '% of Facility Maintenance SRs for Recreation Centers completed on time', 'Effectiveness', 'The rate of timely completion for recreation center buildings', 'Internal Service Request', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Weekly', 'SR''s completed sorted by date entered and completed; total complete within time frame based on request type', 'Increase', NULL, NULL, 'Percent', NULL, 'Why is it only Recreation Centers that are considered for this measure?', false, NULL, 'Salesforce', 'Salesforce report', 'This measure informs BCRP of the maintenance of recreation centers; maintenance of recreation centers impacts: (1) the building''s lifecycle; and (2) whether the public want to use the space.', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (524, 'AGC6300', 4, '% of neighborhood pools inspected, cleaned, and maintained on-time', 'Efficiency', 'The rate of timely completion for neighborhood pools', 'Internal Service Request', 'Jerusalem Tekie', 'Chief, Policy & Innovation', 'Weekly', 'Number of pools inspected, cleaned and maintained on time/Number of total pools', 'Increase', NULL, NULL, 'Percent', NULL, 'How does this get tracked in Salesforce as an "Internal SR"?', false, NULL, 'Salesforce/Excel', 'Salesforce report', 'This measure informs BCRP of the maintenance of neighborhood pools; this impacts: (1) use of the pools by the public; and (2) lifecycle of the pool (which ties into future capital improvements to the pool).', NULL, NULL, 'N/A', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
