    (582, 'AGC7900', 4, 'Average # of days from filing a zoning appeal to a public hearing', 'Efficiency', 'days from filing appeal to hearing', 'Accela', 'Justin Williams', 'Interim Director of BMZA', 'Live; but system not set up to accurately collect this currently', 'Difference between date application deemed complete and date initially set for hearing', 'Decrease', NULL, NULL, 'Count', 'days', 'When Accela is fully online, will the appeals be requested solely through that system?', false, NULL, 'Accela', 'I did random sample of cases because Accela does nto provide easily', 'it doesn''t really; I/we inherited this measure.', NULL, 'I suppose complaints; but as soon as application is filed, we put it on the next docket that meets filing deadlines,', 'If there is a given SLA/timeline for how much time BMZA has to schedule and hold a hearing, change this measure to "% of hearings held within required time."', NULL, NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
