    (663, 'AGC2600', 4, 'Average Age of Fleet', 'Outcome', 'This KPI tracks the average age of vehicles in DGS''s Fleet at the beginning of each fiscal quarter. Vehicle age has a significant impact on availability, performance, and the maintenance required on a vehicle.', 'FasterWeb', 'James Trimarco', 'Analyst', 'Daily', 'SUM(Age of Fleet Vehicles)/COUNT(Fleet Vehicles)', 'Decrease', 6.7, 2025, 'Count', 'years', NULL, true, 'Yes', NULL, 'Fleet availability is viewed on FasterWeb.', 'Yes', 'Vehicle age has a significant impact on availability, performance, and the maintenance required on a vehicle.', NULL, NULL, 'New', 5, 19, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (664, 'AGC2600', 4, 'Number of Building Systems with Established PM Program', 'Outcome', 'Cumulative number of building systems with an established preventative maintenance (PM) program for DGS managed facilities in the downtown campus. Systems include: Elevator, HVAC, Air Handling Units (AHU), Kitchen/Gas Line, Generators.', 'Archibus', 'Happy Iguare', 'Operations Research Analyst', 'Biannually', 'Cumulative count of building systems with an established PM program for facilities in the downtown campus.', 'Increase', 5, 2025, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'New', 6, 19, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (665, 'AGC2600', 4, '% of BEPS Sites Benchmarked in ENERGYSTAR Portfolio Manager', 'Outcome', 'This metric is a measure of the percentage of the Building Energy Performance Standards (BEPS) identified sites benchmarked.', 'EnergyStar Portfolio Manager', 'Amy DaSilva', 'Energy Program Manager', 'Live', '(Count of BEPS sites in Portfolio Manager / Total # of BEPS Sites) * 100', 'Increase', 100, 2025, 'Percent', NULL, 'BEPS are regulatory frameworks designed to set minimum energy performance thresholds for existing buildings.', true, 'No', 'ENERGYSTAR Portfolio Manager', 'This data is viewable and can be queried in ENERGYSTAR Portfolio Manager', 'Yes', 'This metric is meaningful because it demonstrates our compliance with the state requirement.', NULL, NULL, 'Modified', 3, 10, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (666, 'AGC2600', 4, 'Apprenticeship & Vocational Program Hires', 'Outcome', 'Cumulative number of youth (persons 25 or under at time of employment) hired by DGS through participation in an apprenticeship or vocational partnership initiative.', 'Workday', 'Sierra Mason', 'Lead Recruitment Specialist', 'Quarterly', 'Cumulative Number of Hires Within Category', 'Increase', NULL, NULL, 'Count', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Baseline and target TBD — measure is newly tracked for FY27.', 'New', 5, 15, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (667, 'AGC2600', 4, 'Employee Voice Engagement Score', 'Outcome', 'Quantitative metric measuring how actively employees communicate their opinions, concerns, and suggestions. Collected via surveys or feedback platforms. Highlights employee involvement, trust in leadership, and investment in organizational improvement.', 'Periscope / Department of Human Resources', 'Sierra Mason', 'Lead Recruitment Specialist', 'Annually', 'Composite Score', 'Increase', 7.2, 2025, 'Count', 'out of 10', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'New', 5, 15, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (668, 'AGC2600', 4, '% Invoices Paid Within 30 Days of Workday Submission Date', 'Efficiency', 'Percentage of invoices submitted through Workday that are paid within 30 days of submission date. Measures speed and efficiency of invoice processing workflow. Timely payment supports strong vendor relationships, reduces service gap risk, and reflects sound fiscal management.', 'Workday / MOPI Prompt Payment Dashboard', 'Ruth Mosley', 'Budget Analyst', 'Monthly', '(Invoices Paid < 30 Days From Workday Submission / Total Invoice Count) * 100', 'Increase', 96, 2025, 'Percent', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'New', 5, 14, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (670, 'AGC4346', 4, 'Citywide Violence Reduction', 'Outcome', 'Sustain a 15% reduction in Homicides and Shootings Year Over Year in Baltimore City.', 'Citistat - Baltimore Police Department (BPD)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Daily', '(Current Year - Previous Year) / Previous Year * 100', 'Decrease', -13.13, 2025, 'Percent', NULL, NULL, NULL, NULL, 'Citistat', 'SQL query against GroupA_Crime table', 'Track year-over-year violence reduction progress across GVRS districts and citywide', 'Core outcome measure for the GVRS and citywide violence prevention strategy', NULL, NULL, 'New', 1, 2, true, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (671, 'AGC4346', 4, 'Safe Streets Site Stabilization Rate', 'Outcome', 'The average number of consecutive days without a homicide or shooting within the expanded Safe Streets zones.', 'Citistat - Baltimore Police Department (BPD)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Annually', 'Max(Date1 - Date2) for each Safe Streets zone', 'Increase', 194, 2025, 'Count', NULL, NULL, NULL, NULL, 'Citistat', 'SQL query against GroupA_Crime table filtered by Safe Streets zone boundaries', 'Assess zone-level stabilization effectiveness and guide Safe Streets site prioritization', 'Longer streaks without violence indicate Safe Streets sites are disrupting retaliation cycles', NULL, NULL, 'New', 1, 2, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (672, 'AGC4346', 4, 'Community Trust Index', 'Outcome', 'A quarterly survey-based percentage reflecting the increase in residents who report increased confidence in local government following a MONSE engagement.', 'MS Forms survey responses', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Quarterly', 'Q2(High confidence / Total respondents * 100) - Q1(High confidence / Total respondents * 100)', 'Increase', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE SharePoint (MS Forms exports)', 'Post-engagement surveys administered to residents following MONSE activations', 'Track whether MONSE engagements shift resident perception of government responsiveness', 'Government legitimacy is a prerequisite for community cooperation with violence intervention', NULL, NULL, 'New', 1, 3, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (673, 'AGC4346', 4, 'Proactive Engagement Ratio', 'Output', 'The ratio of proactive community engagements (CNSR pop-ups, lunch bunches) versus reactive responses to incidents. Measures a shift from crisis management to preventative work.', 'Apricot 360 / MONSE Case Management System (Microsoft 365)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Quarterly', 'Proactive events / Activated CNSR reactive responses', 'Increase', NULL, NULL, 'Count', 'ratio (proactive:reactive)', 'Brand new measure — baseline establishment required', NULL, NULL, 'Apricot 360 / MONSE CMS', 'Count of proactive vs. reactive engagement events logged in case management system', 'Monitor shift toward prevention; inform resource allocation between proactive and reactive work', 'A higher ratio indicates MONSE is building relationships before crises rather than only responding', NULL, NULL, 'New', 1, 3, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (674, 'AGC4346', 4, 'Handoff Success Rate', 'Efficiency', 'The percentage of external referrals to MONSE Victim Services that result in an active, engaged case within MONSE within the 48-hour window.', 'MONSE Case Management System (Microsoft 365)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Program Enrollments / Referrals * 100', 'Increase', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Automated timestamped tracking of referral receipt and case opening events in CMS', 'Monitor referral-to-intake pipeline efficiency; identify bottlenecks', 'Rapid intake is critical — delays increase the risk of losing contact with vulnerable victims', NULL, NULL, 'New', 3, 8, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (675, 'AGC4346', 4, 'Victim Navigation Satisfaction', 'Effectiveness', 'A percentage of victims who report that the transition between their initial point of contact (e.g., hospital) and delivery of services while in the program was ''seamless'' and highly effective.', 'Microsoft Forms survey response', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Quarterly', 'Count of ''seamless'' responses / total respondents * 100', 'Increase', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MS Forms / MONSE SharePoint', 'Surveys administered to victims following completion of initial service delivery phase', 'Assess quality of cross-provider handoffs and victim experience through intake', 'Victim satisfaction with navigation directly affects retention and willingness to engage', NULL, NULL, 'New', 3, 8, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (676, 'AGC4346', 4, 'Individualized Development Plan (IDP) Success Rate', 'Outcome', 'For any people accessing MONSE services and Individualized Development Plans, how many have achieved their goals/plans within 9 months of connection with MONSE.', 'MONSE Case Management System (Microsoft 365)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Annually', 'Individuals with goal achieved within 9 months / Individuals with IDPs at the 9-month mark', 'Increase', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Goal completion tracking logged by case managers in CMS at 9-month review', 'Evaluate effectiveness of individualized planning for returning citizens and high-risk individuals', 'IDP completion indicates concrete milestones reducing recidivism risk', NULL, NULL, 'New', 4, 13, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (677, 'AGC4346', 4, 'Re-Entry Engagement Rate', 'Effectiveness', 'Out of the number of returning citizens returning to Baltimore, what ratio are engaged by MONSE re-entry services?', 'DPSCS data / MONSE Case Management System (Microsoft 365)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Annually', 'Returning citizens engaged by MONSE / Total returnees to Baltimore * 100', 'Increase', NULL, NULL, 'Percent', NULL, 'Brand new measure — both baseline and target require DPSCS data sharing agreement', NULL, NULL, 'MONSE CMS (Microsoft Dataverse) + DPSCS data', 'MONSE enrollment records matched against DPSCS release data through interagency agreement', 'Assess reach of MONSE re-entry services relative to total population of returning citizens', 'Higher engagement means more returning citizens get support during the highest-risk period', NULL, 'Dependent on formalized DPSCS data sharing agreement. Baseline and target TBD.', 'New', 4, 13, false, true, false, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (678, 'AGC4346', 4, '# of GVRS Direct Communications Delivered to People at Highest Risk', 'Output', 'The total number of direct communications conducted through the Group Violence Reduction Strategy (GVRS).', 'Apricot Social Solutions case management system', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Weekly', 'Count of direct communications where DC Type = Full Custom Notification', 'Increase', 242, 2025, 'Count', NULL, NULL, NULL, NULL, 'Apricot 360 / MONSE CMS', 'Manual entry in Apricot 360 by GVRS outreach staff following each direct communication', 'Track GVRS outreach volume; assess whether the program is reaching enough high-risk individuals', 'Direct communications are the primary mechanism by which GVRS delivers consequences and services messaging', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (679, 'AGC4346', 4, 'Average # of Days Between GVRS Direct Communication and Enrollment', 'Efficiency', 'The number of days between the date of the direct communication and enrollment with a service provider. Only for Full Custom Notifications (excludes law enforcement notifications).', 'Apricot Social Solutions case management system', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Weekly', 'Average of (enrollment date - DC date) for full custom notifications', 'Decrease', NULL, NULL, 'Count', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'Apricot 360 / MONSE CMS', 'Calculated from timestamps in Apricot 360 case management records', 'Identify delays between outreach and service connection; drive process improvements', 'Faster enrollment reduces the window during which high-risk individuals disengage', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (680, 'AGC4346', 4, '# of Mediations Conducted by Safe Streets Staff', 'Output', 'The total number of mediations conducted by Safe Streets staff that are resolved, resolved conditionally, or resolved temporarily.', 'Apricot Social Solutions case management system', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Count of mediations (resolved, resolved conditionally, resolved temporarily) by Safe Streets staff', 'Increase', 1551, 2025, 'Count', NULL, NULL, NULL, NULL, 'Apricot 360 / MONSE CMS', 'Manual entry by Safe Streets staff in Apricot 360 following each mediation', 'Track Safe Streets program output; assess whether staffing levels meet mediation demand', 'Mediations directly interrupt retaliatory violence cycles', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (681, 'AGC4346', 4, '# of Interventions Across School-Based Violence Intervention Program (SBVIP) Sites', 'Efficiency', 'The average number of days between qualifying incidents at SBVIP partnered schools — a measure of incident spacing over time.', 'Apricot Social Solutions case management system', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Average of days between qualifying incidents at SBVIP partnering schools', 'Increase', 4, 2025, 'Count', NULL, NULL, NULL, NULL, 'Apricot 360 / MONSE CMS', 'Incident timestamps logged in Apricot 360; days between incidents calculated at end of period', 'Assess whether SBVIP interventions are increasing spacing between school-based incidents', 'Longer average days between incidents indicates the intervention is disrupting violence cycles', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (682, 'AGC4346', 4, 'Period-Over-Period Decrease in School-Based Incidents at SBVIP Sites', 'Outcome', 'The percentage change in incidents that take place within SBVIP partnered schools year over year.', 'Apricot Social Solutions case management system', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Annually', '(This year''s incidents - last year''s incidents) / last year''s incidents * 100', 'Decrease', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'Apricot 360 / MONSE CMS', 'Annual count of qualifying incidents at SBVIP schools extracted from Apricot 360', 'Evaluate SBVIP impact on school safety at program sites; inform expansion decisions', 'Year-over-year reduction at SBVIP schools is a direct outcome measure of program effectiveness', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (684, 'AGC4346', 4, 'Average # of Days Between Referral and MONSE Victim Services Intake', 'Efficiency', 'The average number of days between a victim referral and the time of intake.', 'Microsoft Dataverse Table (MONSE CMS)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Average of (intake date - referral date) across all victim services referrals in period', 'Decrease', NULL, NULL, 'Count', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Automated timestamping in MONSE CMS captures referral receipt and intake completion dates', 'Monitor referral-to-intake speed; identify bottlenecks against 48-hour SLA', 'Speed of intake directly affects victim engagement and trauma response outcomes', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (686, 'AGC4346', 4, '# of People Trained by MONSE Victim Services in Human Trafficking Awareness', 'Output', 'The number of people who attended human trafficking related trainings conducted by MONSE staff or partners.', 'Apricot Social Solutions case management system', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Sum of attendees across all human trafficking training events in the period', 'Increase', 1739, 2025, 'Count', NULL, NULL, NULL, NULL, 'Apricot 360 / MONSE CMS', 'Training attendance records entered in Apricot 360 by MONSE victim services staff', 'Track outreach and education reach; assess progress toward expanded HT awareness goals', 'Community awareness is a prevention measure — trained individuals more likely to identify trafficking', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (687, 'AGC4346', 4, '% of Participants with No New Arrests Up to 1 Year After Referral', 'Outcome', 'Percentage of re-entry participants with no new arrests (excluding technical violations) in the 12 months following their referral to MONSE re-entry services.', 'DPSCS internal recidivism table', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Annually', 'Count(participants with no new offense within 365 days of referral) / Count(participants with referral date >= 365 days ago) * 100', 'Increase', NULL, NULL, 'Percent', NULL, 'Dependent on formalized DPSCS data sharing agreement — frequency and methodology TBD', NULL, NULL, 'DPSCS data / MONSE CMS', 'MONSE participant records matched against DPSCS recidivism data through interagency agreement', 'Evaluate long-term re-entry program effectiveness in preventing recidivism', 'Avoiding re-arrest is the core outcome of re-entry services', NULL, 'SOURCE DOCUMENT FLAG: plan lists desired_direction = Decrease, but this metric tracks % with NO new arrests — higher is better. Direction corrected to Increase. Confirm with agency.', 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (688, 'AGC4346', 4, 'Average # of Days Between Referral and MONSE Re-Entry Services Intake', 'Efficiency', 'The average number of days between the date of referral and the time of intake for re-entry participants.', 'Microsoft Dataverse Table (MONSE CMS)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Average of (intake date - referral date) across all re-entry referrals in period', 'Decrease', NULL, NULL, 'Count', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Automated timestamping in MONSE CMS captures referral receipt and intake completion dates', 'Monitor intake pipeline speed for re-entry participants', 'Rapid intake during the high-risk period immediately following release is critical', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (689, 'AGC4346', 4, '# of Safe Return Plans Co-Developed by MONSE Re-Entry Services', 'Output', 'The number of safe return plans developed for participants in the re-entry lane. NOTE: MONSE is currently not operating in a behind-the-wall capacity at present.', 'Microsoft Dataverse Table (MONSE CMS)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Count of re-entry participants where a completed safe return plan has been entered in CMS', 'Increase', 158, 2025, 'Count', NULL, NULL, NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Safe return plan completion flagged by case managers in MONSE CMS upon plan finalization', 'Track co-developed planning output; assess progress toward re-entry program scale goals', 'A safe return plan is the tangible product of MONSE''s behind-the-wall re-entry engagement', NULL, 'MONSE is not currently operating in a behind-the-wall capacity. Will grow with Office of Returning Citizens.', 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (690, 'AGC4346', 4, 'Average # of Days Between Youth Opportunity Referral and Service Enrollment', 'Efficiency', 'The average time in days between date of referral and enrollment in services for youth diversion participants.', 'Microsoft Dataverse Table (MONSE CMS)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Average of (enrollment date - referral date) for youth diversion participants', 'Decrease', NULL, NULL, 'Count', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Referral and enrollment timestamps captured in MONSE CMS', 'Monitor speed of service connection for referred youth', 'Rapid enrollment is critical — delays increase risk of additional incidents before services begin', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (691, 'AGC4346', 4, 'Cumulative Recidivism Rate for MONSE Youth Opportunity Participants', 'Outcome', 'The percentage of youth diversion participants who have recidivated (violent offenses only).', 'Microsoft Dataverse Table and Citistat database', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Count of referred participants who recidivated / all participants referred to program * 100', 'Decrease', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required. Dependent on DJS data sharing.', NULL, NULL, 'MONSE CMS (Microsoft Dataverse) + Citistat / DJS data', 'Youth participant records matched against DJS recidivism data through interagency data sharing', 'Evaluate whether youth diversion programming successfully prevents re-offending', 'Recidivism among youth participants is the core outcome measure for youth diversion', NULL, 'Dependent on DJS data sharing agreement. Baseline and target TBD.', 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (692, 'AGC4346', 4, 'Average # of Days Between Incident and Activation for Reactive Stabilization', 'Efficiency', 'The average number of days between a qualifying incident and its associated MONSE neighborhood stabilization response.', 'Microsoft Dataverse Table (MONSE CMS)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Average of (activation date - incident date) excluding proactive stabilizations', 'Decrease', 12, 2025, 'Count', NULL, NULL, NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Incident and activation timestamps entered by stabilization team in MONSE CMS', 'Monitor responsiveness of neighborhood stabilization operations', 'Rapid response to traumatic incidents is critical to preventing retaliatory violence', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (693, 'AGC4346', 4, '% of People Identified Through Stabilization Who Receive Requested Services', 'Outcome', 'The percentage of contacts who are receiving services within a month of being engaged by MONSE''s street outreach team during a stabilization or response.', 'Microsoft Dataverse Table (MONSE CMS)', 'Joseph Muhlhausen', 'Chief of Data Analytics', 'Monthly', 'Count of contacts who receive services / all contacts engaged by stabilization outreach * 100', 'Increase', NULL, NULL, 'Percent', NULL, 'Brand new measure — baseline establishment required', NULL, NULL, 'MONSE CMS (Microsoft Dataverse)', 'Service receipt tracked by outreach staff in MONSE CMS within 30-day follow-up window', 'Assess whether stabilization contacts are successfully connected to services they need', 'Service connection rate during stabilization is a leading indicator of participant engagement', NULL, NULL, 'New', NULL, NULL, false, false, true, true, 'Validated', '2026-06-01', '2026-06-26T16:54:00.817077'),
