    (703, 'AGC4393', 4, '# of residents that received services', 'Output', 'Definition pending.', 'Client counts are reported by service providers. An individual is counted as a case if they receive: (1) representation for immigration legal services; (2) representation in deportation proceedings; or (3) complete a 3-month case engagement for social services.', 'Angela Ra', 'Communications and Strategic Policy Manager', 'For legal services, quarterly; for social services, live', 'Total number of individuals who received representation for immigration legal services + total number of individuals who received representation in deportation proceedings + total number of individuals in households that completed a 3-month case engagement for social services', 'Increase', NULL, NULL, 'N/A', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.817077'),
    (704, 'AGC4393', 4, 'Residents engaged per time spent in the community', 'Effectiveness', 'Definition pending.', 'One instance of a resident interaction is defined as: (1) a resident who is engaged by MIMA personnel at a community event and either learns about at least one Baltimore City resource or takes one handout from MIMA''s resource table; or (2) a resident who participates in a civic engagement opportunity hosted by MIMA, such as the Asian American Pacific Islander Advisory Group, Community Advisory Board, Hispanic Commission, or Language Access Oversight Committee. Data are collected live by MIMA staff present at an event. Community event hours staffed are defined as the time duration of an event multiplied by the number of MIMA personnel staffing that event.', 'Angela Ra', 'Communications and Strategic Policy Manager', 'Live', '(sum count of residents engaged by MIMA personnel at a community event that either learns about at least one Baltimore City resource or takes one handout from MIMA''s resource table + sum count of residents who participated in a civic engagement opportunity hosted by MIMA) / (sum product of each event''s hours and number of personnel staffing that event)', 'Increase', NULL, NULL, 'N/A', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, false, false, true, false, 'Draft', '2026-06-01', '2026-06-26T16:54:00.817077')
ON CONFLICT ("measure_id") DO UPDATE SET
    "agency_id" = EXCLUDED."agency_id", "initial_cycle" = EXCLUDED."initial_cycle", "title" = EXCLUDED."title", "measure_type" = EXCLUDED."measure_type", "description" = EXCLUDED."description", "data_source" = EXCLUDED."data_source", "data_owner" = EXCLUDED."data_owner", "data_owner_role" = EXCLUDED."data_owner_role", "update_frequency" = EXCLUDED."update_frequency", "formula" = EXCLUDED."formula", "desired_direction" = EXCLUDED."desired_direction", "baseline_value" = EXCLUDED."baseline_value", "baseline_fy" = EXCLUDED."baseline_fy", "format_type" = EXCLUDED."format_type", "display_unit" = EXCLUDED."display_unit", "context_required" = EXCLUDED."context_required", "replicability" = EXCLUDED."replicability", "disaggregation" = EXCLUDED."disaggregation", "data_location" = EXCLUDED."data_location", "collection_method" = EXCLUDED."collection_method", "how_data_used" = EXCLUDED."how_data_used", "why_meaningful" = EXCLUDED."why_meaningful", "proxy_measure" = EXCLUDED."proxy_measure", "improvement_notes" = EXCLUDED."improvement_notes", "change_mapping" = EXCLUDED."change_mapping", "pillar_id" = EXCLUDED."pillar_id", "pillar_goal_id" = EXCLUDED."pillar_goal_id", "is_city" = EXCLUDED."is_city", "is_agency" = EXCLUDED."is_agency", "is_service" = EXCLUDED."is_service", "validated" = EXCLUDED."validated", "approval_status" = EXCLUDED."approval_status", "created_date" = EXCLUDED."created_date", "last_updated" = EXCLUDED."last_updated";
SELECT setval(
    pg_get_serial_sequence('performance.performance_measure', 'measure_id'),
    COALESCE((SELECT MAX("measure_id") FROM performance.performance_measure), 1),
    (SELECT COUNT(*) > 0 FROM performance.performance_measure)
);

-- MONSE old measures are tied to inactive service families SRV0617, SRV0618, SRV0619, and SRV0758.
-- Keep the history, but exclude them from FY27 performance planning in favor of the SRV0924-SRV0927 measures.
UPDATE performance.performance_measure
SET active = false,
    change_mapping = 'Replaced',
    last_updated = CURRENT_TIMESTAMP,
    updated_at = CURRENT_TIMESTAMP
WHERE agency_id = 'AGC4346'
  AND measure_id BETWEEN 312 AND 329;

