    (1255, 79, 2024, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 18, 'Decrease in line of duty injuries correlates to the increase in the number of training hours to both recruit classes and to field operations units.', 19, NULL, 2, '2026-06-26T16:54:00.997112', '2026-06-26T16:54:00.997112'),
