    (1597, 507, 2024, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'The factors that impacted the fiscal 2024 actual data was the lack of funding, multiple vacancies, not having an active maintenance playground contract in place.', 1, NULL, 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
