    (1863, 190, 2025, 0.97, NULL, 0.96, NULL, 0.96, NULL, 0.93, NULL, 0.96, 'Small decrease is base on the transition to a new permitting system.', 0.98, NULL, 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1864, 191, 2025, 9801, NULL, 9855, NULL, 5927, NULL, 7128, 'Includes data for Commercial/residential/demo/temp events issued 4/1 - 6/30. Does not include reinstatement/extesion/change or add contractor permits included in Q1, Q2 and Q3', 32711, 'The decrease here is associated with what records are now counted as a permit in the new permitting system. In the past applications for extension, reinstatements, change of scope and addition of a contractor were counted as permit applications. They are no longer counted as a permit record.', 40000, 'The FY25 target is based on the three year average of actual permits issued FY21-FY23, rounded up.', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1865, 192, 2025, 13157, NULL, 12914, NULL, 12880, NULL, 12599, 'The quarterly measures are point in time measures for the end of each quarter, which is why Q4 and FY25 Total are the same.', 12599, 'Reframe Baltimore Strategies', 12199, 'This is a 1000 reduction from the FY24 target. This accounts for increased activity in litigation, demolition and prviate rehabilitation work.', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1866, 193, 2025, 65, NULL, 48, NULL, 33, NULL, 30, 'In Q4, staff that complete these applications assisted in reviewing an additional 1,468 Emergency Mortgage and Rental Assistance applications. That funding became available and staff shifted to take advantage of that opportunity to support residents.', 176, 'transitions in staffing impacted the number of cases that were able to be certified and processed', 400, NULL, 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1867, 195, 2025, 162, NULL, 92, NULL, 93, NULL, 275, '4th quarter began the renewed relationship with BCFD and OEM and DHCD recommiting to the structure of the Crisis Services Team (Ombudsman) being the first responders on events impacting housed indivuals being displaced due to a catashropic incident.  479 persons were impacted and referred as a result of the  change', 617, 'this number included residents impacted through crisis services and needing subsistence with remediating impending homelessness', 375, NULL, 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
