    (1924, 268, 2025, 4.67, NULL, 4.72, NULL, 4.68, NULL, 4.65, 'This score was negatively impacted by the average time to answer a call. We anticipate improvement based on the plan indicated for the other two metrics.', 4.75, 'This score was negatively impacted by the average time to answer a call. We anticipate improvement based on the plan indicated for the other two metrics.', 4.75, 'Collecting and analyzing 311''s data trends each year helped us arrive at a challenging yet attainable goal.', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1925, 269, 2025, 0.8407, NULL, 1, NULL, 0.89, NULL, 0.92, 'The root causes of last fiscal year’s incidents included hardware failures, database connection issues, power faults, and gaps in monitoring and change management. The IT Support Teams are addressing these by improving detection and alerting, enforcing planned downtime for changes, enhancing testing, and streamlining communications during outages. Through Critical Incident Management, the BCIT IT Incident and Problem Management team ensures faster recovery, reduced business impact, and long-term prevention of similar issues.', 0.92, 'The root causes of last fiscal year’s incidents included hardware failures, database connection issues, power faults, and gaps in monitoring and change management. The IT Support Teams are addressing these by improving detection and alerting, enforcing planned downtime for changes, enhancing testing', 0.99, 'Critical incidents represent the most impacting incidents in the organization and it''s important to work our hardest to resolve those issues as quickly as possible.', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1926, 270, 2025, 1, NULL, 1, NULL, 1, NULL, 0.9966, NULL, 1, 'No factors impacted us meeting the Target for Fiscal year 2025.', 0.99, 'Industry standard target', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1927, 271, 2025, 0.95, NULL, 0.96, NULL, 0.94, NULL, 0.96, NULL, 0.95, 'No factors impacted us meeting the Target for Fiscal year 2025.', 0.95, 'We have maintained a customer satisfaction score of at least 93% for the past 3 years, and therefore want to increase our goal for this target.', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
    (1928, 272, 2025, 0.9994, NULL, 0.9994, NULL, 0.9997, NULL, 0.9988, NULL, 1, 'Achieving 100% uptime/availability is not practical due to the necessity of scheduled maintenance outages for all network infrastructures.', 0.999, 'This is the industry SLA  (standard license agreement) standard.', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
