    (2091, 484, 2025, 407.38, NULL, 639.93, NULL, 537, NULL, 454.94, NULL, 495.89, 'The cost of chemicals skyrocketed. Extra chemicals were used due to high temperatures and to ensure high water quality.', 425, '5-Yr historical valuse have varied from $324/MG to $472/MG averaging around $372/MG. We have a significant baglog of rehab and maintenance needed so we are proposing a higher target for FY25', 2, '2026-06-26T16:54:00.998111', '2026-06-26T16:54:00.998111'),
