    (2258, 57, 2026, 84, NULL, 99, NULL, 52, NULL, NULL, NULL, NULL, NULL, 500, 'The Fiscal 2026 target was established by relying on internal data, the renewed influx of safety messaging to the community, and the acceptance of recalled Covid-19 restrictions.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
