    (2268, 67, 2026, 0.69, NULL, 0.74, NULL, 0.76, NULL, NULL, NULL, NULL, NULL, 0.5, 'The target was established by evaluating the improvements in training of members assigned to investigates fires and collaborate efforts with Baltimore Police Arson and other partner agencies.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2269, 68, 2026, 0.61, NULL, 0.64, NULL, 0.79, NULL, NULL, NULL, NULL, NULL, 0.7, 'The target was established by evaluating the improvements in training of members assigned to investigates fires and collaborate efforts with Baltimore Police Arson and other partner agencies.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2270, 69, 2026, 0.75, NULL, 0.75, NULL, 0.82, NULL, NULL, NULL, NULL, NULL, 0.7, 'The target was established by taking into consideration recent cuts at the Federal level. Recently, the National Fire Academy (NFA) was closed, presumably due to budget cuts. As the NFA as historically been a premier institution for advanced and executive level training, the BCFD has historically used the NFA as a source for various cause determination classes. As this resource is not currently available, it can be expected that training opportunities for current and future fire investigators will cease. This will have an adverse affect on the fire service as a whole.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2271, 70, 2026, 0.25, NULL, 1, NULL, 1, NULL, NULL, NULL, NULL, NULL, 1, 'Each ground ladder should be service tested annually in accordance with NFPA 1932, Chapter 7 by a certified vendor.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2272, 71, 2026, 0.88, NULL, 0.85, NULL, 0.85, NULL, NULL, NULL, NULL, NULL, 1, 'This metric was established with the goal of each piece of in-service gear being cleaned twice per calendar year. One cleaning must be an advanced cleaning with inspection.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2273, 72, 2026, 7, NULL, 7, NULL, 7, NULL, NULL, NULL, NULL, NULL, 8, 'This goal should be met once data input from fire facilities and air mask repair is uploaded into the Operative IQ program.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2274, 73, 2026, 74101, NULL, 68101, NULL, 63964, NULL, NULL, NULL, NULL, NULL, 168000, 'The FY26 target reflects call volume, system load, and seasonal/weather-related influences.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
