    (2276, 75, 2026, 0.845, NULL, 0.9, NULL, 0.98, NULL, NULL, NULL, NULL, NULL, 0.98, 'Baltimore 911 ensures urgent, professional aid, swiftly deploying the right help every time.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2277, 76, 2026, 0.902, NULL, 0.899, NULL, 0.891, NULL, NULL, NULL, NULL, NULL, 0.9, 'The FY26 target reflects NENA and NFPA standards, training needs, and post-COVID call impacts.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2278, 77, 2026, 0.845, NULL, 0.9, NULL, 0.9107, NULL, NULL, NULL, NULL, NULL, 0.9, 'Maryland law requires 911 calls be answered in 10 seconds; NENA sets 15-second industry standard.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
