    (2407, 219, 2026, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'The FY26 target for this performance objective was established by assessing trends in introduction of legislation and current initistives as well as assessing internal practices/procedures and staff ability to ensure the response time can be maintained at 100%.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2408, 220, 2026, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.95, 'The FY26 target was established based on the goals of each practice group within the service to provide excellent customer support to their clients and to increase the number of participants by starting the survey process earlier in teh fiscal year.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2409, 221, 2026, 61, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 300, 'Assessment of trends for the previous three (3) fiscal years and the ability of attorneys to maintain working relationships with all stakeholders to support continued increase in number of misconduct cases resolved.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2410, 222, 2026, 0.09, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.96, 'The FY26 target was established through assessment of the trends for the previous three (3) fiscal years as well as the ability of its attorneys (through training and mock trials) to successfully argue dispositive motions, aligning with the service goal #1.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2411, 223, 2026, 8, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 150, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2412, 224, 2026, 341, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 3600, 'The target for FY26 was developed based on data trends for the previous three (3) fiscal years and events related to employee/workplace safety in FY25 that we feel will continue to impact number of claims received and handled.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2413, 225, 2026, 0.3857, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.25, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2414, 226, 2026, 0, NULL, 0, NULL, 24, NULL, NULL, NULL, NULL, NULL, 2000000, 'Projected for FY2026 and utilized the projection in tandem with FY2024 actuals to determine a manageable target', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
