    (2472, 335, 2026, 0.65, NULL, 0.65, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.65, 'The 65% target for FY20 6 reﬂects a strategic commitment to racial equity and arts funding, aiming for incremental growth based on past successes, community feedback, and increased funding opportunities.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2473, 336, 2026, 0.55, NULL, 0.55, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.55, 'FY26 target was established through a combination of factors including data from previous years, feedback from stakeholders, a growing commitment to gender equity, and societal movements advocating for greater representation of woman in the arts.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2474, 337, 2026, 110, NULL, 110, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 110, 'The ROI target was established because of thorough analysis of economic indicators, historical performance, and strategic objectives, aiming to promote ﬁscal responsibility and eﬀecve management of city resources.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
