    (2550, 419, 2026, 1, NULL, 1, NULL, 1, NULL, NULL, NULL, NULL, NULL, 0.6, 'CHAP filled the position which will allow us to better accomplish our target goals.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2551, 420, 2026, 15, NULL, 11, NULL, 9, NULL, NULL, NULL, NULL, NULL, 70, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2552, 422, 2026, 0.82, NULL, 0.77, NULL, 0.82, NULL, NULL, NULL, NULL, NULL, 0.55, 'The CCE permit system that we''ve historically used has been unpredictable. Even with proactive permit review, our performance measures haven''t reflected our intense effort to provide exceptional customer service. With a new system coming on board, it''s assumed that there will be a learning curve. With that unpredictability, we are assuming that FY''26 permit review may experience some challenges and a decrease in our previous targets.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2553, 423, 2026, 19695, NULL, 7054, NULL, 1755, NULL, NULL, NULL, NULL, NULL, 85000, 'We anticipate maintaining our performance under this measure compared to our performance in FY24.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2554, 424, 2026, 147, NULL, 32, NULL, 66, NULL, NULL, NULL, NULL, NULL, 140, 'We anticipate continuing to increase performance under this measure in FY26 by engaging City staff participating in the Sustainability & Resiliency Subcabinet, continuing to offer environmental regulations trainings to City agency staff who manage capital projects, and taking advantage of a regional pot of funding that is available to fund climate training for local government staff.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2555, 425, 2026, 0.14, NULL, 0.14, NULL, 0.14, NULL, NULL, NULL, NULL, NULL, 0.05, 'The FY26 target was established based on the expectation that the rate of implementation targeted for FY25 will continue in FY26. This expectation is based on maintaining the number of positions funded under this service, and the expectation of no major operating budget increases to accelerate implementation.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2556, 426, 2026, 0.28, NULL, 0.06, NULL, 0.06, NULL, NULL, NULL, NULL, NULL, 0.1, 'The FY26 target was established based on the expectation that the rate of implementation targeted for FY25 will continue in FY26. This expectation is based on maintaining the number of positions funded under this service, and the expectation of no major operating budget increases to accelerate implementation.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2557, 427, 2026, 0, NULL, 0, NULL, 1800, NULL, NULL, NULL, NULL, NULL, 165259, 'The FY26 target was established based on the expectation of a standard 3%-line item increase over FY25. The needs for community organizations and urban farms working to improve healthy food access in Baltimore City far exceed this amount, but we are not requesting a larger increase due to the City’s overall budget situation. As always, we will work to leverage these funds with additional federal, state, and philanthropic funding.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2558, 428, 2026, 44.5, NULL, 52, NULL, 42, NULL, NULL, NULL, NULL, NULL, 72, 'Achievable with current personnel.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2559, 429, 2026, 0.47, NULL, 0.51, NULL, 0.53, NULL, NULL, NULL, NULL, NULL, 0.3, 'The target has been set at 30%, which was determined to be a achievable goal based on FY25 projections and planned advertising and community outreach efforts focsed within the city.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
