    (2722, 660, 2026, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 59039, 'The target was set based on the baseline of the previous years’ session counts, with adjustments made for an anticipated 10% growth in user interactions, potential increases in website traffic, and strategic changes in accessibility features and improvements to the user experience expected to drive more traffic to the site.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2723, 661, 2026, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 6500, 'The target of 6,500 hours for FY26 was set to ensure that adequate time is allocated for all scheduled government meeting blocks while maintaining flexibility for any unforeseen scheduling adjustments.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2724, 662, 2026, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 'This metric is maintained at 100%.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2725, 665, 2026, 3.1, NULL, 3.1, NULL, 3.13, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2726, 1, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 225000, 'Although fully staffed, the target is projected to increase to prepare for three new variables: new tax system, payment plans and new vacant tax rate which will increase the number of calls to the call center.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2727, 2, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.75, 'Although fully staffed, the target remained the same to prepare for three new variables: new tax system, payment plans and new vacant tax rate which will increase the number of calls to the call center and additional service requests (SR''s).', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2728, 3, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 7, 'Although fully staffed, the target remained the same to prepare for three new variables: new tax system, payment plans and new vacant tax rate which will increase the number of calls to the call center.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2729, 4, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.96, 'Tax collection rate is projected to remain the same with the payment plans off-set by new legislation that may adversely affect the tax sale (bids required at the tax assessed value) and a higher vacants tax rate. For both 2026 and 2027, owner occupied properties will not go to tax sale.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2730, 5, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.046, 'Treasury takes into account likelihood of issuing in the public market based on funding needs, market conditions, credit spreads, timing and other funding strategies.  Market consensus has the fed decreasing short-term rates and high muni supply increasing longer-term yields resulting in net increas', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2731, 6, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 3, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
