    (2738, 13, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 12500, 'With our addition of more refined design services, large format signage, and on-demand print services.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
