    (2741, 16, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 400000, 'The is based on trends in FY25 and FY26 with an increased number of City employees.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2742, 17, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.99, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2743, 18, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 5, 'By industry standards, high performing fiscal teams close their books monthly between 4-6 business days. Closing the period in 5 business days also allows the fiscal team to review and analyze financial reporting and address any issues timely.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
