    (2750, 25, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.02, 'Target consistent with Bureau''s goals.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2751, 26, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 5, 'Updated target reflects FY26 current trends.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2752, 27, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 240, 'For FY2027, a further decline in appraisal reviews is expected, driven by the continued scarcity of properties in developer-preferred areas and ongoing economic challenges affecting the housing industry.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2753, 28, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 815, 'The Fiscal 2027 target reflects anticipated new residential developments expected to increase tax credit applications.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2754, 29, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 160, 'The Fiscal 2027 target for rejected or revoked tax credits is based on historical data and trends.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2755, 30, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 4990000, 'The Fiscal 2027 target was set by analyzing recent reassessments of Assessment Group 3. The average success rate from these years was applied to the total potential assessment increase from appeals filed on the 1/1/2026 reassessments.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2756, 31, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 2965, 'The Fiscal 2027 target assumes a slight increase in granted tax credit applications from new residential developments and factors in properties with expiring tax credits.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2757, 32, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.85, NULL, 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
