    (2862, 144, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 44000, 'By assesseing the levels over the past two years, the program is looking to maintain it''s current levels as other program offerings expand while staffing has been reduced due to funding.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2863, 145, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 30000, 'The levels were determined using the average of the past two years and factoring in potential federal funding reductions for programs and staff, especially with the end of ARPA funding.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2864, 146, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 50000, 'The levels were determined using the average of the past two years and factoring in potential federal funding reductions for programs and staff, especially with the end of ARPA funding.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
    (2865, 147, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 26000, 'We reviewed performance data for FY 2023-FY 2026 and established a target based on that data, taking into account volatility in requests for service, and variations in staffing of the call center.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
