    (2930, 218, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.15, 'As the Labor & Employment team has limited control over the amount and type of claims that will be received, the FY27 target was established by reviewing previous years data (average over the last 3 fiscal years) and trends.', 2, '2026-06-26T16:54:00.999486', '2026-06-26T16:54:00.999486'),
