    (3008, 353, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 3800, 'As a result of increased shelter capacity and increased services and supports. Our focus will shift towards decreasing street homelessness.', 2, '2026-06-26T16:54:01.000508', '2026-06-26T16:54:01.000508'),
