    (3011, 356, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1535, NULL, 2, '2026-06-26T16:54:01.000508', '2026-06-26T16:54:01.000508'),
    (3012, 357, 2027, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.45, 'In FY27, the federal government has stated they intends to make drastic changes to permanent housing programs. As such, our targeted goals remain in alignment with FY25 however we need to make targeted efforts towards assisting clients with improving their earned income.', 2, '2026-06-26T16:54:01.000508', '2026-06-26T16:54:01.000508'),
