);

-- SERVICE_GOAL_LINK plan_service_id values are plan-local in the workbook and are mapped by the linked agency goal's plan.
-- Skipped SERVICE_GOAL_LINK rows with unresolved plan service references: 2, 3, 4, 5, 6, 7, 8, 9, 13, 14, 15, 16
INSERT INTO performance.service_goal_link ("sgl_id", "plan_service_id", "agency_goal_id", "initiative_id")
VALUES
    (1, 1, 1, 1),
    (10, 1, 3, 8),
    (11, 2, 4, 10),
    (12, 2, 5, 13)
ON CONFLICT ("sgl_id") DO UPDATE SET
    "plan_service_id" = EXCLUDED."plan_service_id", "agency_goal_id" = EXCLUDED."agency_goal_id", "initiative_id" = EXCLUDED."initiative_id";
SELECT setval(
    pg_get_serial_sequence('performance.service_goal_link', 'sgl_id'),
    COALESCE((SELECT MAX("sgl_id") FROM performance.service_goal_link), 1),
    (SELECT COUNT(*) > 0 FROM performance.service_goal_link)
);

-- Action Plan measure alignment is system-admin managed.
-- Clear imported DGS and MONSE measure-level Action Plan selections until explicitly reviewed.
UPDATE performance.performance_measure
SET pillar_id = NULL,
    pillar_goal_id = NULL,
    last_updated = CURRENT_TIMESTAMP
WHERE agency_id IN ('AGC2600', 'AGC4346')
  AND (pillar_id IS NOT NULL OR pillar_goal_id IS NOT NULL);

COMMIT;
